);
CREATE TABLE public.work_orders (
  id uuid NOT NULL DEFAULT gen_random_uuid(),
  org_id uuid NOT NULL,
  mo_id uuid NOT NULL,
  operation_id uuid,
  work_center_id uuid NOT NULL,
  work_order_number character varying(50) NOT NULL,
  operation_sequence integer NOT NULL,
  operation_name character varying(200) NOT NULL,
  operation_name_ar character varying(200),
  planned_quantity numeric(12,4) NOT NULL,
  completed_quantity numeric(12,4) DEFAULT 0,
  scrapped_quantity numeric(12,4) DEFAULT 0,
  planned_setup_time numeric(10,2) DEFAULT 0,
  planned_run_time numeric(10,2) DEFAULT 0,
  actual_setup_time numeric(10,2) DEFAULT 0,
  actual_run_time numeric(10,2) DEFAULT 0,
  actual_wait_time numeric(10,2) DEFAULT 0,
