CREATE OR REPLACE FUNCTION public.add_org_id_column(table_name text)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    is_view BOOLEAN;
BEGIN
    -- Check if it's a view (not a table)
    SELECT EXISTS (
        SELECT 1 FROM information_schema.views 
        WHERE views.table_name = add_org_id_column.table_name
    ) INTO is_view;
    
    -- Skip if it's a view
    IF is_view THEN
        RAISE NOTICE 'Skipping view: %', table_name;
        RETURN;
    END IF;
    
    -- Check if org_id column already exists
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE information_schema.columns.table_name = add_org_id_column.table_name 
        AND column_name = 'org_id'
        AND table_schema = 'public'
    ) THEN
        EXECUTE format('ALTER TABLE %I ADD COLUMN org_id UUID REFERENCES organizations(id) DEFAULT %L',
            table_name, '00000000-0000-0000-0000-000000000001');
        EXECUTE format('CREATE INDEX IF NOT EXISTS idx_%I_org_id ON %I(org_id)', table_name, table_name);
        RAISE NOTICE 'Added org_id to table: %', table_name;
    ELSE
        RAISE NOTICE 'Table % already has org_id column', table_name;
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE 'Could not add org_id to %: %. Continuing...', table_name, SQLERRM;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.approve_journal_entry(p_entry_id uuid, p_approval_level integer, p_comments text DEFAULT NULL::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_approval RECORD;
    v_tenant_id UUID;
    v_user_id UUID;
    v_required_levels INTEGER;
    v_approved_levels INTEGER;
BEGIN
    -- [120] اشتقاق tenant من القيد نفسه + بوابة admin (بدل app.* الميت)
    SELECT tenant_id INTO v_tenant_id FROM journal_entries WHERE id = p_entry_id;
    IF NOT FOUND THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Entry not found'
        );
    END IF;
    PERFORM public.wardah_assert_org_admin(v_tenant_id);
    v_user_id := auth.uid();

    -- Check if approval exists
    SELECT * INTO v_approval
    FROM journal_entry_approvals
    WHERE entry_id = p_entry_id
    AND approval_level = p_approval_level
    AND tenant_id = v_tenant_id;

    IF NOT FOUND THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Approval record not found'
        );
    END IF;

    IF v_approval.status != 'pending' THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Approval already processed'
        );
    END IF;

    -- Update approval
    UPDATE journal_entry_approvals SET
        status = 'approved',
        comments = p_comments,
        approved_at = CURRENT_TIMESTAMP,
        updated_at = CURRENT_TIMESTAMP
    WHERE id = v_approval.id;

    -- [120] المطلوب = عدد سجلات الاعتماد المعرّفة للقيد (السطر السابق كان
    -- يطبّق ->> على boolean — خطأ نوعي كان سيفشل وقت التشغيل)
    SELECT COUNT(*) INTO v_required_levels
    FROM journal_entry_approvals
    WHERE entry_id = p_entry_id AND tenant_id = v_tenant_id;
    SELECT COUNT(*) INTO v_approved_levels
    FROM journal_entry_approvals
    WHERE entry_id = p_entry_id AND status = 'approved';

    RETURN json_build_object(
        'success', true,
        'message', 'Entry approved at level ' || p_approval_level,
        'approved_levels', v_approved_levels,
        'required_levels', v_required_levels,
        'can_post', v_approved_levels >= v_required_levels
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.assert_period_open(p_org uuid, p_date date)
 RETURNS void
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_status TEXT;
    v_col    TEXT;
BEGIN
    IF to_regclass('public.accounting_periods') IS NULL THEN
        RETURN; -- لا يوجد نظام فترات — نسمح
    END IF;

    v_col := wardah_periods_org_col();
    IF v_col IS NULL THEN
        RETURN; -- بنية غير معروفة — لا نكسر الإدخال
    END IF;

    EXECUTE format(
        'SELECT status FROM accounting_periods
         WHERE %I = $1 AND $2 BETWEEN start_date AND end_date
         ORDER BY start_date DESC LIMIT 1',
        v_col
    )
    INTO v_status
    USING p_org, p_date;

    IF v_status IS NOT NULL AND v_status <> 'open' THEN
        RAISE EXCEPTION 'PERIOD_CLOSED: لا يمكن القيد بتاريخ % — الفترة المحاسبية بحالة "%"',
            p_date, v_status;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.assign_routing_to_mo(p_mo_id uuid, p_routing_id uuid)
 RETURNS manufacturing_orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_mo manufacturing_orders;
    v_org UUID;
BEGIN
    -- [120] حارس عضوية على مؤسسة أمر التصنيع
    SELECT org_id INTO v_org FROM manufacturing_orders WHERE id = p_mo_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Manufacturing order not found: %', p_mo_id;
    END IF;
    PERFORM public.wardah_assert_org_member(v_org);

    -- التحقق من صلاحية المسار ([120] + انتماؤه لنفس المؤسسة)
    IF NOT EXISTS (
        SELECT 1 FROM routings
        WHERE id = p_routing_id
        AND org_id = v_org
        AND status = 'APPROVED'
        AND is_active = true
    ) THEN
        RAISE EXCEPTION 'Routing must be approved and active';
    END IF;

    -- تحديث أمر التصنيع
    UPDATE manufacturing_orders SET
        routing_id = p_routing_id,
        updated_at = NOW()
    WHERE id = p_mo_id
    RETURNING * INTO v_mo;

    RETURN v_mo;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auth_org_id()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
    SELECT uo.org_id 
    FROM user_organizations uo 
    WHERE uo.user_id = auth.uid() 
    AND uo.is_active = true 
    LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_backflush_materials()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_mo RECORD;
    v_bom_line RECORD;
    v_qty_to_consume DECIMAL;
BEGIN
    -- فقط عند تسجيل كمية منتجة جديدة
    IF NEW.completed_quantity > COALESCE(OLD.completed_quantity, 0) THEN
        
        -- الحصول على معلومات أمر التصنيع
        SELECT mo.*, mo.auto_backflush, mo.backflush_timing, mo.bom_id
        INTO v_mo
        FROM manufacturing_orders mo
        WHERE mo.id = NEW.mo_id;
        
        -- التحقق من تفعيل Backflushing التلقائي
        IF v_mo.auto_backflush = true AND v_mo.backflush_timing = 'ON_COMPLETION' THEN
            
            v_qty_to_consume := NEW.completed_quantity - COALESCE(OLD.completed_quantity, 0);
            
            -- استهلاك المواد بناءً على BOM
            FOR v_bom_line IN 
                SELECT bl.*, i.name as item_name
                FROM bom_lines bl
                JOIN items i ON bl.item_id = i.id
                WHERE bl.bom_id = v_mo.bom_id
                AND bl.item_type IN ('RAW_MATERIAL', 'COMPONENT')
            LOOP
                -- تسجيل الاستهلاك
                INSERT INTO material_consumption (
                    org_id, work_order_id, mo_id, item_id,
                    planned_quantity, consumed_quantity, consumption_type,
                    unit_cost, total_cost, status, consumption_date, created_by
                ) VALUES (
                    NEW.org_id, NEW.id, NEW.mo_id, v_bom_line.item_id,
                    v_bom_line.quantity * v_qty_to_consume,
                    v_bom_line.quantity * v_qty_to_consume,
                    'BACKFLUSH',
                    COALESCE(v_bom_line.unit_cost, 0),
                    COALESCE(v_bom_line.unit_cost, 0) * v_bom_line.quantity * v_qty_to_consume,
                    'POSTED', NOW(), auth.uid()
                );
            END LOOP;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_generate_work_orders()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_operation RECORD;
    v_sequence INTEGER := 0;
    v_work_order_number VARCHAR;
BEGIN
    -- فقط عند تغيير الحالة إلى RELEASED أو IN_PROGRESS
    IF NEW.status IN ('RELEASED', 'IN_PROGRESS') 
       AND (OLD.status IS NULL OR OLD.status NOT IN ('RELEASED', 'IN_PROGRESS'))
       AND NEW.routing_id IS NOT NULL
       AND NEW.work_orders_generated = false THEN
        
        -- إنشاء أوامر عمل لكل عملية في المسار
        FOR v_operation IN 
            SELECT ro.*, wc.name as work_center_name, wc.name_ar as work_center_name_ar
            FROM routing_operations ro
            JOIN work_centers wc ON ro.work_center_id = wc.id
            WHERE ro.routing_id = NEW.routing_id
            AND ro.is_active = true
            ORDER BY ro.operation_sequence
        LOOP
            v_sequence := v_sequence + 1;
            v_work_order_number := NEW.order_number || '-WO-' || LPAD(v_sequence::TEXT, 3, '0');
            
            INSERT INTO work_orders (
                org_id, mo_id, operation_id, work_center_id,
                work_order_number, operation_sequence, operation_name, operation_name_ar,
                planned_quantity, planned_setup_time, planned_run_time,
                status, priority, created_by
            ) VALUES (
                NEW.org_id, NEW.id, v_operation.id, v_operation.work_center_id,
                v_work_order_number, v_operation.operation_sequence, 
                v_operation.operation_name, v_operation.operation_name_ar,
                NEW.quantity, v_operation.standard_setup_time,
                v_operation.standard_run_time_per_unit * NEW.quantity,
                'PENDING', 5, auth.uid()
            );
        END LOOP;
        
        -- تحديث علامة إنشاء أوامر العمل
        NEW.work_orders_generated := true;
    END IF;
    
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.auto_schedule_work_orders(p_work_center_id uuid, p_start_date timestamp with time zone, p_schedule_id uuid DEFAULT NULL::uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_work_order RECORD;
    v_current_time TIMESTAMP WITH TIME ZONE := p_start_date;
    v_scheduled_count INTEGER := 0;
    v_daily_capacity DECIMAL;
    v_daily_used DECIMAL := 0;
    v_current_date DATE := p_start_date::DATE;
    v_org UUID;
BEGIN
    -- [120] حارس عضوية على مؤسسة مركز العمل
    SELECT org_id INTO v_org FROM work_centers WHERE id = p_work_center_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Work center not found: %', p_work_center_id;
    END IF;
    PERFORM public.wardah_assert_org_member(v_org);

    -- الحصول على الطاقة اليومية
    SELECT capacity_hours_per_day * 60 INTO v_daily_capacity -- بالدقائق
    FROM work_centers WHERE id = p_work_center_id;

    -- جدولة أوامر العمل حسب الأولوية وتاريخ الاستحقاق
    FOR v_work_order IN
        SELECT wo.*
        FROM work_orders wo
        JOIN manufacturing_orders mo ON wo.mo_id = mo.id
        WHERE wo.work_center_id = p_work_center_id
        AND wo.status IN ('PENDING', 'READY')
        ORDER BY wo.priority ASC, mo.due_date ASC NULLS LAST, wo.created_at ASC
    LOOP
        -- التحقق من الطاقة المتبقية لليوم
        IF v_daily_used + (v_work_order.planned_setup_time + v_work_order.planned_run_time) > v_daily_capacity THEN
            -- الانتقال لليوم التالي
            v_current_date := v_current_date + 1;
            v_current_time := v_current_date::TIMESTAMP WITH TIME ZONE + INTERVAL '8 hours'; -- بداية اليوم
            v_daily_used := 0;
        END IF;

        -- جدولة أمر العمل
        PERFORM schedule_work_order(v_work_order.id, v_current_time, p_schedule_id);

        -- تحديث الوقت الحالي والطاقة المستخدمة
        v_current_time := v_current_time +
            ((v_work_order.planned_setup_time + v_work_order.planned_run_time) * INTERVAL '1 minute');
        v_daily_used := v_daily_used + (v_work_order.planned_setup_time + v_work_order.planned_run_time);
        v_scheduled_count := v_scheduled_count + 1;
    END LOOP;

    RETURN v_scheduled_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.backflush_materials(p_work_order_id uuid, p_quantity_produced numeric)
 RETURNS SETOF material_consumption
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_work_order RECORD;
    v_mo RECORD;
    v_bom_line RECORD;
BEGIN
    -- الحصول على أمر العمل وأمر التصنيع
    SELECT wo.*, mo.bom_id, mo.org_id as mo_org_id
    INTO v_work_order
    FROM work_orders wo
    JOIN manufacturing_orders mo ON wo.mo_id = mo.id
    WHERE wo.id = p_work_order_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Work order not found: %', p_work_order_id;
    END IF;

    -- [120] حارس عضوية على مؤسسة أمر التصنيع
    PERFORM public.wardah_assert_org_member(v_work_order.mo_org_id);

    -- استهلاك المواد بناءً على BOM
    FOR v_bom_line IN
        SELECT bl.*, i.name as item_name
        FROM bom_lines bl
        JOIN items i ON bl.item_id = i.id
        WHERE bl.bom_id = v_work_order.bom_id
        AND bl.item_type IN ('RAW_MATERIAL', 'COMPONENT')
    LOOP
        RETURN QUERY
        INSERT INTO material_consumption (
            org_id, work_order_id, mo_id, item_id,
            planned_quantity, consumed_quantity, consumption_type,
            unit_cost, total_cost, status, consumption_date, created_by
        ) VALUES (
            v_work_order.mo_org_id, p_work_order_id, v_work_order.mo_id, v_bom_line.item_id,
            v_bom_line.quantity * (v_work_order.planned_quantity),
            v_bom_line.quantity * p_quantity_produced,
            'BACKFLUSH',
            v_bom_line.unit_cost,
            v_bom_line.unit_cost * v_bom_line.quantity * p_quantity_produced,
            'PENDING', NOW(), auth.uid()
        )
        RETURNING *;
    END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.batch_post_journal_entries(p_entry_ids uuid[])
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_entry_id UUID;
    v_result JSON;
    v_success_count INTEGER := 0;
    v_fail_count INTEGER := 0;
    v_results JSONB := '[]'::JSONB;
    v_entry_result JSON;
    v_tenant_id UUID;
    v_org UUID;
BEGIN
    IF p_entry_ids IS NULL OR array_length(p_entry_ids, 1) IS NULL THEN
        RETURN json_build_object(
            'success', false,
            'error', 'No entries provided'
        );
    END IF;

    -- [120] حارس: كل قيد في الدفعة يجب أن ينتمي لمؤسسة المستدعي (admin)
    IF NOT EXISTS (SELECT 1 FROM journal_entries WHERE id = ANY(p_entry_ids)) THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Entries not found'
        );
    END IF;
    FOR v_org IN SELECT DISTINCT tenant_id FROM journal_entries WHERE id = ANY(p_entry_ids)
    LOOP
        IF v_org IS NULL THEN
            RAISE EXCEPTION 'ORG_UNRESOLVED';
        END IF;
        PERFORM public.wardah_assert_org_admin(v_org);
    END LOOP;
    SELECT tenant_id INTO v_tenant_id FROM journal_entries WHERE id = ANY(p_entry_ids) LIMIT 1;

    -- Process each entry
    FOREACH v_entry_id IN ARRAY p_entry_ids
    LOOP
        BEGIN
            -- Try to post the entry
            SELECT post_journal_entry(v_entry_id) INTO v_entry_result;

            IF (v_entry_result->>'success')::BOOLEAN THEN
                v_success_count := v_success_count + 1;
                v_results := v_results || jsonb_build_object(
                    'entry_id', v_entry_id,
                    'success', true,
                    'message', v_entry_result->>'message'
                );
            ELSE
                v_fail_count := v_fail_count + 1;
                v_results := v_results || jsonb_build_object(
                    'entry_id', v_entry_id,
                    'success', false,
                    'error', v_entry_result->>'error'
                );
            END IF;
        EXCEPTION WHEN OTHERS THEN
            v_fail_count := v_fail_count + 1;
            v_results := v_results || jsonb_build_object(
                'entry_id', v_entry_id,
                'success', false,
                'error', SQLERRM
            );
        END;
    END LOOP;

    -- Return summary
    RETURN json_build_object(
        'success', v_fail_count = 0,
        'total', array_length(p_entry_ids, 1),
        'success_count', v_success_count,
        'fail_count', v_fail_count,
        'results', v_results
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.build_bom_tree(p_bom_id uuid, p_quantity numeric DEFAULT 1, p_org_id uuid DEFAULT NULL::uuid, p_force_rebuild boolean DEFAULT false)
 RETURNS TABLE(id uuid, parent_id uuid, item_id uuid, item_code character varying, item_name character varying, level_number integer, quantity_required numeric, cumulative_quantity numeric, unit_cost numeric, total_cost numeric, is_critical boolean, scrap_factor numeric, line_type character varying, path text, has_children boolean)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_cache_expiry INTERVAL := INTERVAL '1 hour';
    v_cached_count INTEGER;
    items_table_exists BOOLEAN;
    products_table_exists BOOLEAN;
BEGIN
    -- التحقق من وجود الجداول
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_name = 'items'
    ) INTO items_table_exists;
    
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_name = 'products'
    ) INTO products_table_exists;

    -- التحقق من وجود cache صالح
    IF NOT p_force_rebuild THEN
        SELECT COUNT(*) INTO v_cached_count
        FROM bom_tree_cache
        WHERE bom_id = p_bom_id
        AND (p_org_id IS NULL OR org_id = p_org_id)
        AND (expires_at IS NULL OR expires_at > NOW());
        
        IF v_cached_count > 0 THEN
            -- إرجاع البيانات من cache
            IF items_table_exists THEN
                RETURN QUERY
                SELECT 
                    c.id,
                    c.parent_id,
                    c.item_id,
                    COALESCE(i.code, i.item_code)::VARCHAR AS item_code,
                    COALESCE(i.name, i.item_name)::VARCHAR AS item_name,
                    c.level_number,
                    c.quantity_required,
                    c.cumulative_quantity,
                    c.unit_cost,
                    c.total_cost,
                    c.is_critical,
                    c.scrap_factor,
                    c.line_type,
                    c.path,
                    EXISTS(
                        SELECT 1 FROM bom_tree_cache child 
                        WHERE child.parent_id = c.id
                    ) AS has_children
                FROM bom_tree_cache c
                LEFT JOIN items i ON i.id = c.item_id
                WHERE c.bom_id = p_bom_id
                AND (p_org_id IS NULL OR c.org_id = p_org_id)
                AND (c.expires_at IS NULL OR c.expires_at > NOW())
                ORDER BY c.level_number, c.path;
            ELSIF products_table_exists THEN
                RETURN QUERY
                SELECT 
                    c.id,
                    c.parent_id,
                    c.item_id,
                    COALESCE(p.code, p.product_code)::VARCHAR AS item_code,
                    COALESCE(p.name, p.product_name)::VARCHAR AS item_name,
                    c.level_number,
                    c.quantity_required,
                    c.cumulative_quantity,
                    c.unit_cost,
                    c.total_cost,
                    c.is_critical,
                    c.scrap_factor,
                    c.line_type,
                    c.path,
                    EXISTS(
                        SELECT 1 FROM bom_tree_cache child 
                        WHERE child.parent_id = c.id
                    ) AS has_children
                FROM bom_tree_cache c
                LEFT JOIN products p ON p.id = c.item_id
                WHERE c.bom_id = p_bom_id
                AND (p_org_id IS NULL OR c.org_id = p_org_id)
                AND (c.expires_at IS NULL OR c.expires_at > NOW())
                ORDER BY c.level_number, c.path;
            END IF;
            
            RETURN;
        END IF;
    END IF;

    -- بناء شجرة جديدة
    IF items_table_exists THEN
        WITH RECURSIVE bom_tree AS (
            -- الجذر (المنتج النهائي)
            SELECT 
                0 AS level,
                bh.item_id,
                NULL::UUID AS parent_item_id,
                p_quantity AS qty_required,
                p_quantity AS cumulative_qty,
                false AS is_critical,
                0 AS scrap_factor,
                'COMPONENT'::VARCHAR AS line_type,
                bh.id AS bom_id,
                '/' || bh.item_id::TEXT AS path
            FROM bom_headers bh
            WHERE bh.id = p_bom_id
            AND (p_org_id IS NULL OR bh.org_id = p_org_id)
            
            UNION ALL
            
            -- المستويات الفرعية
            SELECT 
                bt.level + 1,
                bl.item_id,
                bt.item_id AS parent_item_id,
                bt.qty_required * bl.quantity * (1 + COALESCE(bl.scrap_factor, 0)/100) AS qty_required,
                bt.cumulative_qty * bl.quantity * (1 + COALESCE(bl.scrap_factor, 0)/100) AS cumulative_qty,
                COALESCE(bl.is_critical, false) AS is_critical,
                COALESCE(bl.scrap_factor, 0) AS scrap_factor,
                COALESCE(bl.line_type, 'COMPONENT')::VARCHAR AS line_type,
                COALESCE(sub_bh.id, bt.bom_id) AS bom_id,
                bt.path || '/' || bl.item_id::TEXT AS path
            FROM bom_tree bt
            JOIN bom_lines bl ON bl.bom_id = bt.bom_id
            LEFT JOIN bom_headers sub_bh ON sub_bh.item_id = bl.item_id 
                AND sub_bh.is_active = true
                AND (p_org_id IS NULL OR sub_bh.org_id = p_org_id)
            WHERE bt.level < 20
            AND bl.line_type != 'REFERENCE'
        )
        INSERT INTO bom_tree_cache (
            bom_id, parent_id, item_id, level_number, 
            quantity_required, cumulative_quantity, 
            unit_cost, total_cost, is_critical, scrap_factor, 
            line_type, path, org_id, expires_at
        )
        SELECT DISTINCT ON (bt.item_id, bt.path)
            p_bom_id,
            NULL, -- سيتم تحديثه لاحقاً
            bt.item_id,
            bt.level,
            bt.qty_required,
            bt.cumulative_qty,
            COALESCE(i.unit_cost, i.standard_cost, 0) AS unit_cost,
            bt.cumulative_qty * COALESCE(i.unit_cost, i.standard_cost, 0) AS total_cost,
            bt.is_critical,
            bt.scrap_factor,
            bt.line_type,
            bt.path,
            COALESCE(p_org_id, (SELECT org_id FROM bom_headers WHERE id = p_bom_id)),
            NOW() + v_cache_expiry
        FROM bom_tree bt
        LEFT JOIN items i ON i.id = bt.item_id
        ORDER BY bt.item_id, bt.path, bt.level;
    END IF;

    -- تحديث parent_id
    UPDATE bom_tree_cache c1
    SET parent_id = c2.id
    FROM bom_tree_cache c2
    WHERE c1.bom_id = p_bom_id
    AND c1.path LIKE c2.path || '/%'
    AND c1.level_number = c2.level_number + 1
    AND (p_org_id IS NULL OR c1.org_id = p_org_id);

    -- إرجاع النتيجة
    IF items_table_exists THEN
        RETURN QUERY
        SELECT 
            c.id,
            c.parent_id,
            c.item_id,
            COALESCE(i.code, i.item_code)::VARCHAR AS item_code,
            COALESCE(i.name, i.item_name)::VARCHAR AS item_name,
            c.level_number,
            c.quantity_required,
            c.cumulative_quantity,
            c.unit_cost,
            c.total_cost,
            c.is_critical,
            c.scrap_factor,
            c.line_type,
            c.path,
            EXISTS(
                SELECT 1 FROM bom_tree_cache child 
                WHERE child.parent_id = c.id
            ) AS has_children
        FROM bom_tree_cache c
        LEFT JOIN items i ON i.id = c.item_id
        WHERE c.bom_id = p_bom_id
        AND (p_org_id IS NULL OR c.org_id = p_org_id)
        ORDER BY c.level_number, c.path;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_available_capacity(p_work_center_id uuid, p_start_date date, p_end_date date)
 RETURNS TABLE(total_available_hours numeric, working_days integer, avg_daily_hours numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    WITH calendar_data AS (
        SELECT 
            COALESCE(wcc.available_hours, wc.capacity_hours_per_day) - 
            COALESCE(wcc.planned_maintenance_hours, 0) as daily_hours,
            COALESCE(wcc.is_working_day, true) as is_working
        FROM generate_series(p_start_date, p_end_date, '1 day'::interval) d(date)
        CROSS JOIN work_centers wc
        LEFT JOIN work_center_calendars wcc 
            ON wcc.work_center_id = wc.id 
            AND wcc.calendar_date = d.date::DATE
        WHERE wc.id = p_work_center_id
    )
    SELECT 
        COALESCE(SUM(CASE WHEN is_working THEN daily_hours ELSE 0 END), 0)::DECIMAL as total_available_hours,
        COUNT(*) FILTER (WHERE is_working)::INTEGER as working_days,
        COALESCE(AVG(CASE WHEN is_working THEN daily_hours ELSE NULL END), 0)::DECIMAL as avg_daily_hours
    FROM calendar_data;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_bom_cost(p_bom_id uuid, p_quantity numeric DEFAULT 1)
 RETURNS numeric
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_total_cost NUMERIC := 0;
    items_table_exists BOOLEAN;
BEGIN
    -- تحديد الجدول المستخدم
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_name = 'items'
    ) INTO items_table_exists;

    IF items_table_exists THEN
        -- استخدام items
        SELECT COALESCE(SUM(
            eb.quantity_required * 
            COALESCE(i.unit_cost, i.standard_cost, i.cost_price, 0)
        ), 0)
        INTO v_total_cost
        FROM explode_bom(p_bom_id, p_quantity) eb
        LEFT JOIN items i ON i.id = eb.item_id;
    ELSE
        -- استخدام products
        SELECT COALESCE(SUM(
            eb.quantity_required * 
            COALESCE(p.unit_cost, p.standard_cost, p.cost_price, 0)
        ), 0)
        INTO v_total_cost
        FROM explode_bom(p_bom_id, p_quantity) eb
        LEFT JOIN products p ON p.id = eb.item_id;
    END IF;
    
    RETURN v_total_cost;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_bom_standard_cost(p_bom_id uuid, p_quantity numeric DEFAULT 1, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(material_cost numeric, labor_cost numeric, overhead_cost numeric, total_cost numeric, unit_cost numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_material_cost NUMERIC := 0;
    v_labor_cost NUMERIC := 0;
    v_overhead_cost NUMERIC := 0;
    v_total_cost NUMERIC := 0;
    items_table_exists BOOLEAN;
    products_table_exists BOOLEAN;
BEGIN
    -- تحديد الجدول المستخدم
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_name = 'items'
    ) INTO items_table_exists;
    
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_name = 'products'
    ) INTO products_table_exists;

    -- حساب تكلفة المواد
    IF items_table_exists THEN
        SELECT COALESCE(SUM(
            eb.quantity_required * 
            COALESCE(i.standard_cost, i.unit_cost, 0)
        ), 0)
        INTO v_material_cost
        FROM explode_bom(p_bom_id, p_quantity, p_org_id) eb
        LEFT JOIN items i ON i.id = eb.item_id
        WHERE eb.line_type = 'COMPONENT';
    ELSIF products_table_exists THEN
        SELECT COALESCE(SUM(
            eb.quantity_required * 
            COALESCE(p.standard_cost, p.unit_cost, 0)
        ), 0)
        INTO v_material_cost
        FROM explode_bom(p_bom_id, p_quantity, p_org_id) eb
        LEFT JOIN products p ON p.id = eb.item_id
        WHERE eb.line_type = 'COMPONENT';
    END IF;

    -- حساب تكلفة العمالة (من routing إذا كان موجوداً)
    SELECT COALESCE(SUM(
        bo.setup_time_minutes / 60.0 * COALESCE(bo.labor_rate, 0) +
        bo.run_time_minutes / 60.0 * COALESCE(bo.labor_rate, 0) * p_quantity
    ), 0)
    INTO v_labor_cost
    FROM bom_operations bo
    WHERE bo.bom_id = p_bom_id
    AND bo.is_active = true
    AND (p_org_id IS NULL OR bo.org_id = p_org_id);

    -- حساب التكاليف غير المباشرة (نسبة من العمالة)
    SELECT COALESCE(v_labor_cost * 0.15, 0) INTO v_overhead_cost; -- 15% افتراضي

    -- التكلفة الإجمالية
    v_total_cost := v_material_cost + v_labor_cost + v_overhead_cost;

    RETURN QUERY SELECT 
        v_material_cost,
        v_labor_cost,
        v_overhead_cost,
        v_total_cost,
        CASE WHEN p_quantity > 0 THEN v_total_cost / p_quantity ELSE 0 END;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_bom_total_cost()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  NEW.total_cost = NEW.quantity * NEW.unit_cost;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_labor_variances(p_mo_id uuid, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date)
 RETURNS TABLE(work_center_code character varying, work_center_name character varying, standard_hours numeric, actual_hours numeric, standard_rate numeric, actual_rate numeric, rate_variance numeric, efficiency_variance numeric, total_variance numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    IF to_regclass('public.labor_entries') IS NULL THEN
        RETURN; -- جداول التتبع غير مفعَّلة — فارغ بدل 42P01
    END IF;
    RETURN QUERY EXECUTE format($q$
        SELECT wc.code::varchar, wc.name::varchar,
               SUM(le.standard_hours), SUM(le.actual_hours),
               AVG(le.standard_rate), AVG(le.actual_rate),
               SUM((le.actual_rate - le.standard_rate) * le.actual_hours),
               SUM((le.actual_hours - le.standard_hours) * le.standard_rate),
               SUM((le.actual_rate - le.standard_rate) * le.actual_hours) +
               SUM((le.actual_hours - le.standard_hours) * le.standard_rate)
        FROM labor_entries le
        JOIN work_centers wc ON wc.id = le.work_center_id
        WHERE le.mo_id = %L
          AND (%L::date IS NULL OR le.entry_date >= %L::date)
          AND (%L::date IS NULL OR le.entry_date <= %L::date)
        GROUP BY wc.code, wc.name ORDER BY wc.code
    $q$, p_mo_id, p_start_date, p_start_date, p_end_date, p_end_date);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_material_variances(p_mo_id uuid, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date)
 RETURNS TABLE(product_code character varying, product_name character varying, standard_qty numeric, actual_qty numeric, standard_cost numeric, actual_cost numeric, qty_variance numeric, price_variance numeric, efficiency_variance numeric, total_variance numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    IF to_regclass('public.stock_moves') IS NULL THEN
        RETURN; -- جداول التتبع غير مفعَّلة — فارغ بدل 42P01
    END IF;
    RETURN QUERY EXECUTE format($q$
        SELECT sm.product_code::varchar, p.name::varchar,
               SUM(sm.quantity), SUM(sm.actual_quantity),
               SUM(sm.standard_cost), SUM(sm.total_cost),
               SUM((sm.quantity - COALESCE(sm.actual_quantity,0)) * sm.unit_cost),
               SUM((sm.unit_cost - COALESCE(sm.actual_unit_cost, sm.unit_cost)) * COALESCE(sm.actual_quantity, sm.quantity)),
               0::NUMERIC,
               SUM((sm.quantity - COALESCE(sm.actual_quantity,0)) * sm.unit_cost) +
               SUM((sm.unit_cost - COALESCE(sm.actual_unit_cost, sm.unit_cost)) * COALESCE(sm.actual_quantity, sm.quantity))
        FROM stock_moves sm
        JOIN products p ON sm.product_code = p.code
        WHERE sm.move_type = 'material_issue'
          AND sm.reference_id::text = %L::text
          AND (%L::date IS NULL OR sm.date >= %L::date)
          AND (%L::date IS NULL OR sm.date <= %L::date)
        GROUP BY sm.product_code, p.name ORDER BY sm.product_code
    $q$, p_mo_id, p_start_date, p_start_date, p_end_date, p_end_date);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_planned_load(p_work_center_id uuid, p_start_date date, p_end_date date)
 RETURNS TABLE(total_planned_hours numeric, total_work_orders integer, pending_work_orders integer, in_progress_work_orders integer)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(SUM((wo.planned_setup_time + wo.planned_run_time) / 60), 0)::DECIMAL as total_planned_hours,
        COUNT(*)::INTEGER as total_work_orders,
        COUNT(*) FILTER (WHERE wo.status IN ('PENDING', 'READY'))::INTEGER as pending_work_orders,
        COUNT(*) FILTER (WHERE wo.status = 'IN_PROGRESS')::INTEGER as in_progress_work_orders
    FROM work_orders wo
    WHERE wo.work_center_id = p_work_center_id
    AND wo.status NOT IN ('COMPLETED', 'CANCELLED')
    AND (
        (wo.planned_start_date::DATE BETWEEN p_start_date AND p_end_date)
        OR (wo.planned_end_date::DATE BETWEEN p_start_date AND p_end_date)
        OR (wo.planned_start_date IS NULL AND wo.created_at::DATE BETWEEN p_start_date AND p_end_date)
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_risk_score()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  NEW.risk_score = (NEW.probability * NEW.impact) / 100;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_routing_cost(p_bom_id uuid, p_quantity numeric DEFAULT 1, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(operation_sequence integer, operation_code character varying, operation_name character varying, setup_cost numeric, run_cost numeric, total_cost numeric, total_time_minutes numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        bo.operation_sequence,
        bo.operation_code,
        bo.operation_name,
        bo.setup_cost,
        bo.run_cost_per_unit * p_quantity AS run_cost,
        bo.setup_cost + (bo.run_cost_per_unit * p_quantity) AS total_cost,
        bo.setup_time_minutes + (bo.run_time_minutes * p_quantity) AS total_time_minutes
    FROM bom_operations bo
    WHERE bo.bom_id = p_bom_id
    AND bo.is_active = true
    AND (p_org_id IS NULL OR bo.org_id = p_org_id)
    ORDER BY bo.operation_sequence;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_routing_standard_cost(p_routing_id uuid, p_quantity numeric DEFAULT 1)
 RETURNS TABLE(total_labor_cost numeric, total_overhead_cost numeric, total_routing_cost numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(SUM(
            ((ro.standard_setup_time + (ro.standard_run_time_per_unit * p_quantity)) / 60) * 
            COALESCE(ro.labor_rate_per_hour, wc.default_labor_rate, 0)
        ), 0) as total_labor_cost,
        COALESCE(SUM(
            ((ro.standard_setup_time + (ro.standard_run_time_per_unit * p_quantity)) / 60) * 
            COALESCE(ro.overhead_rate_per_hour, wc.default_overhead_rate, 0)
        ), 0) as total_overhead_cost,
        COALESCE(SUM(
            ((ro.standard_setup_time + (ro.standard_run_time_per_unit * p_quantity)) / 60) * 
            (COALESCE(ro.labor_rate_per_hour, wc.default_labor_rate, 0) + 
             COALESCE(ro.overhead_rate_per_hour, wc.default_overhead_rate, 0))
        ), 0) as total_routing_cost
    FROM routing_operations ro
    LEFT JOIN work_centers wc ON ro.work_center_id = wc.id
    WHERE ro.routing_id = p_routing_id
    AND ro.is_active = true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_routing_total_time(p_routing_id uuid, p_quantity numeric DEFAULT 1)
 RETURNS TABLE(total_setup_time numeric, total_run_time numeric, total_queue_time numeric, total_move_time numeric, total_lead_time numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(SUM(ro.standard_setup_time), 0) as total_setup_time,
        COALESCE(SUM(ro.standard_run_time_per_unit * p_quantity), 0) as total_run_time,
        COALESCE(SUM(ro.standard_queue_time), 0) as total_queue_time,
        COALESCE(SUM(ro.standard_move_time), 0) as total_move_time,
        COALESCE(SUM(
            ro.standard_setup_time + 
            (ro.standard_run_time_per_unit * p_quantity) + 
            ro.standard_queue_time + 
            ro.standard_move_time
        ), 0) as total_lead_time
    FROM routing_operations ro
    WHERE ro.routing_id = p_routing_id
    AND ro.is_active = true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_total_routing_cost(p_bom_id uuid, p_quantity numeric DEFAULT 1, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_total_cost NUMERIC := 0;
BEGIN
    SELECT COALESCE(SUM(total_cost), 0)
    INTO v_total_cost
    FROM calculate_routing_cost(p_bom_id, p_quantity, p_org_id);
    
    RETURN v_total_cost;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_wip_equivalent_units()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    -- Calculate Equivalent Units for Materials
    NEW.equivalent_units_material := 
        (NEW.units_completed * (NEW.material_completion_pct / 100.0)) +
        (NEW.units_ending_wip * (NEW.material_completion_pct / 100.0));
    
    -- Calculate Equivalent Units for Conversion (Labor + Overhead)
    NEW.equivalent_units_conversion := 
        (NEW.units_completed * (NEW.conversion_completion_pct / 100.0)) +
        (NEW.units_ending_wip * (NEW.conversion_completion_pct / 100.0));
    
    -- Calculate Cost per Equivalent Unit (Weighted Average Method)
    IF NEW.equivalent_units_material > 0 THEN
        NEW.cost_per_eu_material := 
            (NEW.cost_beginning_wip + NEW.cost_material + NEW.cost_transferred_in) / 
            NEW.equivalent_units_material;
    ELSE
        NEW.cost_per_eu_material := 0;
    END IF;
    
    IF NEW.equivalent_units_conversion > 0 THEN
        NEW.cost_per_eu_conversion := 
            (NEW.cost_labor + NEW.cost_overhead) / 
            NEW.equivalent_units_conversion;
    ELSE
        NEW.cost_per_eu_conversion := 0;
    END IF;
    
    -- Calculate Valuation
    NEW.cost_completed_transferred := 
        (NEW.units_completed * NEW.cost_per_eu_material) +
        (NEW.units_completed * NEW.cost_per_eu_conversion);
    
    NEW.cost_ending_wip := 
        (NEW.units_ending_wip * NEW.material_completion_pct / 100.0 * NEW.cost_per_eu_material) +
        (NEW.units_ending_wip * NEW.conversion_completion_pct / 100.0 * NEW.cost_per_eu_conversion);
    
    RETURN NEW;
END;
$function$
;

