CREATE OR REPLACE FUNCTION public.check_approval_required()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  -- Require approval if absolute value difference > 10,000
  IF ABS(NEW.total_value_difference) > 10000 THEN
    NEW.requires_approval := TRUE;
  ELSE
    NEW.requires_approval := FALSE;
  END IF;
  
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_balance_before_post()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    IF NEW.status = 'posted' AND OLD.status != 'posted' THEN
        IF ABS(NEW.total_debit - NEW.total_credit) > 0.01 THEN
            RAISE EXCEPTION 'لا يمكن ترحيل قيد غير متوازن';
        END IF;
        NEW.posted_at = NOW();
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_entry_approval_required(p_entry_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_org_id UUID;
    v_entry_amount NUMERIC;
    v_approval_limit NUMERIC;
    v_requires_approval BOOLEAN := false;
BEGIN
    -- Get org context
    BEGIN
        v_org_id := current_setting('app.current_org_id', true)::UUID;
    EXCEPTION WHEN OTHERS THEN
        v_org_id := '00000000-0000-0000-0000-000000000001'::UUID;
    END;
    
    -- Get entry total amount
    SELECT COALESCE(SUM(GREATEST(debit_amount, credit_amount)), 0)
    INTO v_entry_amount
    FROM gl_entry_lines
    WHERE entry_id = p_entry_id;
    
    -- Get approval limit from organization settings (if exists)
    -- For now, return false (no approval required)
    -- TODO: Implement approval workflow settings
    
    RETURN v_requires_approval;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.check_materials_availability(p_org_id uuid, p_materials jsonb[])
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_material JSONB;
    v_required DECIMAL;
    v_available DECIMAL;
    v_result JSONB := jsonb_build_object('available', true, 'items', jsonb_build_array());
    v_item_result JSONB;
BEGIN
    FOREACH v_material IN ARRAY p_materials
    LOOP
        v_required := (v_material->>'quantity')::DECIMAL;
        v_available := get_available_quantity(
            p_org_id,
            (v_material->>'item_id')::UUID,
            (v_material->>'location_id')::UUID
        );
        
        v_item_result := jsonb_build_object(
            'item_id', v_material->>'item_id',
            'required', v_required,
            'available', v_available,
            'sufficient', v_available >= v_required
        );
        
        v_result := jsonb_set(
            v_result,
            '{items}',
            (v_result->'items')::jsonb || jsonb_build_array(v_item_result)
        );
        
        IF v_available < v_required THEN
            v_result := jsonb_set(v_result, '{available}', 'false'::jsonb);
        END IF;
    END LOOP;
    
    RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_bom_tree_cache()
 RETURNS integer
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_deleted_count INTEGER;
BEGIN
    DELETE FROM bom_tree_cache
    WHERE expires_at IS NOT NULL 
    AND expires_at < NOW() - INTERVAL '24 hours';
    
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    RETURN v_deleted_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.compare_bom_costs(p_bom_id uuid, p_quantity numeric DEFAULT 1, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(cost_type character varying, standard_cost numeric, actual_cost numeric, variance numeric, variance_pct numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    WITH standard AS (
        SELECT * FROM calculate_bom_standard_cost(p_bom_id, p_quantity, p_org_id)
    ),
    actual AS (
        SELECT 
            COALESCE(SUM(material_cost), 0) AS material_cost,
            COALESCE(SUM(labor_cost), 0) AS labor_cost,
            COALESCE(SUM(overhead_cost), 0) AS overhead_cost
        FROM (
            SELECT 
                actual_material_cost AS material_cost,
                actual_labor_cost AS labor_cost,
                actual_overhead_cost AS overhead_cost
            FROM bom_cost_analysis bca
            WHERE bca.bom_id = p_bom_id
            AND (p_org_id IS NULL OR bca.org_id = p_org_id)
            AND bca.status = 'APPROVED'
            ORDER BY bca.analysis_date DESC
            LIMIT 1
        ) latest
    )
    SELECT 
        'Material'::VARCHAR,
        s.material_cost,
        COALESCE(a.material_cost, 0),
        COALESCE(a.material_cost, 0) - s.material_cost,
        CASE WHEN s.material_cost > 0 
            THEN ((COALESCE(a.material_cost, 0) - s.material_cost) / s.material_cost * 100)
            ELSE 0 END
    FROM standard s
    CROSS JOIN actual a
    
    UNION ALL
    
    SELECT 
        'Labor'::VARCHAR,
        s.labor_cost,
        COALESCE(a.labor_cost, 0),
        COALESCE(a.labor_cost, 0) - s.labor_cost,
        CASE WHEN s.labor_cost > 0 
            THEN ((COALESCE(a.labor_cost, 0) - s.labor_cost) / s.labor_cost * 100)
            ELSE 0 END
    FROM standard s
    CROSS JOIN actual a
    
    UNION ALL
    
    SELECT 
        'Overhead'::VARCHAR,
        s.overhead_cost,
        COALESCE(a.overhead_cost, 0),
        COALESCE(a.overhead_cost, 0) - s.overhead_cost,
        CASE WHEN s.overhead_cost > 0 
            THEN ((COALESCE(a.overhead_cost, 0) - s.overhead_cost) / s.overhead_cost * 100)
            ELSE 0 END
    FROM standard s
    CROSS JOIN actual a;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.complete_operation(p_work_order_id uuid, p_quantity_produced numeric, p_quantity_scrapped numeric DEFAULT 0, p_notes text DEFAULT NULL::text)
 RETURNS work_orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_work_order work_orders;
    v_labor_tracking labor_time_tracking;
    v_duration DECIMAL;
BEGIN
    -- الحصول على أمر العمل
    SELECT * INTO v_work_order FROM work_orders WHERE id = p_work_order_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Work order not found: %', p_work_order_id;
    END IF;

    -- [120] حارس عضوية على مؤسسة أمر العمل
    PERFORM public.wardah_assert_org_member(v_work_order.org_id);

    -- إغلاق تسجيل الوقت
    UPDATE labor_time_tracking SET
        clock_out = NOW(),
        total_minutes = EXTRACT(EPOCH FROM (NOW() - clock_in)) / 60,
        billable_minutes = EXTRACT(EPOCH FROM (NOW() - clock_in)) / 60 - break_minutes,
        status = 'COMPLETED',
        updated_at = NOW()
    WHERE work_order_id = p_work_order_id AND status = 'ACTIVE'
    RETURNING * INTO v_labor_tracking;

    -- حساب الوقت الفعلي
    IF v_labor_tracking.labor_type = 'SETUP' THEN
        v_duration := COALESCE(v_labor_tracking.billable_minutes, 0);
        UPDATE work_orders SET
            actual_setup_time = actual_setup_time + v_duration
        WHERE id = p_work_order_id;
    ELSE
        v_duration := COALESCE(v_labor_tracking.billable_minutes, 0);
        UPDATE work_orders SET
            actual_run_time = actual_run_time + v_duration
        WHERE id = p_work_order_id;
    END IF;

    -- تحديث أمر العمل
    UPDATE work_orders SET
        completed_quantity = completed_quantity + p_quantity_produced,
        scrapped_quantity = scrapped_quantity + p_quantity_scrapped,
        status = CASE
            WHEN (completed_quantity + p_quantity_produced + scrapped_quantity + p_quantity_scrapped) >= planned_quantity
            THEN 'COMPLETED'
            ELSE status
        END,
        actual_end_date = CASE
            WHEN (completed_quantity + p_quantity_produced + scrapped_quantity + p_quantity_scrapped) >= planned_quantity
            THEN NOW()
            ELSE actual_end_date
        END,
        notes = COALESCE(notes || E'\n', '') || COALESCE(p_notes, ''),
        updated_at = NOW()
    WHERE id = p_work_order_id
    RETURNING * INTO v_work_order;

    -- تسجيل الحدث
    INSERT INTO operation_execution_logs (
        org_id, work_order_id, event_type, operator_id,
        quantity_produced, quantity_scrapped, notes, event_timestamp
    ) VALUES (
        v_work_order.org_id, p_work_order_id, 'PRODUCTION_END', v_work_order.current_operator_id,
        p_quantity_produced, p_quantity_scrapped, p_notes, NOW()
    );

    RETURN v_work_order;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.comprehensive_data_integrity_check(p_org_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_result JSONB := jsonb_build_object(
        'valid', true,
        'checks', jsonb_build_array(),
        'errors', jsonb_build_array(),
        'warnings', jsonb_build_array()
    );
    v_check_result JSONB;
    v_table_name TEXT;
    v_tables TEXT[] := ARRAY[
        'manufacturing_orders',
        'inventory_items',
        'stock_moves',
        'gl_accounts',
        'journal_entries',
        'sales_orders',
        'purchase_orders'
    ];
BEGIN
    -- Check each table
    FOREACH v_table_name IN ARRAY v_tables
    LOOP
        -- Check org_id presence
        SELECT jsonb_build_object(
            'table', v_table_name,
            'check', 'org_id_presence',
            'valid', NOT EXISTS (
                SELECT 1 FROM information_schema.columns
                WHERE table_name = v_table_name
                AND column_name = 'org_id'
            ) OR NOT EXISTS (
                SELECT 1 FROM information_schema.tables t
                WHERE t.table_name = v_table_name
                AND EXISTS (
                    SELECT 1 FROM pg_class c
                    JOIN pg_namespace n ON n.oid = c.relnamespace
                    WHERE c.relname = v_table_name
                    AND n.nspname = 'public'
                    AND EXISTS (
                        SELECT 1 FROM information_schema.columns
                        WHERE table_name = v_table_name
                        AND column_name = 'org_id'
                        AND is_nullable = 'NO'
                    )
                )
            )
        ) INTO v_check_result;
        
        v_result := jsonb_set(
            v_result,
            '{checks}',
            (v_result->'checks')::jsonb || jsonb_build_array(v_check_result)
        );
    END LOOP;
    
    -- Check stock balance
    IF EXISTS (SELECT 1 FROM validate_stock_balance(p_org_id)) THEN
        v_result := jsonb_set(v_result, '{valid}', 'false'::jsonb);
        v_result := jsonb_set(
            v_result,
            '{errors}',
            (v_result->'errors')::jsonb || jsonb_build_array('Stock balance mismatches found')
        );
    END IF;
    
    -- Check reservations
    IF EXISTS (SELECT 1 FROM validate_reservations(p_org_id)) THEN
        v_result := jsonb_set(v_result, '{valid}', 'false'::jsonb);
        v_result := jsonb_set(
            v_result,
            '{warnings}',
            (v_result->'warnings')::jsonb || jsonb_build_array('Reservation issues found')
        );
    END IF;
    
    RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.consume_materials_for_mo(p_org_id uuid, p_mo_id uuid, p_consumptions jsonb[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_consumption JSONB;
    v_stock_move_id UUID;
    v_result JSONB;
BEGIN
    -- Start transaction
    
    -- 1. Release reservations
    UPDATE material_reservations
    SET status = 'consumed',
        consumed_at = NOW()
    WHERE mo_id = p_mo_id
    AND org_id = p_org_id
    AND status = 'reserved';
    
    -- 2. Create stock moves
    FOREACH v_consumption IN ARRAY p_consumptions
    LOOP
        INSERT INTO stock_moves (
            org_id,
            item_id,
            move_type,
            quantity,
            unit_cost,
            reference_type,
            reference_id
        ) VALUES (
            p_org_id,
            (v_consumption->>'item_id')::UUID,
            'manufacturing_consume',
            -(v_consumption->>'quantity')::DECIMAL, -- Negative for consumption
            (v_consumption->>'unit_cost')::DECIMAL,
            'manufacturing_order',
            p_mo_id
        ) RETURNING id INTO v_stock_move_id;
    END LOOP;
    
    -- 3. Update stock quants (via trigger or explicit update)
    -- This would typically be handled by a trigger
    
    -- 4. Return success
    RETURN jsonb_build_object(
        'success', true,
        'mo_id', p_mo_id,
        'consumptions', array_length(p_consumptions, 1)
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', SQLERRM
        );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.copy_routing(p_routing_id uuid, p_new_code character varying, p_new_version integer DEFAULT 1)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_new_routing_id UUID;
    v_org_id UUID;
BEGIN
    -- الحصول على org_id من المسار الأصلي
    SELECT org_id INTO v_org_id FROM routings WHERE id = p_routing_id;

    -- [120] حارس عضوية على مؤسسة المسار
    IF v_org_id IS NULL THEN
        RAISE EXCEPTION 'Routing not found: %', p_routing_id;
    END IF;
    PERFORM public.wardah_assert_org_member(v_org_id);

    -- إنشاء المسار الجديد
    INSERT INTO routings (
        org_id, routing_code, routing_name, routing_name_ar,
        description, description_ar, version, status, item_id,
        effective_date, created_by
    )
    SELECT
        org_id, p_new_code, routing_name || ' (Copy)', routing_name_ar,
        description, description_ar, p_new_version, 'DRAFT', item_id,
        CURRENT_DATE, auth.uid()
    FROM routings
    WHERE id = p_routing_id
    RETURNING id INTO v_new_routing_id;

    -- نسخ العمليات
    INSERT INTO routing_operations (
        org_id, routing_id, operation_sequence, operation_code,
        operation_name, operation_name_ar, description, work_center_id,
        standard_setup_time, standard_run_time_per_unit, standard_queue_time,
        standard_move_time, time_unit, labor_rate_per_hour, overhead_rate_per_hour,
        operation_type, is_outsourced, requires_inspection
    )
    SELECT
        org_id, v_new_routing_id, operation_sequence, operation_code,
        operation_name, operation_name_ar, description, work_center_id,
        standard_setup_time, standard_run_time_per_unit, standard_queue_time,
        standard_move_time, time_unit, labor_rate_per_hour, overhead_rate_per_hour,
        operation_type, is_outsourced, requires_inspection
    FROM routing_operations
    WHERE routing_id = p_routing_id;

    -- نسخ الموارد
    INSERT INTO operation_resources (
        org_id, operation_id, resource_type, resource_code,
        resource_name, quantity_required, unit_of_measure, cost_rate, notes
    )
    SELECT
        orr.org_id,
        (SELECT nro.id FROM routing_operations nro
         WHERE nro.routing_id = v_new_routing_id
         AND nro.operation_sequence = ro.operation_sequence),
        orr.resource_type, orr.resource_code, orr.resource_name,
        orr.quantity_required, orr.unit_of_measure, orr.cost_rate, orr.notes
    FROM operation_resources orr
    JOIN routing_operations ro ON orr.operation_id = ro.id
    WHERE ro.routing_id = p_routing_id;

    RETURN v_new_routing_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_bom_version()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    -- عند تحديث bom_version، أنشئ سجل في جدول الإصدارات
    IF (TG_OP = 'UPDATE' AND OLD.bom_version IS DISTINCT FROM NEW.bom_version) THEN
        INSERT INTO bom_versions (bom_id, version_number, change_description, org_id)
        VALUES (NEW.id, NEW.bom_version, 'Version updated', NEW.org_id);
    END IF;
    
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_crud_permissions(p_module_name character varying, p_resource character varying, p_resource_ar character varying, p_include_approve boolean DEFAULT false)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_module_id UUID;
BEGIN
    SELECT id INTO v_module_id FROM modules WHERE name = p_module_name;
    
    IF v_module_id IS NULL THEN
        RAISE NOTICE 'Module % not found', p_module_name;
        RETURN;
    END IF;

    -- Read
    INSERT INTO permissions (module_id, resource, resource_ar, action, action_ar, permission_key, description_ar)
    VALUES (v_module_id, p_resource, p_resource_ar, 'read', 'عرض', 
            p_module_name || '.' || p_resource || '.read', 
            'عرض ' || p_resource_ar)
    ON CONFLICT (permission_key) DO NOTHING;

    -- Create
    INSERT INTO permissions (module_id, resource, resource_ar, action, action_ar, permission_key, description_ar)
    VALUES (v_module_id, p_resource, p_resource_ar, 'create', 'إنشاء', 
            p_module_name || '.' || p_resource || '.create', 
            'إنشاء ' || p_resource_ar)
    ON CONFLICT (permission_key) DO NOTHING;

    -- Update
    INSERT INTO permissions (module_id, resource, resource_ar, action, action_ar, permission_key, description_ar)
    VALUES (v_module_id, p_resource, p_resource_ar, 'update', 'تعديل', 
            p_module_name || '.' || p_resource || '.update', 
            'تعديل ' || p_resource_ar)
    ON CONFLICT (permission_key) DO NOTHING;

    -- Delete
    INSERT INTO permissions (module_id, resource, resource_ar, action, action_ar, permission_key, description_ar)
    VALUES (v_module_id, p_resource, p_resource_ar, 'delete', 'حذف', 
            p_module_name || '.' || p_resource || '.delete', 
            'حذف ' || p_resource_ar)
    ON CONFLICT (permission_key) DO NOTHING;

    -- Approve (اختياري)
    IF p_include_approve THEN
        INSERT INTO permissions (module_id, resource, resource_ar, action, action_ar, permission_key, description_ar)
        VALUES (v_module_id, p_resource, p_resource_ar, 'approve', 'اعتماد', 
                p_module_name || '.' || p_resource || '.approve', 
                'اعتماد ' || p_resource_ar)
        ON CONFLICT (permission_key) DO NOTHING;
    END IF;
END;
$function$
;

