CREATE OR REPLACE FUNCTION public.create_mo_with_reservation(p_org_id uuid, p_mo_data jsonb, p_materials jsonb[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_mo_id UUID;
    v_material JSONB;
    v_reservation_id UUID;
    v_result JSONB;
    v_errors TEXT[] := ARRAY[]::TEXT[];
BEGIN
    -- Start transaction (implicit in function)
    
    -- 1. Create manufacturing order
    INSERT INTO manufacturing_orders (
        org_id,
        mo_number,
        product_id,
        qty_planned,
        status
        -- ... other fields from p_mo_data can be added here
    )
    SELECT
        p_org_id,
        p_mo_data->>'mo_number',
        (p_mo_data->>'product_id')::UUID,
        (p_mo_data->>'qty_planned')::DECIMAL,
        'draft'
    RETURNING id INTO v_mo_id;
    
    -- 2. Reserve materials
    FOREACH v_material IN ARRAY p_materials
    LOOP
        -- Check availability
        IF NOT EXISTS (
            SELECT 1 FROM stock_quants
            WHERE item_id = (v_material->>'item_id')::UUID
            AND org_id = p_org_id
            AND quantity >= (v_material->>'quantity')::DECIMAL
        ) THEN
            v_errors := array_append(
                v_errors,
                format('Insufficient stock for item %s', v_material->>'item_id')
            );
            RAISE EXCEPTION 'Insufficient inventory';
        END IF;
        
        -- Create reservation
        INSERT INTO material_reservations (
            org_id,
            mo_id,
            item_id,
            quantity_reserved,
            status,
            reserved_at
        ) VALUES (
            p_org_id,
            v_mo_id,
            (v_material->>'item_id')::UUID,
            (v_material->>'quantity')::DECIMAL,
            'reserved',
            NOW()
        ) RETURNING id INTO v_reservation_id;
    END LOOP;
    
    -- 3. Return success result
    v_result := jsonb_build_object(
        'success', true,
        'mo_id', v_mo_id,
        'reservations', array_length(p_materials, 1)
    );
    
    RETURN v_result;
    
EXCEPTION
    WHEN OTHERS THEN
        -- Transaction will automatically rollback
        RETURN jsonb_build_object(
            'success', false,
            'error', SQLERRM,
            'mo_id', v_mo_id
        );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_role_from_template(p_org_id uuid, p_template_id uuid, p_custom_name character varying DEFAULT NULL::character varying, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_template role_templates%ROWTYPE;
    v_new_role_id UUID;
    v_perm_key TEXT;
BEGIN
    -- [120] بوابة admin على المؤسسة الهدف؛ p_created_by يُتجاهل (تصعيد محتمل)
    PERFORM public.wardah_assert_org_admin(p_org_id);

    -- جلب القالب
    SELECT * INTO v_template FROM role_templates WHERE id = p_template_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Template not found';
    END IF;

    -- إنشاء الدور
    INSERT INTO roles (org_id, name, name_ar, description_ar, created_by)
    VALUES (
        p_org_id,
        COALESCE(p_custom_name, v_template.name),
        v_template.name_ar,
        v_template.description_ar,
        auth.uid()
    )
    RETURNING id INTO v_new_role_id;

    -- إضافة الصلاحيات
    FOREACH v_perm_key IN ARRAY v_template.permission_keys
    LOOP
        INSERT INTO role_permissions (role_id, permission_id, created_by)
        SELECT v_new_role_id, p.id, auth.uid()
        FROM permissions p
        WHERE p.permission_key LIKE REPLACE(v_perm_key, '%', '%%')
           OR p.permission_key LIKE v_perm_key
        ON CONFLICT DO NOTHING;
    END LOOP;

    RETURN v_new_role_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_simple_org_rls(table_name text)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    -- Enable RLS
    EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', table_name);
    
    -- Drop existing policies
    EXECUTE format('DROP POLICY IF EXISTS %I_org_isolation ON %I', table_name, table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I_select_policy ON %I', table_name, table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I_insert_policy ON %I', table_name, table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I_update_policy ON %I', table_name, table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I_delete_policy ON %I', table_name, table_name);
    
    -- Create simple org-based policy (allow all operations for same org)
    EXECUTE format('
        CREATE POLICY %I_org_isolation ON %I
        FOR ALL
        USING (org_id = current_setting(''app.current_org_id'', true)::uuid)
        WITH CHECK (org_id = current_setting(''app.current_org_id'', true)::uuid)
    ', table_name, table_name);
    
    RAISE NOTICE 'Created simple RLS for table: %', table_name;
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE 'Could not create RLS for %: %', table_name, SQLERRM;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.ensure_column(p_table text, p_column text, p_type text, p_default text)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_exists BOOLEAN;
    v_sql TEXT;
BEGIN
    SELECT EXISTS (
        SELECT 1
        FROM information_schema.columns
        WHERE table_schema = 'public'
          AND table_name = p_table
          AND column_name = p_column
    ) INTO v_exists;

    IF NOT v_exists THEN
        v_sql := format(
            'ALTER TABLE %I ADD COLUMN %I %s',
            p_table, p_column, p_type
        );

    IF p_default IS NOT NULL THEN
        v_sql := v_sql || format(' DEFAULT %s', p_default);
        END IF;

        EXECUTE v_sql;
        RAISE NOTICE '✓ Added column % to %', p_column, p_table;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.explode_bom(p_bom_id uuid, p_quantity numeric DEFAULT 1, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(level_number integer, item_id uuid, item_code character varying, item_name character varying, quantity_required numeric, unit_of_measure character varying, is_critical boolean, scrap_factor numeric, line_type character varying)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    items_table_exists BOOLEAN;
    products_table_exists BOOLEAN;
BEGIN
    -- تحديد الجدول المستخدم (items أو products)
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_name = 'items'
    ) INTO items_table_exists;
    
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_name = 'products'
    ) INTO products_table_exists;

    -- استخدام items إذا كان موجوداً
    IF items_table_exists THEN
        RETURN QUERY
        WITH RECURSIVE bom_tree AS (
            SELECT 
                0 AS level,
                bh.item_id,
                bh.id AS bom_id,
                p_quantity AS qty_required,
                bl.is_critical,
                bl.scrap_factor,
                bl.line_type
            FROM bom_headers bh
            LEFT JOIN bom_lines bl ON bl.bom_id = bh.id
            WHERE bh.id = p_bom_id
            AND (p_org_id IS NULL OR bh.org_id = p_org_id)
            
            UNION ALL
            
            SELECT 
                bt.level + 1,
                bl.item_id,
                bh.id AS bom_id,
                bt.qty_required * bl.quantity * (1 + COALESCE(bl.scrap_factor, 0)/100),
                bl.is_critical,
                bl.scrap_factor,
                bl.line_type
            FROM bom_tree bt
            JOIN bom_lines bl ON bl.bom_id = bt.bom_id
            JOIN bom_headers bh ON bh.item_id = bl.item_id
            WHERE bt.level < 20
            AND bl.line_type != 'REFERENCE'
        )
        SELECT DISTINCT ON (bt.item_id)
            bt.level AS level_number,
            bt.item_id,
            COALESCE(i.code, i.item_code)::VARCHAR AS item_code,
            COALESCE(i.name, i.item_name)::VARCHAR AS item_name,
            bt.qty_required AS quantity_required,
            COALESCE(i.unit, i.unit_of_measure)::VARCHAR AS unit_of_measure,
            COALESCE(bt.is_critical, false) AS is_critical,
            COALESCE(bt.scrap_factor, 0) AS scrap_factor,
            COALESCE(bt.line_type, 'COMPONENT')::VARCHAR AS line_type
        FROM bom_tree bt
        LEFT JOIN items i ON i.id = bt.item_id
        ORDER BY bt.item_id, bt.level;
    
    -- استخدام products إذا كان موجوداً
    ELSIF products_table_exists THEN
        RETURN QUERY
        WITH RECURSIVE bom_tree AS (
            SELECT 
                0 AS level,
                bh.item_id,
                bh.id AS bom_id,
                p_quantity AS qty_required,
                bl.is_critical,
                bl.scrap_factor,
                bl.line_type
            FROM bom_headers bh
            LEFT JOIN bom_lines bl ON bl.bom_id = bh.id
            WHERE bh.id = p_bom_id
            AND (p_org_id IS NULL OR bh.org_id = p_org_id)
            
            UNION ALL
            
            SELECT 
                bt.level + 1,
                bl.item_id,
                bh.id AS bom_id,
                bt.qty_required * bl.quantity * (1 + COALESCE(bl.scrap_factor, 0)/100),
                bl.is_critical,
                bl.scrap_factor,
                bl.line_type
            FROM bom_tree bt
            JOIN bom_lines bl ON bl.bom_id = bt.bom_id
            JOIN bom_headers bh ON bh.item_id = bl.item_id
            WHERE bt.level < 20
            AND bl.line_type != 'REFERENCE'
        )
        SELECT DISTINCT ON (bt.item_id)
            bt.level AS level_number,
            bt.item_id,
            COALESCE(p.code, p.product_code)::VARCHAR AS item_code,
            COALESCE(p.name, p.product_name)::VARCHAR AS item_name,
            bt.qty_required AS quantity_required,
            COALESCE(p.unit, p.uom)::VARCHAR AS unit_of_measure,
            COALESCE(bt.is_critical, false) AS is_critical,
            COALESCE(bt.scrap_factor, 0) AS scrap_factor,
            COALESCE(bt.line_type, 'COMPONENT')::VARCHAR AS line_type
        FROM bom_tree bt
        LEFT JOIN products p ON p.id = bt.item_id
        ORDER BY bt.item_id, bt.level;
    ELSE
        RAISE EXCEPTION 'لا يوجد جدول items أو products';
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.fn_invitations_set_token_hash()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    IF NEW.token IS NOT NULL THEN
