$function$
;

CREATE OR REPLACE FUNCTION public.generate_adjustment_number()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  next_num INTEGER;
BEGIN
  -- Get next number for this organization
  SELECT COALESCE(MAX(
    CAST(SUBSTRING(adjustment_number FROM 'ADJ-(\d+)') AS INTEGER)
  ), 0) + 1 
  INTO next_num
  FROM stock_adjustments
  WHERE organization_id = NEW.organization_id;
  
  -- Generate formatted number
  NEW.adjustment_number := 'ADJ-' || LPAD(next_num::TEXT, 6, '0');
  
  RETURN NEW;
END;
$function$
;

