CREATE OR REPLACE FUNCTION public.generate_customer_receipt_number()
 RETURNS text
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_prefix TEXT := 'CR';
    v_year TEXT := TO_CHAR(CURRENT_DATE, 'YYYY');
    v_month TEXT := TO_CHAR(CURRENT_DATE, 'MM');
    v_sequence INTEGER;
    v_org_id UUID;
BEGIN
    -- Get org_id from current context (you may need to pass it as parameter)
    -- For now, we'll use a simple sequence
    SELECT COALESCE(MAX(CAST(SUBSTRING(collection_number FROM '[0-9]+$') AS INTEGER)), 0) + 1
    INTO v_sequence
    FROM customer_collections
    WHERE collection_number LIKE v_prefix || '-' || v_year || v_month || '%';
    
    RETURN v_prefix || '-' || v_year || v_month || '-' || LPAD(v_sequence::TEXT, 5, '0');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_entry_number(p_org_id uuid, p_entry_date date)
 RETURNS character varying
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_year VARCHAR(4);
    v_month VARCHAR(2);
    v_sequence INTEGER;
    v_entry_number VARCHAR(50);
BEGIN
    v_year := TO_CHAR(p_entry_date, 'YYYY');
    v_month := TO_CHAR(p_entry_date, 'MM');
    
    -- الحصول على آخر رقم في الشهر
    SELECT COALESCE(MAX(CAST(SPLIT_PART(entry_number, '-', 4) AS INTEGER)), 0) + 1
    INTO v_sequence
    FROM gl_entries
    WHERE org_id = p_org_id
    AND entry_number LIKE 'JE-' || v_year || '-' || v_month || '-%';
    
    v_entry_number := 'JE-' || v_year || '-' || v_month || '-' || LPAD(v_sequence::TEXT, 4, '0');
    
    RETURN v_entry_number;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_entry_number(p_journal_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_prefix VARCHAR(10);
    v_sequence_name TEXT;
    v_next_number INTEGER;
    v_entry_number TEXT;
    v_org_id UUID;
BEGIN
    -- الحصول على معلومات الدفتر
    SELECT sequence_prefix, org_id INTO v_prefix, v_org_id
    FROM journals
    WHERE id = p_journal_id;

    IF v_prefix IS NULL THEN
        RAISE EXCEPTION 'Journal not found: %', p_journal_id;
    END IF;

    -- [120] حارس عضوية على مؤسسة الدفتر
    PERFORM public.wardah_assert_org_member(v_org_id);

    -- إنشاء اسم تسلسل فريد لكل دفتر
    -- استخدام أسماء أبسط للـ sequences
    v_sequence_name := 'seq_' || lower(v_prefix);

    -- إنشاء التسلسل إذا لم يكن موجوداً
    BEGIN
        EXECUTE format('CREATE SEQUENCE IF NOT EXISTS %I START WITH 1', v_sequence_name);
    EXCEPTION
        WHEN duplicate_table THEN
            -- التسلسل موجود بالفعل، لا مشكلة
            NULL;
        WHEN OTHERS THEN
            -- في حالة أي خطأ آخر، نحاول المتابعة
            RAISE NOTICE 'Could not create sequence %, continuing...', v_sequence_name;
    END;

    -- الحصول على الرقم التالي
    BEGIN
        EXECUTE format('SELECT nextval(%L)', v_sequence_name) INTO v_next_number;
    EXCEPTION WHEN OTHERS THEN
        -- إذا فشل، نستخدم رقم 1
        v_next_number := 1;
    END;

    -- تنسيق رقم القيد: PREFIX-YYYY-NNNNNN
    v_entry_number := v_prefix || '-' || EXTRACT(YEAR FROM CURRENT_DATE) || '-' || LPAD(v_next_number::text, 6, '0');

    RETURN v_entry_number;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_entry_number_enhanced(p_journal_id uuid, p_entry_date date DEFAULT CURRENT_DATE)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_prefix TEXT;
    v_sequence_name TEXT;
    v_next_number INTEGER;
    v_entry_number TEXT;
    v_tenant_id UUID;
    v_year TEXT;
BEGIN
    -- Get tenant context
    v_tenant_id := current_setting('app.current_tenant_id', true)::UUID;
    
    -- Get journal prefix
    SELECT sequence_prefix INTO v_prefix
    FROM journals 
    WHERE id = p_journal_id;
    
    IF v_prefix IS NULL THEN
        -- Try to get from code
        SELECT code INTO v_prefix
        FROM journals
        WHERE id = p_journal_id;
        
        IF v_prefix IS NULL THEN
            RAISE EXCEPTION 'Journal not found';
        END IF;
    END IF;
    
    -- Get year
    v_year := EXTRACT(YEAR FROM p_entry_date)::TEXT;
    
    -- Create sequence name with year
    v_sequence_name := 'seq_' || lower(replace(v_prefix, '-', '_')) || '_' || v_year || '_' || replace(v_tenant_id::text, '-', '_');
    
    -- Create sequence if it doesn't exist
    BEGIN
        EXECUTE format('CREATE SEQUENCE IF NOT EXISTS %I START WITH 1', v_sequence_name);
    EXCEPTION WHEN OTHERS THEN
        NULL;
    END;
    
    -- Get next number
    EXECUTE format('SELECT nextval(%L)', v_sequence_name) INTO v_next_number;
    
    -- Format: PREFIX-YYYY-NNNNNN
    v_entry_number := v_prefix || '-' || v_year || '-' || LPAD(v_next_number::text, 6, '0');
    
    RETURN v_entry_number;
END;
$function$
;

