CREATE OR REPLACE FUNCTION public.generate_voucher_number(p_voucher_type text, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_org_id UUID;
    v_year TEXT;
    v_month TEXT;
    v_sequence INT;
    v_prefix TEXT;
    v_voucher_number TEXT;
BEGIN
    -- Get org context
    v_org_id := COALESCE(
        p_org_id,
        current_setting('app.current_org_id', true)::UUID,
        '00000000-0000-0000-0000-000000000001'::UUID
    );
    
    -- Get current year and month
    v_year := TO_CHAR(CURRENT_DATE, 'YYYY');
    v_month := TO_CHAR(CURRENT_DATE, 'MM');
    
    -- Set prefix based on voucher type
    v_prefix := CASE p_voucher_type
        WHEN 'RECEIPT' THEN 'RV'
        WHEN 'PAYMENT' THEN 'PV'
        ELSE 'VC'
    END;
    
    -- Get next sequence number
    -- Try to get from vouchers tables
    IF p_voucher_type = 'RECEIPT' THEN
        SELECT COALESCE(MAX(CAST(SUBSTRING(voucher_number FROM '[0-9]+$') AS INT)), 0) + 1
        INTO v_sequence
        FROM receipt_vouchers
        WHERE org_id = v_org_id
        AND voucher_number LIKE v_prefix || v_year || v_month || '%';
    ELSIF p_voucher_type = 'PAYMENT' THEN
        SELECT COALESCE(MAX(CAST(SUBSTRING(voucher_number FROM '[0-9]+$') AS INT)), 0) + 1
        INTO v_sequence
        FROM payment_vouchers
        WHERE org_id = v_org_id
        AND voucher_number LIKE v_prefix || v_year || v_month || '%';
    ELSE
        v_sequence := 1;
    END IF;
    
    -- Default to 1 if sequence is NULL
    v_sequence := COALESCE(v_sequence, 1);
    
    -- Generate voucher number: PREFIX-YYYYMM-NNNN
    v_voucher_number := v_prefix || '-' || v_year || v_month || '-' || LPAD(v_sequence::TEXT, 4, '0');
    
    RETURN v_voucher_number;
EXCEPTION
    WHEN OTHERS THEN
        -- Fallback to timestamp-based number
        RETURN v_prefix || '-' || v_year || v_month || '-' || TO_CHAR(EXTRACT(EPOCH FROM NOW())::INT, 'FM0000');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.generate_work_orders_from_mo(p_mo_id uuid)
 RETURNS SETOF work_orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_mo RECORD;
    v_operation RECORD;
    v_work_order_number VARCHAR;
    v_sequence INTEGER := 0;
BEGIN
    -- الحصول على معلومات أمر التصنيع
    SELECT * INTO v_mo FROM manufacturing_orders WHERE id = p_mo_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Manufacturing order not found: %', p_mo_id;
    END IF;

    -- [120] حارس عضوية على مؤسسة أمر التصنيع
    PERFORM public.wardah_assert_org_member(v_mo.org_id);

    -- إنشاء أوامر عمل لكل عملية في المسار
    FOR v_operation IN
        SELECT ro.*, wc.name as work_center_name, wc.name_ar as work_center_name_ar
        FROM routing_operations ro
        JOIN work_centers wc ON ro.work_center_id = wc.id
        WHERE ro.routing_id = v_mo.routing_id
        AND ro.is_active = true
        ORDER BY ro.operation_sequence
    LOOP
        v_sequence := v_sequence + 1;
        v_work_order_number := v_mo.order_number || '-' || LPAD(v_sequence::TEXT, 3, '0');

        RETURN QUERY
        INSERT INTO work_orders (
            org_id, mo_id, operation_id, work_center_id,
            work_order_number, operation_sequence, operation_name, operation_name_ar,
            planned_quantity, planned_setup_time, planned_run_time,
            status, created_by
        ) VALUES (
            v_mo.org_id, p_mo_id, v_operation.id, v_operation.work_center_id,
            v_work_order_number, v_operation.operation_sequence,
            v_operation.operation_name, v_operation.operation_name_ar,
            v_mo.quantity, v_operation.standard_setup_time,
            v_operation.standard_run_time_per_unit * v_mo.quantity,
            'PENDING', auth.uid()
        )
        RETURNING *;
    END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_account_details(p_org_id uuid, p_account_code character varying)
 RETURNS TABLE(account_id uuid, code character varying, name character varying, category character varying, subtype character varying, parent_code character varying, normal_balance character varying, allow_posting boolean)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        id,
        gl_accounts.code,
        gl_accounts.name,
        gl_accounts.category,
        gl_accounts.subtype,
        gl_accounts.parent_code,
        gl_accounts.normal_balance,
