$function$
;

CREATE OR REPLACE FUNCTION public.get_account_statement(p_account_code text, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(entry_date date, entry_number text, description text, debit numeric, credit numeric, running_balance numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_org_id UUID;
    v_opening_balance NUMERIC(18,4) := 0;
    v_category TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'NOT_AUTHENTICATED';
    END IF;
    v_org_id := public.wardah_org_id(NULL);
    IF v_org_id IS NULL OR NOT EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = auth.uid() AND org_id = v_org_id AND COALESCE(is_active, TRUE)
    ) THEN
        SELECT org_id INTO v_org_id
        FROM user_organizations
        WHERE user_id = auth.uid() AND COALESCE(is_active, TRUE)
        ORDER BY joined_at NULLS LAST
        LIMIT 1;
    END IF;
    PERFORM public.wardah_assert_org_member(v_org_id);

    SELECT category INTO v_category
    FROM gl_accounts
    WHERE code = p_account_code
    AND org_id = v_org_id
    LIMIT 1;

    IF v_category IS NULL THEN
        RETURN;
    END IF;

    IF p_from_date IS NOT NULL THEN
        SELECT
            CASE
                WHEN v_category IN ('ASSET', 'EXPENSE') THEN
                    COALESCE(SUM(debit_amount - credit_amount), 0)
                ELSE
                    COALESCE(SUM(credit_amount - debit_amount), 0)
            END
        INTO v_opening_balance
        FROM gl_entry_lines
        WHERE account_code = p_account_code
        AND entry_id IN (
            SELECT id FROM gl_entries
            WHERE org_id = v_org_id
            AND entry_date < p_from_date
            AND status = 'POSTED'
        );
    END IF;

    RETURN QUERY
    WITH lines_with_balance AS (
        SELECT
            ge.entry_date,
            ge.entry_number,
            COALESCE(gel.description, ge.description) as description,
            gel.debit_amount as debit,
            gel.credit_amount as credit,
            CASE
                WHEN v_category IN ('ASSET', 'EXPENSE') THEN
                    gel.debit_amount - gel.credit_amount
                ELSE
                    gel.credit_amount - gel.debit_amount
            END as balance_change
        FROM gl_entry_lines gel
        INNER JOIN gl_entries ge ON gel.entry_id = ge.id
        WHERE gel.account_code = p_account_code
        AND ge.org_id = v_org_id
        AND (p_from_date IS NULL OR ge.entry_date >= p_from_date)
        AND ge.entry_date <= p_to_date
        AND ge.status = 'POSTED'
        ORDER BY ge.entry_date, ge.entry_number, gel.line_number
    )
    SELECT
        lwb.entry_date,
        lwb.entry_number,
        lwb.description,
        lwb.debit,
        lwb.credit,
        v_opening_balance + SUM(lwb.balance_change) OVER (
            ORDER BY lwb.entry_date, lwb.entry_number
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        ) as running_balance
    FROM lines_with_balance lwb;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_account_statement_by_code(p_account_code text, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT CURRENT_DATE, p_include_unposted boolean DEFAULT false)
 RETURNS TABLE(entry_date date, entry_number text, description text, description_ar text, debit numeric, credit numeric, balance numeric, running_balance numeric, reference_type text, reference_number text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_tenant_id UUID;
    v_opening_balance NUMERIC(18,4) := 0;
    v_account_type TEXT;
    v_account_id UUID;
BEGIN
    -- Get tenant context
    v_tenant_id := current_setting('app.current_tenant_id', true)::UUID;
    
    -- Get account ID and type from gl_accounts
    SELECT id, account_type INTO v_account_id, v_account_type
    FROM gl_accounts
    WHERE code = p_account_code 
    AND org_id = v_tenant_id
    AND is_active = true
    LIMIT 1;
    
    IF v_account_id IS NULL THEN
        RAISE EXCEPTION 'Account not found: %', p_account_code;
    END IF;
    
    -- Calculate opening balance
    IF p_from_date IS NOT NULL THEN
        SELECT 
            CASE 
                WHEN v_account_type IN ('asset', 'expense', 'ASSET', 'EXPENSE') THEN
                    COALESCE(SUM(jl.debit - jl.credit), 0)
                ELSE
                    COALESCE(SUM(jl.credit - jl.debit), 0)
            END
        INTO v_opening_balance
        FROM journal_lines jl
        JOIN journal_entries je ON jl.entry_id = je.id
        WHERE jl.account_id = v_account_id
        AND jl.org_id = v_tenant_id
        AND je.org_id = v_tenant_id
        AND je.entry_date < p_from_date
        AND (p_include_unposted OR je.status = 'posted');
    END IF;
    
    -- Return statement lines
    RETURN QUERY
    SELECT 
        je.entry_date,
        je.entry_number,
        COALESCE(jl.description, je.description) as description,
        COALESCE(jl.description_ar, je.description_ar) as description_ar,
        jl.debit,
        jl.credit,
        CASE 
            WHEN v_account_type IN ('asset', 'expense', 'ASSET', 'EXPENSE') THEN
                jl.debit - jl.credit
            ELSE
                jl.credit - jl.debit
        END as balance,
        v_opening_balance + 
        SUM(CASE 
            WHEN v_account_type IN ('asset', 'expense', 'ASSET', 'EXPENSE') THEN
                jl.debit - jl.credit
            ELSE
                jl.credit - jl.debit
        END) OVER (
            ORDER BY je.entry_date, je.entry_number, jl.line_number
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        ) as running_balance,
        je.reference_type,
        je.reference_number
    FROM journal_lines jl
    JOIN journal_entries je ON jl.entry_id = je.id
    WHERE jl.account_id = v_account_id
    AND jl.org_id = v_tenant_id
    AND je.org_id = v_tenant_id
    AND (p_from_date IS NULL OR je.entry_date >= p_from_date)
    AND je.entry_date <= p_to_date
    AND (p_include_unposted OR je.status = 'posted')
    ORDER BY je.entry_date, je.entry_number, jl.line_number;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_account_tree(p_org_id uuid, p_category character varying DEFAULT NULL::character varying)
 RETURNS TABLE(account_id uuid, code character varying, name character varying, category character varying, parent_code character varying, level integer, path text)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    WITH RECURSIVE account_tree AS (
        -- المستوى الأول: الحسابات الرئيسية
        SELECT 
            gl_accounts.id,
            gl_accounts.code,
            gl_accounts.name,
            gl_accounts.category,
            gl_accounts.parent_code,
            1 as level,
            gl_accounts.code::TEXT as path
        FROM gl_accounts
        WHERE gl_accounts.org_id = p_org_id
        AND gl_accounts.parent_code IS NULL
        AND gl_accounts.is_active = true
        AND (p_category IS NULL OR gl_accounts.category = p_category)
        
        UNION ALL
        
        -- المستويات التالية
        SELECT 
            a.id,
            a.code,
            a.name,
            a.category,
            a.parent_code,
            t.level + 1,
            t.path || ' > ' || a.code
        FROM gl_accounts a
        INNER JOIN account_tree t ON a.parent_code = t.code
        WHERE a.org_id = p_org_id
        AND a.is_active = true
    )
    SELECT * FROM account_tree
    ORDER BY path;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_available_quantity(p_org_id uuid, p_item_id uuid, p_location_id uuid DEFAULT NULL::uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_on_hand DECIMAL := 0;
    v_reserved DECIMAL := 0;
BEGIN
    -- Get on-hand quantity
    SELECT COALESCE(SUM(quantity), 0) INTO v_on_hand
    FROM stock_quants
    WHERE org_id = p_org_id
    AND item_id = p_item_id
    AND (p_location_id IS NULL OR location_id = p_location_id);
    
    -- Get reserved quantity
    SELECT COALESCE(SUM(quantity_reserved - quantity_consumed - quantity_released), 0) INTO v_reserved
    FROM material_reservations
    WHERE org_id = p_org_id
    AND item_id = p_item_id
    AND status = 'reserved';
    
    RETURN GREATEST(0, v_on_hand - v_reserved);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_child_accounts(p_org_id uuid, p_parent_code character varying)
 RETURNS TABLE(account_id uuid, code character varying, name character varying, category character varying, level integer)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    WITH RECURSIVE account_tree AS (
        -- المستوى الأول: الحسابات الفرعية المباشرة
        SELECT 
            id,
            gl_accounts.code,
            gl_accounts.name,
            gl_accounts.category,
            1 as level
        FROM gl_accounts
        WHERE gl_accounts.org_id = p_org_id
        AND parent_code = p_parent_code
        AND is_active = true
        
        UNION ALL
        
        -- المستويات التالية: الحسابات الفرعية للحسابات الفرعية
        SELECT 
            a.id,
            a.code,
            a.name,
            a.category,
            t.level + 1
        FROM gl_accounts a
        INNER JOIN account_tree t ON a.parent_code = t.code
        WHERE a.org_id = p_org_id
        AND a.is_active = true
    )
    SELECT * FROM account_tree
    ORDER BY level, code;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_current_tenant_id()
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_uid uuid := auth.uid();
    v_claims jsonb;
    v_claim_org uuid;
    v_org uuid;
BEGIN
    IF v_uid IS NULL THEN RETURN NULL; END IF;
    BEGIN v_claims := current_setting('request.jwt.claims', true)::jsonb;
    EXCEPTION WHEN OTHERS THEN v_claims := NULL; END;
    IF v_claims IS NOT NULL THEN
        v_claim_org := COALESCE(
            NULLIF(v_claims ->> 'tenant_id', '')::uuid,
            NULLIF(v_claims ->> 'org_id', '')::uuid,
            NULLIF(v_claims -> 'app_metadata' ->> 'org_id', '')::uuid
        );
        IF v_claim_org IS NOT NULL AND public.wardah_is_org_member(v_claim_org) THEN
            RETURN v_claim_org;
        END IF;
    END IF;
    -- عضوية نشطة واحدة بترتيب حتمي (الأقدم) — يشمل متعدد المؤسسات (لا NULL يكسرهم)
    SELECT org_id INTO v_org
    FROM public.user_organizations
    WHERE user_id = v_uid AND COALESCE(is_active, TRUE)
    ORDER BY created_at NULLS LAST, org_id
    LIMIT 1;
    RETURN v_org;
EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_effective_org_id()
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN COALESCE(
        current_setting('app.current_org_id', true)::uuid,
        '00000000-0000-0000-0000-000000000001'::uuid
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_exchange_rate(p_from_currency text, p_to_currency text, p_rate_date date DEFAULT CURRENT_DATE)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_tenant_id UUID;
    v_rate NUMERIC(18,6);
BEGIN
    -- Get tenant context
    v_tenant_id := current_setting('app.current_tenant_id', true)::UUID;
    
    -- Same currency
    IF p_from_currency = p_to_currency THEN
        RETURN 1.0;
    END IF;
    
    -- Get direct rate
    SELECT exchange_rate INTO v_rate
    FROM currency_exchange_rates
    WHERE tenant_id = v_tenant_id
    AND from_currency = p_from_currency
    AND to_currency = p_to_currency
    AND rate_date <= p_rate_date
    AND is_active = true
    ORDER BY rate_date DESC
    LIMIT 1;
    
    -- If not found, try reverse
    IF v_rate IS NULL THEN
        SELECT 1.0 / exchange_rate INTO v_rate
        FROM currency_exchange_rates
        WHERE tenant_id = v_tenant_id
        AND from_currency = p_to_currency
        AND to_currency = p_from_currency
        AND rate_date <= p_rate_date
        AND is_active = true
        ORDER BY rate_date DESC
        LIMIT 1;
    END IF;
    
    RETURN COALESCE(v_rate, 1.0);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_fifo_rate(p_stock_queue jsonb)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_queue_array JSONB;
    v_first_batch JSONB;
BEGIN
    -- stock_queue format: [{"qty": 100, "rate": 45.5}, {"qty": 50, "rate": 50.0}, ...]
    
    IF p_stock_queue IS NULL OR jsonb_array_length(p_stock_queue) = 0 THEN
        RETURN 0;
    END IF;
    
    -- Get first element (oldest batch)
    v_first_batch := p_stock_queue->0;
    
    RETURN (v_first_batch->>'rate')::DECIMAL(15, 4);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_gl_accounts_by_category(p_org_id uuid, p_category text)
 RETURNS TABLE(id uuid, code character varying, name character varying, category character varying, subtype character varying, parent_code character varying, allow_posting boolean)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        a.id,
        a.code,
        a.name,
        a.category,
        a.subtype,
        a.parent_code,
        a.allow_posting
    FROM gl_accounts a
    WHERE a.org_id = p_org_id
    AND a.category = p_category
    AND a.is_active = true
    AND a.allow_posting = true  -- Only postable accounts
    ORDER BY a.code;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_gl_mapping(p_org_id uuid, p_event_key character varying)
 RETURNS TABLE(mapping_id uuid, debit_account character varying, credit_account character varying, description text)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        id,
        debit_account_code,
        credit_account_code,
        gl_mappings.description
    FROM gl_mappings
    WHERE gl_mappings.org_id = p_org_id
    AND key_type = 'EVENT'
    AND key_value = p_event_key
    AND is_active = true
    LIMIT 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_labor_efficiency_summary(p_org_id uuid, p_start_date date, p_end_date date, p_work_center_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(work_center_id uuid, work_center_name character varying, completed_operations integer, total_planned_time numeric, total_actual_time numeric, efficiency_pct numeric, total_produced numeric, total_scrapped numeric, scrap_rate_pct numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        wo.work_center_id,
        wc.name::VARCHAR as work_center_name,
        COUNT(*)::INTEGER as completed_operations,
        SUM(wo.planned_setup_time + wo.planned_run_time)::DECIMAL as total_planned_time,
        SUM(wo.actual_setup_time + wo.actual_run_time)::DECIMAL as total_actual_time,
        ROUND((SUM(wo.planned_setup_time + wo.planned_run_time) / 
               NULLIF(SUM(wo.actual_setup_time + wo.actual_run_time), 0) * 100)::NUMERIC, 2)::DECIMAL as efficiency_pct,
        SUM(wo.completed_quantity)::DECIMAL as total_produced,
        SUM(wo.scrapped_quantity)::DECIMAL as total_scrapped,
        ROUND((SUM(wo.scrapped_quantity) / 
               NULLIF(SUM(wo.completed_quantity + wo.scrapped_quantity), 0) * 100)::NUMERIC, 2)::DECIMAL as scrap_rate_pct
    FROM work_orders wo
    JOIN work_centers wc ON wo.work_center_id = wc.id
    WHERE wo.org_id = p_org_id
    AND wo.status = 'COMPLETED'
    AND wo.actual_end_date::DATE BETWEEN p_start_date AND p_end_date
    AND (p_work_center_id IS NULL OR wo.work_center_id = p_work_center_id)
    GROUP BY wo.work_center_id, wc.name;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_lifo_rate(p_stock_queue jsonb)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_queue_length INTEGER;
    v_last_batch JSONB;
BEGIN
    IF p_stock_queue IS NULL OR jsonb_array_length(p_stock_queue) = 0 THEN
        RETURN 0;
    END IF;
    
    -- Get last element (newest batch)
    v_queue_length := jsonb_array_length(p_stock_queue);
    v_last_batch := p_stock_queue->(v_queue_length - 1);
    
    RETURN (v_last_batch->>'rate')::DECIMAL(15, 4);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_oee_summary(p_org_id uuid, p_start_date date, p_end_date date, p_work_center_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(work_center_id uuid, work_center_name character varying, availability_pct numeric, performance_pct numeric, quality_pct numeric, oee_pct numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        v.work_center_id,
        v.work_center_name::VARCHAR,
        ROUND(AVG(v.availability_pct)::NUMERIC, 2)::DECIMAL,
        ROUND(AVG(v.performance_pct)::NUMERIC, 2)::DECIMAL,
        ROUND(AVG(v.quality_pct)::NUMERIC, 2)::DECIMAL,
        ROUND(AVG(v.oee_pct)::NUMERIC, 2)::DECIMAL
    FROM v_oee_report v
    WHERE v.org_id = p_org_id
    AND v.production_date::DATE BETWEEN p_start_date AND p_end_date
    AND (p_work_center_id IS NULL OR v.work_center_id = p_work_center_id)
    GROUP BY v.work_center_id, v.work_center_name;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_organization_profile(p_org_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_id UUID;
    v_result JSONB;
BEGIN
    v_user_id := auth.uid();
    
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'غير مصرح');
    END IF;
    
    -- ⚠️ PERFORMANCE: Use EXISTS for better performance (stops at first match)
    -- EXISTS is more efficient than COUNT(*) as it short-circuits on first row found
    IF NOT EXISTS (
        SELECT 1 FROM user_organizations 
        WHERE user_id = v_user_id 
          AND org_id = p_org_id 
          AND is_active
    ) THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'ليس لديك صلاحية للوصول لهذه المؤسسة');
    END IF;
    
    SELECT jsonb_build_object(
        'success', TRUE,
        'data', jsonb_build_object(
            'id', o.id,
            'code', o.code,
            'name', o.name,
            'name_ar', o.name_ar,
            'name_en', o.name_en,
            'tax_number', o.tax_number,
            'commercial_registration', o.commercial_registration,
            'license_number', o.license_number,
            'phone', o.phone,
            'mobile', o.mobile,
            'email', o.email,
            'website', o.website,
            'fax', o.fax,
            'address', o.address,
            'city', o.city,
            'state', o.state,
            'country', o.country,
            'postal_code', o.postal_code,
            'logo_url', o.logo_url,
            'favicon_url', o.favicon_url,
            'primary_color', o.primary_color,
            'secondary_color', o.secondary_color,
            'currency', o.currency,
            'timezone', o.timezone,
            'fiscal_year_start', o.fiscal_year_start,
            'date_format', o.date_format,
            'is_active', o.is_active,
            'created_at', o.created_at,
            'updated_at', o.updated_at
        )
    ) INTO v_result
    FROM organizations o
    WHERE o.id = p_org_id;
    
    IF v_result IS NULL THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'المؤسسة غير موجودة');
    END IF;
    
    RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_product_batches(p_product_id uuid)
 RETURNS TABLE(batch_no integer, qty numeric, rate numeric, value numeric, age_days integer)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    ROW_NUMBER() OVER ()::INT as batch_no,
    (batch->>'qty')::DECIMAL as qty,
    (batch->>'rate')::DECIMAL as rate,
    ((batch->>'qty')::DECIMAL * (batch->>'rate')::DECIMAL) as value,
    NULL::INT as age_days -- Can be enhanced with timestamp if needed
  FROM (
    SELECT jsonb_array_elements(stock_queue) as batch
    FROM products
    WHERE id = p_product_id
  ) batches;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_segment_report(p_segment_type text, p_segment_id uuid DEFAULT NULL::uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT CURRENT_DATE, p_account_type text DEFAULT NULL::text)
 RETURNS TABLE(segment_code text, segment_name text, account_code text, account_name text, total_debit numeric, total_credit numeric, balance numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_tenant_id UUID;
BEGIN
    -- Get tenant context
    v_tenant_id := current_setting('app.current_tenant_id', true)::UUID;
    
    RETURN QUERY
    SELECT 
        seg.segment_code,
        seg.segment_name,
        a.code as account_code,
        a.name as account_name,
        COALESCE(SUM(jl.debit), 0) as total_debit,
        COALESCE(SUM(jl.credit), 0) as total_credit,
        CASE 
            WHEN a.account_type IN ('asset', 'expense') THEN
                COALESCE(SUM(jl.debit - jl.credit), 0)
            ELSE
                COALESCE(SUM(jl.credit - jl.debit), 0)
        END as balance
    FROM account_segments seg
    JOIN journal_lines jl ON jl.segment_id = seg.id
    JOIN journal_entries je ON jl.entry_id = je.id
    JOIN accounts a ON jl.account_id = a.id
    WHERE seg.tenant_id = v_tenant_id
    AND seg.segment_type = p_segment_type
    AND (p_segment_id IS NULL OR seg.id = p_segment_id)
    AND (p_from_date IS NULL OR je.entry_date >= p_from_date)
    AND je.entry_date <= p_to_date
    AND je.status = 'posted'
    AND (p_account_type IS NULL OR a.account_type = p_account_type)
    GROUP BY seg.segment_code, seg.segment_name, a.code, a.name, a.account_type
    ORDER BY seg.segment_code, a.code;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_stock_aging(p_warehouse_id uuid DEFAULT NULL::uuid, p_category_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(product_id uuid, product_code character varying, product_name character varying, quantity numeric, valuation_rate numeric, stock_value numeric, first_receipt_date date, days_in_stock integer)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        p.id as product_id,
        p.code as product_code,
        p.name as product_name,
        b.actual_qty as quantity,
        b.valuation_rate,
        b.stock_value,
        (
            SELECT MIN(sle.posting_date)
            FROM stock_ledger_entries sle
            WHERE sle.product_id = p.id
              AND sle.warehouse_id = b.warehouse_id
              AND sle.actual_qty > 0
              AND sle.is_cancelled = FALSE
        ) as first_receipt_date,
        (
            CURRENT_DATE - (
                SELECT MIN(sle.posting_date)
                FROM stock_ledger_entries sle
                WHERE sle.product_id = p.id
                  AND sle.warehouse_id = b.warehouse_id
                  AND sle.actual_qty > 0
                  AND sle.is_cancelled = FALSE
            )
        )::INTEGER as days_in_stock
    FROM products p
    JOIN bins b ON b.product_id = p.id
    WHERE b.actual_qty > 0
      AND (p_warehouse_id IS NULL OR b.warehouse_id = p_warehouse_id)
      AND (p_category_id IS NULL OR p.category_id = p_category_id)
    ORDER BY days_in_stock DESC;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_stock_balance(p_product_id uuid, p_warehouse_id uuid, p_posting_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(quantity numeric, valuation_rate numeric, stock_value numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(b.actual_qty, 0) as quantity,
        COALESCE(b.valuation_rate, 0) as valuation_rate,
        COALESCE(b.stock_value, 0) as stock_value
    FROM bins b
    WHERE b.product_id = p_product_id
      AND b.warehouse_id = p_warehouse_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_stock_balance_at_date(p_product_id uuid, p_warehouse_id uuid, p_posting_date date)
 RETURNS TABLE(quantity numeric, valuation_rate numeric, stock_value numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(sle.qty_after_transaction, 0) as quantity,
        COALESCE(sle.valuation_rate, 0) as valuation_rate,
        COALESCE(sle.stock_value, 0) as stock_value
    FROM stock_ledger_entries sle
    WHERE sle.product_id = p_product_id
      AND sle.warehouse_id = p_warehouse_id
      AND sle.posting_date <= p_posting_date
      AND sle.is_cancelled = FALSE
    ORDER BY sle.posting_date DESC, sle.posting_time DESC
    LIMIT 1;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_stock_balance_with_method(p_product_id uuid, p_warehouse_id uuid, p_valuation_method text DEFAULT 'Weighted Average'::text)
 RETURNS TABLE(quantity numeric, valuation_rate numeric, stock_value numeric, stock_queue jsonb)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_bin RECORD;
    v_calculated_rate DECIMAL(15, 4);
BEGIN
    -- Get bin data
    SELECT * INTO v_bin
    FROM bins b
    WHERE b.product_id = p_product_id
      AND b.warehouse_id = p_warehouse_id;
    
    IF NOT FOUND THEN
        RETURN QUERY SELECT 
            0::DECIMAL(15, 4),
            0::DECIMAL(15, 4),
            0::DECIMAL(20, 4),
            NULL::JSONB;
        RETURN;
    END IF;
    
    -- Calculate rate based on valuation method
    v_calculated_rate := CASE 
        WHEN p_valuation_method = 'FIFO' THEN get_fifo_rate(v_bin.stock_queue)
        WHEN p_valuation_method = 'LIFO' THEN get_lifo_rate(v_bin.stock_queue)
        WHEN p_valuation_method IN ('Moving Average', 'Weighted Average') THEN v_bin.valuation_rate
        ELSE v_bin.valuation_rate
    END;
    
    RETURN QUERY SELECT 
        COALESCE(v_bin.actual_qty, 0),
        COALESCE(v_calculated_rate, 0),
        COALESCE(v_bin.actual_qty * v_calculated_rate, 0),
        v_bin.stock_queue;
END;
$function$
;

