$function$
;

CREATE OR REPLACE FUNCTION public.get_user_permissions(p_user_id uuid, p_org_id uuid)
 RETURNS TABLE(permission_key character varying, module_name character varying, resource character varying, action character varying)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    -- Super Admin: كل الصلاحيات
    IF EXISTS (
        SELECT 1 FROM super_admins 
        WHERE user_id = p_user_id AND is_active = true
    ) THEN
        RETURN QUERY
        SELECT 
            p.permission_key::VARCHAR,
            m.name::VARCHAR as module_name,
            p.resource::VARCHAR,
            p.action::VARCHAR
        FROM permissions p
        INNER JOIN modules m ON p.module_id = m.id
        WHERE m.is_active = true;
        RETURN;
    END IF;
    
    -- Org Admin: كل الصلاحيات
    IF EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = p_user_id 
        AND org_id = p_org_id
        AND is_active = true 
        AND is_org_admin = true
    ) THEN
        RETURN QUERY
        SELECT 
            p.permission_key::VARCHAR,
            m.name::VARCHAR as module_name,
            p.resource::VARCHAR,
            p.action::VARCHAR
        FROM permissions p
        INNER JOIN modules m ON p.module_id = m.id
        WHERE m.is_active = true;
        RETURN;
    END IF;
    
    -- صلاحيات عادية
    RETURN QUERY
    SELECT DISTINCT
        p.permission_key::VARCHAR,
        m.name::VARCHAR as module_name,
        p.resource::VARCHAR,
        p.action::VARCHAR
    FROM user_roles ur
    INNER JOIN role_permissions rp ON ur.role_id = rp.role_id
    INNER JOIN permissions p ON rp.permission_id = p.id
    INNER JOIN modules m ON p.module_id = m.id
    WHERE ur.user_id = p_user_id
    AND ur.org_id = p_org_id
    AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
    AND m.is_active = true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_weighted_average_from_queue(p_stock_queue jsonb)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_total_qty DECIMAL(15, 4) := 0;
    v_total_value DECIMAL(20, 4) := 0;
    v_batch JSONB;
    v_qty DECIMAL(15, 4);
    v_rate DECIMAL(15, 4);
BEGIN
    IF p_stock_queue IS NULL OR jsonb_array_length(p_stock_queue) = 0 THEN
        RETURN 0;
    END IF;
    
    -- Calculate weighted average from all batches
    FOR v_batch IN SELECT * FROM jsonb_array_elements(p_stock_queue)
    LOOP
        v_qty := (v_batch->>'qty')::DECIMAL(15, 4);
        v_rate := (v_batch->>'rate')::DECIMAL(15, 4);
        
        v_total_qty := v_total_qty + v_qty;
        v_total_value := v_total_value + (v_qty * v_rate);
    END LOOP;
    
    IF v_total_qty > 0 THEN
        RETURN v_total_value / v_total_qty;
    ELSE
        RETURN 0;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_where_used(p_item_id uuid, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(parent_bom_id uuid, parent_item_code character varying, parent_item_name character varying, quantity_per numeric, bom_status character varying, is_active boolean)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    items_table_exists BOOLEAN;
BEGIN
    -- تحديد الجدول المستخدم
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_name = 'items'
    ) INTO items_table_exists;

    IF items_table_exists THEN
        -- استخدام items
        RETURN QUERY
        SELECT 
            wu.parent_bom_id,
            COALESCE(i.code, i.item_code)::VARCHAR AS parent_item_code,
            COALESCE(i.name, i.item_name)::VARCHAR AS parent_item_name,
            wu.quantity_per,
            bh.status AS bom_status,
            bh.is_active
        FROM bom_where_used wu
        JOIN bom_headers bh ON bh.id = wu.parent_bom_id
        JOIN items i ON i.id = wu.parent_item_id
        WHERE wu.component_id = p_item_id
        AND (p_org_id IS NULL OR wu.org_id = p_org_id)
        ORDER BY COALESCE(i.code, i.item_code);
    ELSE
        -- استخدام products
        RETURN QUERY
        SELECT 
            wu.parent_bom_id,
            COALESCE(p.code, p.product_code)::VARCHAR AS parent_item_code,
            COALESCE(p.name, p.product_name)::VARCHAR AS parent_item_name,
            wu.quantity_per,
            bh.status AS bom_status,
            bh.is_active
        FROM bom_where_used wu
        JOIN bom_headers bh ON bh.id = wu.parent_bom_id
        JOIN products p ON p.id = wu.parent_item_id
        WHERE wu.component_id = p_item_id
        AND (p_org_id IS NULL OR wu.org_id = p_org_id)
        ORDER BY COALESCE(p.code, p.product_code);
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  INSERT INTO public.user_profiles (user_id, full_name, email)
  VALUES (
    NEW.id, 
    COALESCE(NEW.raw_user_meta_data ->> 'full_name', ''),
    NEW.email
  )
  ON CONFLICT (user_id) DO NOTHING;
  
  RETURN NEW;
EXCEPTION
  WHEN OTHERS THEN
    RAISE NOTICE 'Failed to create user profile: %', SQLERRM;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.has_permission(p_user_id uuid, p_org_id uuid, p_permission_key character varying)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_has_permission BOOLEAN;
BEGIN
    -- Super Admin: كل الصلاحيات
    IF EXISTS (
        SELECT 1 FROM super_admins 
        WHERE user_id = p_user_id AND is_active = true
    ) THEN
        RETURN true;
    END IF;
    
    -- Org Admin: كل صلاحيات منظمته
    IF EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = p_user_id 
        AND org_id = p_org_id
        AND is_active = true 
        AND is_org_admin = true
    ) THEN
        RETURN true;
    END IF;
    
    -- التحقق من الصلاحيات العادية
    SELECT EXISTS (
        SELECT 1
        FROM user_roles ur
        INNER JOIN role_permissions rp ON ur.role_id = rp.role_id
        INNER JOIN permissions p ON rp.permission_id = p.id
        WHERE ur.user_id = p_user_id
        AND ur.org_id = p_org_id
        AND (
            p.permission_key = p_permission_key
            OR p.permission_key LIKE REPLACE(SPLIT_PART(p_permission_key, '.', 1) || '.%', '*', '%')
        )
        AND (ur.expires_at IS NULL OR ur.expires_at > NOW())
    ) INTO v_has_permission;
    
    RETURN COALESCE(v_has_permission, false);
END;
$function$
;

