CREATE OR REPLACE FUNCTION public.log_activity()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_user_id UUID;
    v_org_id UUID;
    v_action VARCHAR(50);
    v_old_data JSONB;
    v_new_data JSONB;
    v_changes JSONB;
    v_entity_id TEXT;
BEGIN
    -- الحصول على معرف المستخدم الحالي
    v_user_id := auth.uid();
    
    -- تحديد نوع العملية والبيانات
    IF TG_OP = 'INSERT' THEN
        v_action := 'create';
        v_new_data := to_jsonb(NEW);
        v_old_data := NULL;
        v_changes := v_new_data;
        v_entity_id := NEW.id::TEXT;
        -- محاولة الحصول على org_id
        BEGIN
            v_org_id := NEW.org_id;
        EXCEPTION WHEN OTHERS THEN
            v_org_id := NULL;
        END;
    ELSIF TG_OP = 'UPDATE' THEN
        v_action := 'update';
        v_old_data := to_jsonb(OLD);
        v_new_data := to_jsonb(NEW);
        v_changes := jsonb_build_object('before', v_old_data, 'after', v_new_data);
        v_entity_id := NEW.id::TEXT;
        BEGIN
            v_org_id := NEW.org_id;
        EXCEPTION WHEN OTHERS THEN
            v_org_id := NULL;
        END;
    ELSIF TG_OP = 'DELETE' THEN
        v_action := 'delete';
        v_old_data := to_jsonb(OLD);
        v_new_data := NULL;
        v_changes := v_old_data;
        v_entity_id := OLD.id::TEXT;
        BEGIN
            v_org_id := OLD.org_id;
        EXCEPTION WHEN OTHERS THEN
            v_org_id := NULL;
        END;
    END IF;

    -- تسجيل النشاط
    BEGIN
        INSERT INTO audit_logs (
            org_id,
            user_id,
            action,
            entity_type,
            entity_id,
            old_data,
            new_data,
            changes,
            metadata,
            created_at
        ) VALUES (
            v_org_id,
            v_user_id,
            v_action,
            TG_TABLE_NAME,
            v_entity_id,
            v_old_data,
            v_new_data,
            v_changes,
            jsonb_build_object(
                'table_schema', TG_TABLE_SCHEMA,
                'trigger_name', TG_NAME,
                'triggered_at', NOW()
            ),
            NOW()
        );
    EXCEPTION WHEN OTHERS THEN
        -- تسجيل الخطأ دون إيقاف العملية
        RAISE WARNING 'Audit log failed: % - %', SQLSTATE, SQLERRM;
    END;

    -- إرجاع السجل المناسب
    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    ELSE
        RETURN NEW;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.log_custom_activity(p_org_id uuid, p_action character varying, p_entity_type character varying, p_entity_id text DEFAULT NULL::text, p_details jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_log_id UUID;
BEGIN
    INSERT INTO audit_logs (
        org_id,
        user_id,
        action,
        entity_type,
        entity_id,
        changes,
        metadata
    ) VALUES (
        p_org_id,
        auth.uid(),
        p_action,
        p_entity_type,
        p_entity_id,
        p_details,
        jsonb_build_object('timestamp', NOW(), 'source', 'manual')
    )
    RETURNING id INTO v_log_id;

    RETURN v_log_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.normalize_mo_status(p_status text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
 SET search_path TO 'public'
AS $function$
    SELECT CASE lower(trim(p_status))
        WHEN 'in-progress'     THEN 'in_progress'
        WHEN 'in_progress'     THEN 'in_progress'
        WHEN 'completed'       THEN 'done'
        WHEN 'done'            THEN 'done'
        WHEN 'on-hold'         THEN 'on_hold'
        WHEN 'on_hold'         THEN 'on_hold'
        WHEN 'quality-check'   THEN 'quality_check'
        WHEN 'quality_check'   THEN 'quality_check'
        WHEN 'draft'           THEN 'draft'
        WHEN 'confirmed'       THEN 'confirmed'
        WHEN 'pending'         THEN 'pending'
        WHEN 'cancelled'       THEN 'cancelled'
        ELSE lower(trim(p_status))
    END;
$function$
;

CREATE OR REPLACE FUNCTION public.post_journal_entry(p_entry_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_entry RECORD;
    v_total_debit NUMERIC(18,4);
    v_total_credit NUMERIC(18,4);
    v_line_count INTEGER;
    v_result JSON;
BEGIN
    -- الحصول على تفاصيل القيد
    SELECT * INTO v_entry
    FROM journal_entries 
    WHERE id = p_entry_id;
    
    IF NOT FOUND THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Journal entry not found'
        );
    END IF;
    
    -- التحقق من الحالة
    IF v_entry.status = 'posted' THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Journal entry is already posted'
        );
    END IF;
    
    IF v_entry.status = 'reversed' THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Cannot post a reversed entry'
        );
    END IF;
    
    -- التحقق من وجود بنود
    SELECT 
        COUNT(*),
        COALESCE(SUM(debit), 0),
        COALESCE(SUM(credit), 0)
    INTO v_line_count, v_total_debit, v_total_credit
    FROM journal_lines 
    WHERE entry_id = p_entry_id;
    
    IF v_line_count = 0 THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Journal entry has no lines'
        );
    END IF;
    
    -- التحقق من أن كل بند له مدين أو دائن فقط (وليس الاثنين)
    IF EXISTS (
        SELECT 1 FROM journal_lines
        WHERE entry_id = p_entry_id 
        AND (debit > 0 AND credit > 0)
    ) THEN
        RETURN json_build_object(
            'success', false,
            'error', 'كل بند يجب أن يحتوي على مدين أو دائن فقط، وليس الاثنين معاً / Each line must have either debit or credit, not both'
        );
    END IF;
    
    -- التحقق من عدم وجود بنود بدون مدين ولا دائن
    IF EXISTS (
        SELECT 1 FROM journal_lines
        WHERE entry_id = p_entry_id 
        AND debit = 0 AND credit = 0
    ) THEN
        RETURN json_build_object(
            'success', false,
            'error', 'كل بند يجب أن يحتوي على مبلغ في المدين أو الدائن / Each line must have either debit or credit amount'
        );
    END IF;
    
    -- التحقق من التوازن
    IF v_total_debit != v_total_credit OR v_total_debit = 0 THEN
        RETURN json_build_object(
            'success', false,
            'error', 'القيد غير متوازن. المدين: ' || v_total_debit || '، الدائن: ' || v_total_credit || ' / Journal entry is not balanced. Debit: ' || v_total_debit || ', Credit: ' || v_total_credit
        );
    END IF;
    
    -- التحقق من أن جميع الحسابات تقبل الترحيل
    IF EXISTS (
        SELECT 1 FROM journal_lines jl
        LEFT JOIN gl_accounts a ON jl.account_id = a.id
        WHERE jl.entry_id = p_entry_id 
        AND (a.allow_posting = false OR a.id IS NULL)
    ) THEN
        RETURN json_build_object(
            'success', false,
            'error', 'لا يمكن الترحيل على حسابات رئيسية أو حسابات غير صالحة / Cannot post to non-posting accounts or invalid accounts'
        );
    END IF;
    
    -- تحديث حالة القيد
    UPDATE journal_entries
    SET 
        status = 'posted',
        posting_date = CURRENT_DATE,
        posted_at = NOW(),
        total_debit = v_total_debit,
        total_credit = v_total_credit
    WHERE id = p_entry_id;
    
    RETURN json_build_object(
        'success', true,
        'message', 'تم ترحيل القيد بنجاح / Journal entry posted successfully',
        'entry_id', p_entry_id,
        'total_debit', v_total_debit,
        'total_credit', v_total_credit
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.protect_posted_gl_entries()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    IF TG_OP = 'DELETE' THEN
        IF OLD.status IN ('posted', 'reversed') THEN
            RAISE EXCEPTION 'POSTED_ENTRY_IMMUTABLE: لا يمكن حذف قيد مرحّل (%) — استخدم العكس', OLD.entry_number;
        END IF;
        RETURN OLD;
    END IF;

    -- UPDATE
    IF OLD.status IN ('posted', 'reversed') THEN
        -- الحقول المالية الجوهرية لا تتغير بعد الترحيل
        IF NEW.entry_date    IS DISTINCT FROM OLD.entry_date
           OR NEW.total_debit  IS DISTINCT FROM OLD.total_debit
           OR NEW.total_credit IS DISTINCT FROM OLD.total_credit
           OR NEW.journal_id   IS DISTINCT FROM OLD.journal_id THEN
            RAISE EXCEPTION 'POSTED_ENTRY_IMMUTABLE: لا يمكن تعديل الحقول المالية لقيد مرحّل (%) — استخدم العكس', OLD.entry_number;
        END IF;
        -- الرجوع من posted إلى draft ممنوع
        IF OLD.status = 'posted' AND NEW.status = 'draft' THEN
            RAISE EXCEPTION 'POSTED_ENTRY_IMMUTABLE: لا يمكن إرجاع قيد مرحّل إلى مسودة (%)', OLD.entry_number;
        END IF;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.protect_posted_gl_entry_lines()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
    v_status TEXT;
    v_entry UUID := COALESCE(NEW.entry_id, OLD.entry_id);
BEGIN
    SELECT status INTO v_status FROM gl_entries WHERE id = v_entry;
    IF v_status IN ('posted', 'reversed') THEN
        RAISE EXCEPTION 'POSTED_ENTRY_IMMUTABLE: لا يمكن تعديل/حذف سطور قيد مرحّل — استخدم العكس';
    END IF;
    RETURN COALESCE(NEW, OLD);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reconcile_account(p_account_id uuid, p_reconciliation_date date, p_statement_items jsonb DEFAULT NULL::jsonb)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_tenant_id UUID;
    v_reconciliation_id UUID;
    v_opening_balance NUMERIC(18,4);
    v_closing_balance NUMERIC(18,4);
    v_unreconciled_amount NUMERIC(18,4);
    v_item JSONB;
    v_result JSON;
BEGIN
    -- Get tenant context
    v_tenant_id := current_setting('app.current_tenant_id', true)::UUID;
    
    -- Get account balance
    SELECT get_account_balance(p_account_id, p_reconciliation_date, false)
    INTO v_closing_balance;
    
    -- Calculate opening balance
    SELECT get_account_balance(p_account_id, p_reconciliation_date - INTERVAL '1 day', false)
    INTO v_opening_balance;
    
    -- Create reconciliation record
    v_reconciliation_id := gen_random_uuid();
    
    INSERT INTO account_reconciliations (
        id, account_id, reconciliation_date,
        opening_balance, closing_balance,
        reconciled_amount, unreconciled_amount,
        status, tenant_id
    ) VALUES (
        v_reconciliation_id,
        p_account_id,
        p_reconciliation_date,
        v_opening_balance,
        v_closing_balance,
        v_closing_balance - v_opening_balance,
        0,
        'open',
        v_tenant_id
    );
    
    -- Add statement items if provided
    IF p_statement_items IS NOT NULL THEN
        FOR v_item IN SELECT * FROM jsonb_array_elements(p_statement_items)
        LOOP
            INSERT INTO reconciliation_items (
                reconciliation_id,
                statement_date,
                statement_amount,
                statement_reference,
                tenant_id
            ) VALUES (
                v_reconciliation_id,
                (v_item->>'date')::DATE,
                (v_item->>'amount')::NUMERIC(18,4),
                v_item->>'reference',
                v_tenant_id
            );
        END LOOP;
    END IF;
    
    RETURN json_build_object(
        'success', true,
        'reconciliation_id', v_reconciliation_id,
        'opening_balance', v_opening_balance,
        'closing_balance', v_closing_balance,
        'movement', v_closing_balance - v_opening_balance
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.release_expired_reservations(p_org_id uuid DEFAULT NULL::uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_count INTEGER;
BEGIN
    UPDATE material_reservations
    SET status = 'expired',
        released_at = NOW(),
        quantity_released = quantity_reserved - quantity_consumed,
        updated_at = NOW()
    WHERE status = 'reserved'
    AND expires_at IS NOT NULL
    AND expires_at < NOW()
    AND (p_org_id IS NULL OR org_id = p_org_id);
    
    GET DIAGNOSTICS v_count = ROW_COUNT;
    
    RETURN v_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.release_manufacturing_order(p_mo_id uuid)
 RETURNS manufacturing_orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_mo manufacturing_orders;
    v_org UUID;
BEGIN
    -- [120] حارس عضوية على مؤسسة أمر التصنيع
    SELECT org_id INTO v_org FROM manufacturing_orders WHERE id = p_mo_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Manufacturing order not found or invalid status';
    END IF;
    PERFORM public.wardah_assert_org_member(v_org);

    -- تحديث حالة أمر التصنيع لـ RELEASED
    UPDATE manufacturing_orders SET
        status = 'RELEASED',
        start_date = COALESCE(start_date, CURRENT_DATE),
        updated_at = NOW()
    WHERE id = p_mo_id
    AND status IN ('PENDING', 'PLANNED')
    RETURNING * INTO v_mo;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Manufacturing order not found or invalid status';
    END IF;

    RETURN v_mo;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.reverse_journal_entry_enhanced(p_entry_id uuid, p_reversal_reason text DEFAULT NULL::text, p_reversal_date date DEFAULT CURRENT_DATE)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_original_entry RECORD;
    v_reversal_entry_id UUID;
    v_reversal_number TEXT;
    v_line RECORD;
    v_tenant_id UUID;
    v_result JSON;
BEGIN
    -- Get original entry
    SELECT * INTO v_original_entry
    FROM journal_entries
    WHERE id = p_entry_id;

    IF NOT FOUND THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Original entry not found'
        );
    END IF;

    -- [120] tenant من صف القيد + بوابة admin (بدل app.current_tenant_id الميت)
    v_tenant_id := v_original_entry.tenant_id;
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'ORG_UNRESOLVED';
    END IF;
    PERFORM public.wardah_assert_org_admin(v_tenant_id);

    IF v_original_entry.status != 'posted' THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Can only reverse posted entries'
        );
    END IF;

    IF v_original_entry.reversed_by_entry_id IS NOT NULL THEN
        RETURN json_build_object(
            'success', false,
            'error', 'Entry already reversed'
        );
    END IF;

    -- Generate reversal entry
    v_reversal_entry_id := gen_random_uuid();
    v_reversal_number := generate_entry_number_enhanced(v_original_entry.journal_id, p_reversal_date);

    -- Create reversal entry ([120] المستخدم من auth.uid() بدل app.current_user_id الميت)
    INSERT INTO journal_entries (
        id, journal_id, entry_number, entry_date, posting_date,
        reference_type, reference_id, reference_number,
        description, description_ar,
        status, posted_at, posted_by,
        total_debit, total_credit,
        reversed_by_entry_id, reversal_reason,
        tenant_id, created_by, updated_by
    ) VALUES (
        v_reversal_entry_id,
        v_original_entry.journal_id,
        v_reversal_number,
        p_reversal_date,
        p_reversal_date,
        'reversal',
        p_entry_id,
        'REV-' || v_original_entry.entry_number,
        COALESCE('Reversal: ' || v_original_entry.description, 'Reversal Entry'),
        COALESCE('عكس: ' || v_original_entry.description_ar, 'عكس قيد'),
        'posted',
        CURRENT_TIMESTAMP,
        auth.uid(),
        v_original_entry.total_credit, -- Swap totals
        v_original_entry.total_debit,  -- Swap totals
        NULL,
        p_reversal_reason,
        v_tenant_id,
        auth.uid(),
        auth.uid()
    );

    -- Create reversal lines (swap debit/credit)
    FOR v_line IN
        SELECT * FROM journal_lines
        WHERE entry_id = p_entry_id
        ORDER BY line_number
    LOOP
        INSERT INTO journal_lines (
            entry_id, line_number, account_id,
            cost_center_id, partner_id, product_id, project_id,
            debit, credit, currency_code,
            description, description_ar,
            tenant_id
        ) VALUES (
            v_reversal_entry_id,
            v_line.line_number,
            v_line.account_id,
            v_line.cost_center_id,
            v_line.partner_id,
            v_line.product_id,
            v_line.project_id,
            v_line.credit, -- Swap
            v_line.debit,  -- Swap
            v_line.currency_code,
            'REV: ' || COALESCE(v_line.description, ''),
            'عكس: ' || COALESCE(v_line.description_ar, ''),
            v_tenant_id
        );
    END LOOP;

    -- Update original entry
    UPDATE journal_entries SET
        status = 'reversed',
        reversed_by_entry_id = v_reversal_entry_id,
        reversal_reason = p_reversal_reason,
        updated_at = CURRENT_TIMESTAMP
    WHERE id = p_entry_id;

    RETURN json_build_object(
        'success', true,
        'message', 'Entry reversed successfully',
        'original_entry_id', p_entry_id,
        'reversal_entry_id', v_reversal_entry_id,
        'reversal_number', v_reversal_number
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_accept_invitation(p_token text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_caller_id    UUID := auth.uid();
    v_caller_email TEXT;
    v_inv          invitations%ROWTYPE;
    v_hash         TEXT;
BEGIN
    IF v_caller_id IS NULL THEN RETURN jsonb_build_object('ok', false, 'error', 'NOT_AUTHENTICATED'); END IF;
    SELECT email INTO v_caller_email FROM auth.users WHERE id = v_caller_id;
    v_hash := encode(sha256(p_token::bytea), 'hex');
    SELECT * INTO v_inv FROM invitations WHERE token_hash = v_hash FOR UPDATE;
    IF NOT FOUND THEN RETURN jsonb_build_object('ok', false, 'error', 'INVITATION_NOT_FOUND'); END IF;
    IF v_inv.status != 'pending' THEN RETURN jsonb_build_object('ok', false, 'error', 'INVITATION_ALREADY_USED'); END IF;
    IF v_inv.expires_at < NOW() THEN
        UPDATE invitations SET status = 'expired' WHERE id = v_inv.id;
        RETURN jsonb_build_object('ok', false, 'error', 'INVITATION_EXPIRED');
    END IF;
    IF lower(v_caller_email) != lower(v_inv.email) THEN RETURN jsonb_build_object('ok', false, 'error', 'EMAIL_MISMATCH'); END IF;
    INSERT INTO user_organizations (user_id, org_id, is_active, is_org_admin, joined_at, invited_by)
    VALUES (v_caller_id, v_inv.org_id, true, false, NOW(), v_inv.invited_by)
    ON CONFLICT (user_id, org_id) DO NOTHING;
    IF v_inv.role_ids IS NOT NULL AND array_length(v_inv.role_ids, 1) > 0 THEN
        INSERT INTO user_roles (user_id, role_id, org_id)
        SELECT v_caller_id, role_id, v_inv.org_id FROM unnest(v_inv.role_ids) AS role_id
        ON CONFLICT DO NOTHING;
    END IF;
    UPDATE invitations SET status = 'accepted', accepted_at = NOW() WHERE id = v_inv.id;
    RETURN jsonb_build_object('ok', true, 'org_id', v_inv.org_id);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_complete_manufacturing_order(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org        UUID;
    v_uid        UUID;
    v_mo_id      UUID;
    v_mo         RECORD;
    v_prod       RECORD;
    v_done_qty   NUMERIC;
    v_wip_cost   NUMERIC;
    v_unit_cost  NUMERIC;
    v_new_qty    NUMERIC;
    v_new_rate   NUMERIC;
    v_allow_zero BOOLEAN;
    v_warnings   JSONB := '[]'::JSONB;
BEGIN
    v_org := wardah_org_id(NULLIF(p_payload->>'tenant_id', '')::UUID);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED: تعذر تحديد هوية المؤسسة';
    END IF;
    v_uid := auth.uid();
    IF v_uid IS NULL OR NOT EXISTS (
        SELECT 1 FROM user_organizations WHERE user_id = v_uid AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'FORBIDDEN_ORG: المستخدم ليس عضواً في المؤسسة المطلوبة';
    END IF;

    v_mo_id := (p_payload->>'mo_id')::UUID;
    IF v_mo_id IS NULL THEN
        RAISE EXCEPTION 'INVALID_PAYLOAD: mo_id مطلوب';
    END IF;

    SELECT id, status, quantity, completed_quantity, product_id, total_cost
    INTO v_mo
    FROM manufacturing_orders
    WHERE id = v_mo_id AND org_id = v_org
    FOR UPDATE;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'MO_NOT_FOUND: أمر التصنيع غير موجود ضمن مؤسستك';
    END IF;

    IF normalize_mo_status(v_mo.status) = 'done' THEN
        RETURN jsonb_build_object(
            'success', TRUE, 'mo_id', v_mo_id, 'already_done', TRUE,
            'completed_quantity', v_mo.completed_quantity,
            'total_cost', ROUND(COALESCE(v_mo.total_cost, 0), 6)
        );
    END IF;

    IF v_mo.product_id IS NULL THEN
        RAISE EXCEPTION 'MO_NO_PRODUCT: أمر التصنيع بلا منتج تام محدَّد';
    END IF;

    v_done_qty := COALESCE((p_payload->>'completed_quantity')::NUMERIC, v_mo.quantity);
    IF v_done_qty IS NULL OR v_done_qty <= 0 THEN
        RAISE EXCEPTION 'INVALID_QUANTITY: الكمية المنجزة يجب أن تكون موجبة';
    END IF;

    SELECT COALESCE(SUM(COALESCE(total_cost, consumed_quantity * COALESCE(unit_cost, 0))), 0)
    INTO v_wip_cost
    FROM material_consumption
    WHERE mo_id = v_mo_id AND org_id = v_org;

    -- allow_zero_cost: راية حسّاسة تُحترم فقط لمدير المؤسسة (كنمط allow_over_delivery/91)
    v_allow_zero := COALESCE(p_payload->>'allow_zero_cost', 'false') = 'true';
    IF v_allow_zero AND NOT EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = v_uid AND org_id = v_org
          AND (COALESCE(is_org_admin, FALSE) OR role IN ('admin', 'owner'))
    ) THEN
        v_allow_zero := FALSE;  -- غير مدير ⇒ لا يُصرَّح بالتكلفة الصفرية
    END IF;

    IF v_wip_cost <= 0 AND NOT v_allow_zero THEN
        RAISE EXCEPTION 'ZERO_COST_COMPLETION: لا تكلفة مواد مسجَّلة لأمر التصنيع — '
          'الإتمام بتكلفة صفرية مرفوض (يلوّث متوسط تكلفة المنتج). سجّل استهلاك المواد '
          'أولاً، أو مرّر allow_zero_cost=true بصلاحية مدير للإتمام المصرَّح.';
    END IF;

    v_unit_cost := CASE WHEN v_done_qty > 0 THEN v_wip_cost / v_done_qty ELSE 0 END;

    SELECT id, COALESCE(stock_quantity, 0) AS qty, COALESCE(cost_price, 0) AS cost
    INTO v_prod
    FROM products WHERE id = v_mo.product_id AND org_id = v_org
    FOR UPDATE;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'ITEM_NOT_FOUND: منتج أمر التصنيع غير موجود ضمن مؤسستك';
    END IF;

    v_new_qty := v_prod.qty + v_done_qty;
    v_new_rate := CASE WHEN v_new_qty > 0
        THEN (v_prod.qty * v_prod.cost + v_wip_cost) / v_new_qty
        ELSE v_unit_cost END;

    UPDATE products
    SET stock_quantity = v_new_qty, cost_price = v_new_rate, updated_at = NOW()
    WHERE id = v_mo.product_id;

    IF to_regclass('public.stock_moves') IS NOT NULL THEN
        INSERT INTO stock_moves (
            org_id, product_id, quantity, move_type, unit_cost_in,
            reference_type, reference_id, reference_number, status, date_done
        ) VALUES (
            v_org, v_mo.product_id, v_done_qty, 'production_receipt', v_unit_cost,
            'MANUFACTURING_ORDER', v_mo_id, NULL, 'done', NOW()
        );
    END IF;

    UPDATE manufacturing_orders
    SET status = 'done', completed_quantity = v_done_qty,
        total_cost = v_wip_cost, unit_cost = v_unit_cost
    WHERE id = v_mo_id;

    IF v_wip_cost > 0 THEN
        PERFORM rpc_post_event_journal(
            'MATERIAL_ISSUE', v_wip_cost, 'صرف مواد لأمر تصنيع - ' || v_mo_id::TEXT,
            'MANUFACTURING_ORDER', v_mo_id, v_org, 'MATERIAL_ISSUE:' || v_mo_id::TEXT, NULL
        );
        PERFORM rpc_post_event_journal(
            'FG_RECEIPT', v_wip_cost, 'إنتاج تام لأمر تصنيع - ' || v_mo_id::TEXT,
            'MANUFACTURING_ORDER', v_mo_id, v_org, 'FG_RECEIPT:' || v_mo_id::TEXT, NULL
        );
    ELSE
        v_warnings := v_warnings || to_jsonb(
            'إتمام بتكلفة صفرية (مصرَّح allow_zero_cost بصلاحية مدير): لا استهلاك مواد، لا قيد.'::TEXT
        );
    END IF;

    RETURN jsonb_build_object(
        'success', TRUE, 'mo_id', v_mo_id,
        'completed_quantity', v_done_qty,
        'total_cost', ROUND(v_wip_cost, 6),
        'unit_cost', ROUND(v_unit_cost, 6),
        'fg_new_stock', v_new_qty,
        'warnings', v_warnings
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_cost_of_production_report(p_mo_id uuid, p_stage_no integer DEFAULT NULL::integer, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org        UUID;
    v_mo         RECORD;
    v_stage      RECORD;
    v_stages     JSONB := '[]'::JSONB;
    v_stage_rpt  JSONB;

    -- أعمدة ديناميكية (org_id/tenant_id على غرار Migrations 67-69)
    v_tenant_col TEXT;
    v_mo_col     TEXT;
    v_stage_col  TEXT;
    v_sql        TEXT;

    -- الخطوة 1: جدول الكميات
    v_units_in           NUMERIC;  -- الوحدات الواجب حسابها
    v_units_out          NUMERIC;  -- الوحدات المحسوبة
    v_qty_balanced       BOOLEAN;

    -- الخطوة 2: EUP
    v_eup_dm             NUMERIC;
    v_eup_cc             NUMERIC;

    -- الخطوة 3: التكاليف الواجب حسابها
    v_cc_cost            NUMERIC;  -- تكاليف التحويل = عمالة + أوفرهيد
    v_costs_in           NUMERIC;

    -- الخطوة 4: تكلفة الوحدة المكافئة
    v_ti_per_eu          NUMERIC := 0;
    v_dm_per_eu          NUMERIC := 0;
    v_cc_per_eu          NUMERIC := 0;
    v_unit_cost_total    NUMERIC := 0;
    v_ti_eup_base        NUMERIC;

    -- الخطوة 5: توزيع التكاليف
    v_cost_completed     NUMERIC;
    v_cost_ending_wip    NUMERIC;
    v_cost_abnormal      NUMERIC;
    v_costs_out          NUMERIC;
    v_reconcile_diff     NUMERIC;
    v_is_balanced        BOOLEAN;

    -- إجماليات على مستوى الأمر كاملاً
    v_grand_costs_in     NUMERIC := 0;
    v_grand_completed    NUMERIC := 0;
    v_grand_ending_wip   NUMERIC := 0;
    v_grand_abnormal     NUMERIC := 0;
    v_all_balanced       BOOLEAN := TRUE;
BEGIN
    -- ===== هوية المؤسسة =====
    v_org := wardah_org_id(p_tenant);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED: تعذر تحديد هوية المؤسسة';
    END IF;

    -- ===== كشف أسماء الأعمدة (نفس نمط Migrations 67-69) =====
    SELECT column_name INTO v_tenant_col
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'stage_costs'
      AND column_name IN ('tenant_id', 'org_id')
    ORDER BY CASE column_name WHEN 'tenant_id' THEN 1 ELSE 2 END
    LIMIT 1;

    SELECT column_name INTO v_mo_col
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'stage_costs'
      AND column_name IN ('mo_id', 'manufacturing_order_id')
    ORDER BY CASE column_name WHEN 'mo_id' THEN 1 ELSE 2 END
    LIMIT 1;

    SELECT column_name INTO v_stage_col
    FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'stage_costs'
      AND column_name IN ('stage_no', 'stage_number')
    ORDER BY CASE column_name WHEN 'stage_no' THEN 1 ELSE 2 END
    LIMIT 1;

    IF v_tenant_col IS NULL OR v_mo_col IS NULL OR v_stage_col IS NULL THEN
        RAISE EXCEPTION 'SCHEMA_MISMATCH: جدول stage_costs لا يحتوي الأعمدة المتوقعة';
    END IF;

    -- ===== رأس التقرير: بيانات أمر التصنيع =====
    SELECT * INTO v_mo
    FROM manufacturing_orders
    WHERE id = p_mo_id AND org_id = v_org;

    IF v_mo IS NULL THEN
        RAISE EXCEPTION 'MO_NOT_FOUND: أمر التصنيع غير موجود أو لا يتبع مؤسستك';
    END IF;

    -- ===== المرور على المراحل =====
    v_sql := format(
        'SELECT *,
                %I  AS k_stage_no
         FROM stage_costs
         WHERE %I = $1 AND %I = $2
           AND ($3::INTEGER IS NULL OR %I = $3)
         ORDER BY %I',
        v_stage_col, v_tenant_col, v_mo_col, v_stage_col, v_stage_col
    );

    FOR v_stage IN EXECUTE v_sql USING v_org, p_mo_id, p_stage_no
    LOOP
        -- ============================================================
        -- الخطوة 1: جدول الكميات
        -- الوحدات الواجب حسابها = WIP أول المدة + وحدات بدأت
        -- الوحدات المحسوبة = مكتمل + WIP آخر المدة + تالف طبيعي + تالف غير طبيعي
        -- ============================================================
        v_units_in  := COALESCE(v_stage.wip_beginning_qty, 0)
                     + COALESCE(v_stage.input_qty, 0);
        v_units_out := COALESCE(v_stage.good_qty, 0)
                     + COALESCE(v_stage.wip_end_qty, 0)
                     + COALESCE(v_stage.normal_scrap_qty, 0)
                     + COALESCE(v_stage.abnormal_scrap_qty, 0)
                     + COALESCE(v_stage.rework_qty, 0);
        v_qty_balanced := ABS(v_units_in - v_units_out) < 0.000001;

        -- ============================================================
        -- الخطوة 2: EUP — نفس معادلات upsert_stage_cost حرفياً
        -- ============================================================
        IF COALESCE(v_stage.costing_method, 'weighted_average') = 'fifo' THEN
            IF v_stage.k_stage_no = 1 THEN
                v_eup_dm := COALESCE(v_stage.good_qty, 0)
                          + COALESCE(v_stage.wip_end_qty, 0) * COALESCE(v_stage.wip_end_dm_completion_pct, 0) / 100
                          - COALESCE(v_stage.wip_beginning_qty, 0) * COALESCE(v_stage.wip_beginning_dm_completion_pct, 0) / 100;
            ELSE
                v_eup_dm := COALESCE(v_stage.good_qty, 0);
            END IF;
            v_eup_cc := COALESCE(v_stage.good_qty, 0)
                      + COALESCE(v_stage.wip_end_qty, 0) * COALESCE(v_stage.wip_end_cc_completion_pct, 0) / 100
                      - COALESCE(v_stage.wip_beginning_qty, 0) * COALESCE(v_stage.wip_beginning_cc_completion_pct, 0) / 100;
        ELSE
            -- المتوسط المرجّح
            IF v_stage.k_stage_no = 1 THEN
                v_eup_dm := COALESCE(v_stage.good_qty, 0)
                          + COALESCE(v_stage.wip_end_qty, 0) * COALESCE(v_stage.wip_end_dm_completion_pct, 0) / 100;
            ELSE
                v_eup_dm := COALESCE(v_stage.good_qty, 0);
            END IF;
            v_eup_cc := COALESCE(v_stage.good_qty, 0)
                      + COALESCE(v_stage.wip_end_qty, 0) * COALESCE(v_stage.wip_end_cc_completion_pct, 0) / 100;
        END IF;

        -- ============================================================
        -- الخطوة 3: التكاليف الواجب حسابها
        -- WIP أول + محوَّل وارد + مواد + تحويل (عمالة+أوفرهيد) + إعادة طحن − رصيد خردة
        -- ============================================================
        v_cc_cost  := COALESCE(v_stage.dl_cost, 0) + COALESCE(v_stage.moh_cost, 0);
        v_costs_in := COALESCE(v_stage.wip_beginning_cost, 0)
                    + COALESCE(v_stage.transferred_in, 0)
                    + COALESCE(v_stage.dm_cost, 0)
                    + v_cc_cost
                    + COALESCE(v_stage.regrind_proc_cost, 0)
                    - COALESCE(v_stage.waste_credit, 0);

        -- ============================================================
        -- الخطوة 4: تكلفة الوحدة المكافئة لكل عنصر
        -- المحوَّل الوارد مكتمل 100% دائماً ⇒ قاعدته = مكتمل + WIP نهائي كامل
        -- ============================================================
        v_ti_eup_base := COALESCE(v_stage.good_qty, 0) + COALESCE(v_stage.wip_end_qty, 0);

        v_ti_per_eu := CASE WHEN v_ti_eup_base > 0
                            THEN COALESCE(v_stage.transferred_in, 0) / v_ti_eup_base
                            ELSE 0 END;
        v_dm_per_eu := CASE WHEN v_eup_dm > 0
                            THEN COALESCE(v_stage.dm_cost, 0) / v_eup_dm
                            ELSE 0 END;
        -- تكاليف التحويل تشمل تسويات إعادة الطحن ورصيد الخردة (نفس منطق 69)
        v_cc_per_eu := CASE WHEN v_eup_cc > 0
                            THEN (v_cc_cost
                                  + COALESCE(v_stage.regrind_proc_cost, 0)
                                  - COALESCE(v_stage.waste_credit, 0)
                                  + COALESCE(v_stage.wip_beginning_cost, 0)) / v_eup_cc
                            ELSE 0 END;
        v_unit_cost_total := v_ti_per_eu + v_dm_per_eu + v_cc_per_eu;

        -- ============================================================
        -- الخطوة 5: توزيع التكاليف
        -- مكتمل ومحوَّل = بالباقي (يمتص التالف الطبيعي تلقائياً — لا تسريب)
        -- WIP نهائي = كمية × (TI كامل + DM بنسبته + CC بنسبته)
        -- تالف غير طبيعي = القيمة المخزنة (احتُسبت وقت الترحيل — خسارة فترة)
        -- ============================================================
        v_cost_ending_wip := COALESCE(v_stage.wip_end_qty, 0) * (
                                 v_ti_per_eu
                               + v_dm_per_eu * COALESCE(v_stage.wip_end_dm_completion_pct, 0) / 100
                               + v_cc_per_eu * COALESCE(v_stage.wip_end_cc_completion_pct, 0) / 100
                             );
        v_cost_abnormal   := COALESCE(v_stage.abnormal_scrap_cost, 0);
        v_cost_completed  := v_costs_in - v_cost_ending_wip - v_cost_abnormal;

        v_costs_out      := v_cost_completed + v_cost_ending_wip + v_cost_abnormal;
        v_reconcile_diff := v_costs_in - v_costs_out;
        v_is_balanced    := ABS(v_reconcile_diff) < 0.01;

        v_all_balanced     := v_all_balanced AND v_is_balanced AND v_qty_balanced;
        v_grand_costs_in   := v_grand_costs_in   + v_costs_in;
        v_grand_completed  := v_grand_completed  + v_cost_completed;
        v_grand_ending_wip := v_grand_ending_wip + v_cost_ending_wip;
        v_grand_abnormal   := v_grand_abnormal   + v_cost_abnormal;

        -- ===== بناء JSON المرحلة =====
        v_stage_rpt := jsonb_build_object(
            'stage_no',       v_stage.k_stage_no,
            'work_center_id', v_stage.wc_id,
            'costing_method', COALESCE(v_stage.costing_method, 'weighted_average'),
            'mode',           v_stage.mode,

            'quantity_schedule', jsonb_build_object(
                'wip_beginning_qty',   COALESCE(v_stage.wip_beginning_qty, 0),
                'units_started',       COALESCE(v_stage.input_qty, 0),
                'units_to_account',    v_units_in,
                'units_completed',     COALESCE(v_stage.good_qty, 0),
                'wip_ending_qty',      COALESCE(v_stage.wip_end_qty, 0),
                'normal_scrap_qty',    COALESCE(v_stage.normal_scrap_qty, 0),
                'abnormal_scrap_qty',  COALESCE(v_stage.abnormal_scrap_qty, 0),
                'rework_qty',          COALESCE(v_stage.rework_qty, 0),
                'units_accounted',     v_units_out,
                'qty_difference',      v_units_in - v_units_out,
                'is_balanced',         v_qty_balanced
            ),

            'equivalent_units', jsonb_build_object(
                'eup_dm',                       ROUND(v_eup_dm, 6),
                'eup_cc',                       ROUND(v_eup_cc, 6),
                'wip_end_dm_completion_pct',    COALESCE(v_stage.wip_end_dm_completion_pct, 0),
                'wip_end_cc_completion_pct',    COALESCE(v_stage.wip_end_cc_completion_pct, 0),
                'wip_beg_dm_completion_pct',    COALESCE(v_stage.wip_beginning_dm_completion_pct, 0),
                'wip_beg_cc_completion_pct',    COALESCE(v_stage.wip_beginning_cc_completion_pct, 0)
            ),

            'costs_to_account', jsonb_build_object(
                'wip_beginning_cost', COALESCE(v_stage.wip_beginning_cost, 0),
                'transferred_in',     COALESCE(v_stage.transferred_in, 0),
                'direct_materials',   COALESCE(v_stage.dm_cost, 0),
                'direct_labor',       COALESCE(v_stage.dl_cost, 0),
                'overhead_applied',   COALESCE(v_stage.moh_cost, 0),
                'conversion_costs',   v_cc_cost,
                'regrind_cost',       COALESCE(v_stage.regrind_proc_cost, 0),
                'waste_credit',       COALESCE(v_stage.waste_credit, 0),
                'total_costs_in',     ROUND(v_costs_in, 6)
            ),

            'cost_per_eu', jsonb_build_object(
                'transferred_in_per_eu', ROUND(v_ti_per_eu, 6),
                'dm_per_eu',             ROUND(v_dm_per_eu, 6),
                'cc_per_eu',             ROUND(v_cc_per_eu, 6),
                'total_per_eu',          ROUND(v_unit_cost_total, 6),
                'stored_unit_cost',      COALESCE(v_stage.unit_cost, 0)
            ),

            'cost_assignment', jsonb_build_object(
                'completed_and_transferred', ROUND(v_cost_completed, 6),
                'ending_wip',                ROUND(v_cost_ending_wip, 6),
                'abnormal_scrap_loss',       ROUND(v_cost_abnormal, 6),
                'normal_scrap_absorbed',     COALESCE(v_stage.normal_scrap_cost, 0),
                'total_costs_out',           ROUND(v_costs_out, 6)
            ),

            'reconciliation', jsonb_build_object(
                'costs_in',          ROUND(v_costs_in, 6),
                'costs_out',         ROUND(v_costs_out, 6),
                'difference',        ROUND(v_reconcile_diff, 6),
                'is_balanced',       v_is_balanced,
                'stored_total_cost', COALESCE(v_stage.total_cost, 0),
                'stored_vs_computed_diff', ROUND(COALESCE(v_stage.total_cost, 0) - v_cost_completed, 6)
            )
        );

        v_stages := v_stages || v_stage_rpt;
    END LOOP;

    IF jsonb_array_length(v_stages) = 0 THEN
        RAISE EXCEPTION 'NO_STAGE_DATA: لا توجد بيانات مراحل لهذا الأمر%',
            CASE WHEN p_stage_no IS NOT NULL
                 THEN format(' (المرحلة %s)', p_stage_no) ELSE '' END;
    END IF;

    -- ===== التقرير الكامل =====
    RETURN jsonb_build_object(
        'success', TRUE,
        'report_type', 'cost_of_production',
        'generated_at', now(),
        'manufacturing_order', jsonb_build_object(
            'id',             v_mo.id,
            'order_number',   v_mo.order_number,
            'product_id',     v_mo.product_id,
            'status',         v_mo.status,
            'qty_planned',    v_mo.qty_planned
        ),
        'stages', v_stages,
        'totals', jsonb_build_object(
            'total_costs_in',            ROUND(v_grand_costs_in, 6),
            'total_completed',           ROUND(v_grand_completed, 6),
            'total_ending_wip',          ROUND(v_grand_ending_wip, 6),
            'total_abnormal_scrap_loss', ROUND(v_grand_abnormal, 6),
            'all_stages_balanced',       v_all_balanced
        )
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_create_journal_entry(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID;
    v_journal_id UUID;
    v_entry_id UUID;
    v_entry_number TEXT;
    v_entry_date DATE;
    v_total_debit NUMERIC := 0;
    v_total_credit NUMERIC := 0;
    v_line_count INTEGER := 0;
    v_idem TEXT;
    v_auto_post BOOLEAN := COALESCE((p_payload ->> 'auto_post')::boolean, false);
BEGIN
    -- 3.1 الهوية
    v_org := wardah_org_id(NULLIF(p_payload ->> 'org_id', '')::uuid);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;

    -- 3.2 التاريخ والفترة
    v_entry_date := COALESCE(NULLIF(p_payload ->> 'entry_date', '')::date, CURRENT_DATE);
    PERFORM assert_period_open(v_org, v_entry_date);

    -- 3.3 Idempotency: نفس المفتاح ⇒ نفس القيد (بدون تكرار)
    v_idem := NULLIF(p_payload ->> 'idempotency_key', '');
    IF v_idem IS NOT NULL THEN
        SELECT id, entry_number INTO v_entry_id, v_entry_number
        FROM gl_entries
        WHERE org_id = v_org AND idempotency_key = v_idem
        LIMIT 1;
        IF v_entry_id IS NOT NULL THEN
            RETURN jsonb_build_object(
                'success', true, 'entry_id', v_entry_id,
                'entry_number', v_entry_number, 'duplicate', true
            );
        END IF;
    END IF;

    -- 3.4 التوازن — يُحسب في الخادم من السطور نفسها، لا يُستلم من العميل
    SELECT COALESCE(SUM(COALESCE((l ->> 'debit')::numeric, 0)), 0),
           COALESCE(SUM(COALESCE((l ->> 'credit')::numeric, 0)), 0),
           COUNT(*)
    INTO v_total_debit, v_total_credit, v_line_count
    FROM jsonb_array_elements(p_payload -> 'lines') l;

    IF v_line_count < 2 THEN
        RAISE EXCEPTION 'EMPTY_ENTRY: القيد يحتاج سطرين على الأقل';
    END IF;
    IF round(v_total_debit, 2) <> round(v_total_credit, 2) THEN
        RAISE EXCEPTION 'UNBALANCED_ENTRY: مدين=% دائن=%', v_total_debit, v_total_credit;
    END IF;
    IF round(v_total_debit, 2) = 0 THEN
        RAISE EXCEPTION 'ZERO_ENTRY: قيمة القيد صفر';
    END IF;

    -- 3.5 دفتر اليومية (نفس منطق journal-service الحالي: الافتراضي أول دفتر نشط)
    v_journal_id := NULLIF(p_payload ->> 'journal_id', '')::uuid;
    IF v_journal_id IS NULL AND to_regclass('public.journals') IS NOT NULL THEN
        SELECT id INTO v_journal_id
        FROM journals
        WHERE org_id = v_org AND is_active = true
        ORDER BY created_at ASC
        LIMIT 1;
    END IF;

    -- 3.6 رقم القيد — نعيد استخدام الدالة الحية التي تستدعيها الواجهة اليوم
    BEGIN
        v_entry_number := generate_entry_number(v_journal_id);
    EXCEPTION WHEN OTHERS THEN
        -- توقيع بديل موجود في بعض البيئات: (org_id, date)
        BEGIN
            v_entry_number := generate_entry_number(v_org, v_entry_date);
        EXCEPTION WHEN OTHERS THEN
            v_entry_number := 'JE-' || to_char(v_entry_date, 'YYYY') || '-' ||
                              lpad(floor(random() * 1000000)::text, 6, '0');
        END;
    END;

    -- 3.7 الرأس والسطور — داخل نفس المعاملة (الدالة كلها معاملة واحدة)
    INSERT INTO gl_entries (
        org_id, journal_id, entry_number, entry_date, entry_type,
        description, description_ar, reference_type, reference_number,
        status, total_debit, total_credit, idempotency_key
    ) VALUES (
        v_org, v_journal_id, v_entry_number, v_entry_date, 'manual',
        NULLIF(p_payload ->> 'description', ''),
        NULLIF(p_payload ->> 'description_ar', ''),
        NULLIF(p_payload ->> 'reference_type', ''),
        NULLIF(p_payload ->> 'reference_number', ''),
        'draft', v_total_debit, v_total_credit, v_idem
    )
    RETURNING id INTO v_entry_id;

    INSERT INTO gl_entry_lines (
        org_id, tenant_id, entry_id, line_number, account_id,
        debit, credit, currency_code, description, description_ar
    )
    SELECT
        v_org, v_org, v_entry_id,
        COALESCE((l.value ->> 'line_number')::int, l.ord::int),
        (l.value ->> 'account_id')::uuid,
        COALESCE((l.value ->> 'debit')::numeric, 0),
        COALESCE((l.value ->> 'credit')::numeric, 0),
        COALESCE(NULLIF(l.value ->> 'currency_code', ''), 'SAR'),
        NULLIF(l.value ->> 'description', ''),
        NULLIF(l.value ->> 'description_ar', '')
    FROM jsonb_array_elements(p_payload -> 'lines') WITH ORDINALITY AS l(value, ord);

    -- 3.8 ترحيل فوري اختياري (للقيود الآلية من الأحداث التشغيلية)
    IF v_auto_post THEN
        UPDATE gl_entries
        SET status = 'posted', posted_at = NOW()
        WHERE id = v_entry_id;
    END IF;

    RETURN jsonb_build_object(
        'success', true,
        'entry_id', v_entry_id,
        'entry_number', v_entry_number,
        'total_debit', v_total_debit,
        'total_credit', v_total_credit,
        'status', CASE WHEN v_auto_post THEN 'posted' ELSE 'draft' END
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_create_mo_with_reservation(p_order jsonb, p_materials jsonb DEFAULT '[]'::jsonb, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID; v_mo_id UUID; v_mo_number TEXT; v_mat JSONB; v_item_id UUID;
    v_qty NUMERIC; v_avail NUMERIC; v_insufficient JSONB := '[]'::jsonb;
    v_reserved INT := 0; v_init_status TEXT;
BEGIN
    v_org := wardah_org_id(COALESCE(NULLIF(p_order->>'org_id','')::UUID, p_tenant));
    PERFORM public.wardah_assert_org_member(v_org);

    IF jsonb_array_length(p_materials) > 0 THEN
        FOR v_mat IN SELECT * FROM jsonb_array_elements(p_materials) LOOP
            v_item_id := (v_mat->>'item_id')::UUID;
            v_qty := (v_mat->>'quantity')::NUMERIC;
            SELECT COALESCE(SUM(CASE move_type WHEN 'receipt' THEN quantity WHEN 'material_issue' THEN -quantity ELSE 0 END), 0) -
                   COALESCE((SELECT SUM(quantity_reserved - COALESCE(quantity_consumed,0) - COALESCE(quantity_released,0))
                             FROM material_reservations WHERE item_id = v_item_id AND org_id = v_org AND status = 'reserved'), 0)
            INTO v_avail FROM stock_moves WHERE product_id = v_item_id AND org_id = v_org AND status = 'done';
            IF v_avail < v_qty THEN
                v_insufficient := v_insufficient || jsonb_build_object('item_id', v_item_id, 'required', v_qty, 'available', v_avail);
            END IF;
        END LOOP;
        IF jsonb_array_length(v_insufficient) > 0 THEN
            RAISE EXCEPTION 'INSUFFICIENT_STOCK: مواد غير كافية: %', v_insufficient::TEXT;
        END IF;
    END IF;

    v_init_status := normalize_mo_status(COALESCE(p_order->>'status', 'draft'));
    v_mo_number := COALESCE(NULLIF(p_order->>'order_number',''),
        'MO-' || to_char(NOW(), 'YYYYMMDD') || '-' || lpad(nextval('mo_seq')::TEXT, 4, '0'));

    INSERT INTO manufacturing_orders (
        org_id, order_number, product_id, item_id, quantity,
        status, notes, start_date, due_date
    ) VALUES (
        v_org, v_mo_number,
        NULLIF(p_order->>'product_id','')::UUID,
        NULLIF(p_order->>'item_id','')::UUID,
        COALESCE(NULLIF(p_order->>'quantity','')::NUMERIC, 0),
        v_init_status,
        NULLIF(p_order->>'notes',''),
        NULLIF(p_order->>'start_date','')::DATE,
        NULLIF(p_order->>'due_date','')::DATE
    ) RETURNING id INTO v_mo_id;

    FOR v_mat IN SELECT * FROM jsonb_array_elements(p_materials) LOOP
        INSERT INTO material_reservations (org_id, mo_id, item_id, quantity_reserved, status, expires_at)
        VALUES (v_org, v_mo_id, (v_mat->>'item_id')::UUID, (v_mat->>'quantity')::NUMERIC, 'reserved', (v_mat->>'expires_at')::TIMESTAMPTZ);
        v_reserved := v_reserved + 1;
    END LOOP;

    RETURN jsonb_build_object('success', true, 'mo_id', v_mo_id, 'mo_number', v_mo_number,
        'status', v_init_status, 'materials_reserved', v_reserved);
EXCEPTION WHEN OTHERS THEN RAISE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_generate_fiscal_periods(p_year integer, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org     UUID := wardah_org_id(p_tenant);
    v_col     TEXT := wardah_periods_org_col();
    v_month   INTEGER;
    v_start   DATE;
    v_end     DATE;
    v_code    TEXT;
    v_created INTEGER := 0;
    v_rows    INTEGER;
BEGIN
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;
    IF v_col IS NULL THEN
        RAISE EXCEPTION 'PERIODS_TABLE_MISSING: جدول accounting_periods غير موجود أو بنيته غير معروفة';
    END IF;
    IF p_year IS NULL OR p_year < 2000 OR p_year > 2100 THEN
        RAISE EXCEPTION 'INVALID_YEAR: السنة المالية غير صالحة (%)', p_year;
    END IF;

    FOR v_month IN 1..12 LOOP
        v_start := make_date(p_year, v_month, 1);
        v_end   := (v_start + INTERVAL '1 month' - INTERVAL '1 day')::date;
        v_code  := to_char(v_start, 'YYYY-MM');

        EXECUTE format(
            'INSERT INTO accounting_periods
                (%I, period_code, period_name, period_type,
                 start_date, end_date, fiscal_year, status)
             VALUES ($1, $2, $3, ''month'', $4, $5, $6, ''open'')
             ON CONFLICT DO NOTHING',
            v_col
        )
        USING v_org, v_code,
              'الفترة ' || v_code, v_start, v_end, p_year;

        GET DIAGNOSTICS v_rows = ROW_COUNT;
        v_created := v_created + v_rows;
    END LOOP;

    RETURN jsonb_build_object(
        'success', true,
        'fiscal_year', p_year,
        'periods_created', v_created,
        'periods_existing', 12 - v_created
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_get_invitation_preview(p_token text)
 RETURNS TABLE(email text, org_name text, org_name_ar text, status text, expires_at timestamp with time zone, is_valid boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_hash TEXT;
BEGIN
    v_hash := encode(sha256(p_token::bytea), 'hex');
    RETURN QUERY
    SELECT inv.email::TEXT, org.name::TEXT, org.name_ar::TEXT,
           inv.status::TEXT, inv.expires_at,
           (inv.status = 'pending' AND inv.expires_at > NOW()) AS is_valid
    FROM invitations inv
    JOIN organizations org ON org.id = inv.org_id
    WHERE inv.token_hash = v_hash;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_get_trial_balance(p_tenant uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(account_code text, account_name text, account_name_ar text, account_type text, opening_debit numeric, opening_credit numeric, period_debit numeric, period_credit numeric, closing_debit numeric, closing_credit numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_org UUID;
BEGIN
    -- [120] حارس: p_tenant يجب أن يكون مؤسسة المستدعي؛ NULL ⇒ اشتقاق من العضوية
    v_org := p_tenant;
    IF v_org IS NULL AND auth.uid() IS NOT NULL THEN
        SELECT org_id INTO v_org
        FROM user_organizations
        WHERE user_id = auth.uid() AND COALESCE(is_active, TRUE)
        ORDER BY joined_at NULLS LAST
        LIMIT 1;
    END IF;
    PERFORM public.wardah_assert_org_member(v_org);

    RETURN QUERY
    WITH account_movements AS (
        SELECT
            ga.id as account_id,
            ga.code,
            ga.name,
            ga.name_en,
            ga.category,
            COALESCE(SUM(CASE WHEN je.status = 'posted' THEN jl.debit ELSE 0 END), 0) as total_debit,
            COALESCE(SUM(CASE WHEN je.status = 'posted' THEN jl.credit ELSE 0 END), 0) as total_credit
        FROM gl_accounts ga
        LEFT JOIN journal_lines jl ON ga.id = jl.account_id
        LEFT JOIN journal_entries je ON jl.entry_id = je.id
            AND je.status = 'posted'
            AND COALESCE(je.posting_date, je.entry_date) <= p_as_of_date
        WHERE ga.allow_posting = true
            AND ga.is_active = true
            AND (ga.org_id = v_org OR ga.org_id IS NULL)
        GROUP BY ga.id, ga.code, ga.name, ga.name_en, ga.category
    )
    SELECT
        am.code::TEXT,
        am.name::TEXT,
        COALESCE(am.name_en, am.name)::TEXT as account_name_ar,
        am.category::TEXT as account_type,
        0::NUMERIC(18,4) as opening_debit,
        0::NUMERIC(18,4) as opening_credit,
        am.total_debit::NUMERIC(18,4) as period_debit,
        am.total_credit::NUMERIC(18,4) as period_credit,
        CASE
            WHEN am.total_debit > am.total_credit
            THEN (am.total_debit - am.total_credit)::NUMERIC(18,4)
            ELSE 0::NUMERIC(18,4)
        END as closing_debit,
        CASE
            WHEN am.total_credit > am.total_debit
            THEN (am.total_credit - am.total_debit)::NUMERIC(18,4)
            ELSE 0::NUMERIC(18,4)
        END as closing_credit
    FROM account_movements am
    WHERE am.total_debit > 0 OR am.total_credit > 0
    ORDER BY am.code;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_list_periods(p_fiscal_year integer DEFAULT NULL::integer, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID := wardah_org_id(p_tenant);
    v_col TEXT := wardah_periods_org_col();
    v_out JSONB;
BEGIN
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;
    IF v_col IS NULL THEN
        RETURN '[]'::jsonb;
    END IF;

    EXECUTE format(
        'SELECT COALESCE(jsonb_agg(to_jsonb(t) ORDER BY t.start_date), ''[]''::jsonb)
         FROM (
            SELECT id, period_code, period_name, period_type,
                   start_date, end_date, fiscal_year, status
            FROM accounting_periods
            WHERE %I = $1 AND ($2 IS NULL OR fiscal_year = $2)
         ) t',
        v_col
    )
    INTO v_out
    USING v_org, p_fiscal_year;

    RETURN v_out;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_post_delivery_note(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org         UUID;
    v_uid         UUID;
    v_dn_id       UUID;
    v_dn_number   TEXT;
    v_invoice_id  UUID;
    v_inv_customer UUID;
    v_payload_customer UUID;
    v_idem_key    TEXT;
    v_existing_id UUID;
    v_existing_no TEXT;
    v_allow_over  BOOLEAN;
    v_line        JSONB;
    v_item        RECORD;
    v_inv_line    RECORD;
    v_qty         NUMERIC;
    v_unit_cost   NUMERIC;
    v_total_cogs  NUMERIC := 0;
    v_line_no     INTEGER := 0;
    v_warnings    JSONB := '[]'::JSONB;
BEGIN
    v_org := wardah_org_id(NULLIF(p_payload->>'tenant_id', '')::UUID);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED: تعذر تحديد هوية المؤسسة';
    END IF;
    v_uid := auth.uid();
    IF v_uid IS NULL OR NOT EXISTS (
        SELECT 1 FROM user_organizations WHERE user_id = v_uid AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'FORBIDDEN_ORG: المستخدم ليس عضواً في المؤسسة المطلوبة';
    END IF;

    v_invoice_id := (p_payload->>'sales_invoice_id')::UUID;
    IF v_invoice_id IS NULL THEN
        RAISE EXCEPTION 'INVALID_PAYLOAD: sales_invoice_id مطلوب';
    END IF;
    IF jsonb_array_length(COALESCE(p_payload->'lines', '[]'::JSONB)) = 0 THEN
        RAISE EXCEPTION 'INVALID_PAYLOAD: لا سطور في إذن التسليم';
    END IF;

    -- التسليم الزائد: تُحترم الراية فقط لمدير المؤسسة
    v_allow_over := COALESCE((p_payload->>'allow_over_delivery')::BOOLEAN, FALSE);
    IF v_allow_over AND NOT EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = v_uid AND org_id = v_org
          AND (COALESCE(is_org_admin, FALSE) OR role IN ('admin', 'owner'))
    ) THEN
        v_allow_over := FALSE;  -- غير مدير ⇒ يُمنع التجاوز
    END IF;

    -- ===== قفل استشاري ثم فحص idempotency = لا سباق =====
    PERFORM pg_advisory_xact_lock(hashtext('delivery_notes:' || v_org::TEXT));

    v_idem_key := NULLIF(p_payload->>'idempotency_key', '');
    IF v_idem_key IS NOT NULL THEN
        SELECT id, delivery_number INTO v_existing_id, v_existing_no
        FROM delivery_notes WHERE org_id = v_org AND idempotency_key = v_idem_key;
        IF v_existing_id IS NOT NULL THEN
            SELECT COALESCE(SUM(quantity_delivered * unit_cost_at_delivery), 0)
            INTO v_total_cogs FROM delivery_note_lines WHERE delivery_note_id = v_existing_id;
            RETURN jsonb_build_object(
                'success', TRUE, 'delivery_id', v_existing_id,
                'delivery_number', v_existing_no, 'total_cogs', ROUND(v_total_cogs, 6),
                'idempotent_replay', TRUE, 'warnings', '[]'::JSONB
            );
        END IF;
    END IF;

    -- الفاتورة تخص المؤسسة
    SELECT customer_id INTO v_inv_customer
    FROM sales_invoices WHERE id = v_invoice_id AND org_id = v_org;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'INVOICE_NOT_FOUND: الفاتورة % ليست ضمن مؤسستك', v_invoice_id;
    END IF;
    v_payload_customer := NULLIF(p_payload->>'customer_id', '')::UUID;
    IF v_payload_customer IS NOT NULL AND v_payload_customer <> v_inv_customer THEN
        RAISE EXCEPTION 'CUSTOMER_MISMATCH: العميل لا يطابق عميل الفاتورة';
    END IF;

    BEGIN
        PERFORM assert_period_open(v_org, COALESCE((p_payload->>'delivery_date')::DATE, CURRENT_DATE));
    EXCEPTION WHEN undefined_function THEN NULL;
    END;

    SELECT 'DN-' || LPAD((
        COALESCE(MAX(NULLIF(regexp_replace(delivery_number, '\D', '', 'g'), ''))::BIGINT, 0) + 1
    )::TEXT, 6, '0')
    INTO v_dn_number
    FROM delivery_notes WHERE org_id = v_org AND delivery_number ~ '^DN-\d+$';
    v_dn_number := COALESCE(v_dn_number, 'DN-000001');

    INSERT INTO delivery_notes (
        org_id, delivery_number, sales_invoice_id, customer_id,
        delivery_date, vehicle_number, driver_name, status, notes, idempotency_key
    ) VALUES (
        v_org, v_dn_number, v_invoice_id, v_inv_customer,
        COALESCE((p_payload->>'delivery_date')::DATE, CURRENT_DATE),
        NULLIF(p_payload->>'vehicle_number', ''), NULLIF(p_payload->>'driver_name', ''),
        'delivered', NULLIF(p_payload->>'notes', ''), v_idem_key
    )
    RETURNING id INTO v_dn_id;

    FOR v_line IN SELECT * FROM jsonb_array_elements(p_payload->'lines')
    LOOP
        v_line_no := v_line_no + 1;
        v_qty := (v_line->>'delivered_quantity')::NUMERIC;
        IF v_qty IS NULL OR v_qty <= 0 THEN
            RAISE EXCEPTION 'INVALID_LINE: كمية غير صالحة في السطر %', v_line_no;
        END IF;

        IF NULLIF(v_line->>'sales_invoice_line_id', '') IS NULL THEN
            RAISE EXCEPTION 'LINE_REQUIRED: sales_invoice_line_id مطلوب لكل سطر (السطر %)', v_line_no;
        END IF;

        SELECT id, product_id, quantity, unit_price, COALESCE(delivered_quantity, 0) AS delivered
        INTO v_inv_line
        FROM sales_invoice_lines
        WHERE id = (v_line->>'sales_invoice_line_id')::UUID
          AND invoice_id = v_invoice_id AND org_id = v_org
        FOR UPDATE;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'INVALID_LINE: سطر الفاتورة غير موجود ضمن هذه الفاتورة (السطر %)', v_line_no;
        END IF;
        IF (v_line->>'item_id')::UUID <> v_inv_line.product_id THEN
            RAISE EXCEPTION 'PRODUCT_MISMATCH: المنتج لا يطابق منتج سطر الفاتورة (السطر %)', v_line_no;
        END IF;
        IF NOT v_allow_over AND (v_inv_line.delivered + v_qty) > v_inv_line.quantity THEN
            RAISE EXCEPTION 'OVER_DELIVERY: الكمية % تتجاوز المتبقّي % في السطر %',
                v_qty, (v_inv_line.quantity - v_inv_line.delivered), v_line_no;
        END IF;

        SELECT id, stock_quantity, cost_price, name, name_ar
        INTO v_item
        FROM products WHERE id = v_inv_line.product_id AND org_id = v_org
        FOR UPDATE;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'ITEM_NOT_FOUND: المنتج غير موجود ضمن مؤسستك (السطر %)', v_line_no;
        END IF;
        IF COALESCE(v_item.stock_quantity, 0) < v_qty THEN
            RAISE EXCEPTION 'INSUFFICIENT_STOCK: % — المتاح: %، المطلوب: %',
                COALESCE(v_item.name_ar, v_item.name), COALESCE(v_item.stock_quantity, 0), v_qty;
        END IF;

        v_unit_cost := COALESCE(v_item.cost_price, 0);
        v_total_cogs := v_total_cogs + (v_qty * v_unit_cost);

        INSERT INTO delivery_note_lines (
            org_id, delivery_note_id, sales_invoice_line_id, product_id,
            invoiced_quantity, delivered_quantity, quantity_delivered,
            unit_price, unit_cost_at_delivery, notes
        ) VALUES (
            v_org, v_dn_id, v_inv_line.id, v_item.id,
            v_inv_line.quantity, v_qty, v_qty,
            COALESCE(v_inv_line.unit_price, 0), v_unit_cost, NULLIF(v_line->>'notes', '')
        );

        UPDATE products SET stock_quantity = stock_quantity - v_qty, updated_at = NOW()
        WHERE id = v_item.id;

        IF to_regclass('public.stock_moves') IS NOT NULL THEN
            INSERT INTO stock_moves (
                org_id, product_id, quantity, move_type, unit_cost_out,
                reference_type, reference_id, reference_number, status, date_done
            ) VALUES (
                v_org, v_item.id, -v_qty, 'sales_delivery', v_unit_cost,
                'DELIVERY_NOTE', v_dn_id, v_dn_number, 'done', NOW()
            );
        END IF;

        UPDATE sales_invoice_lines
        SET delivered_quantity = v_inv_line.delivered + v_qty, unit_cost_at_sale = v_unit_cost
        WHERE id = v_inv_line.id;
    END LOOP;

    IF v_total_cogs > 0 THEN
        PERFORM rpc_post_event_journal(
            'COGS_DELIVERY', v_total_cogs, 'تكلفة بضاعة مباعة - ' || v_dn_number,
            'DELIVERY_NOTE', v_dn_id, v_org, 'COGS_DELIVERY:' || v_dn_id::TEXT, NULL
        );
    END IF;

    UPDATE sales_invoices si
    SET delivery_status = CASE
        WHEN NOT EXISTS (
            SELECT 1 FROM sales_invoice_lines l
            WHERE l.invoice_id = si.id AND COALESCE(l.delivered_quantity, 0) < l.quantity
        ) THEN 'fully_delivered' ELSE 'partially_delivered'
    END
    WHERE si.id = v_invoice_id;

    RETURN jsonb_build_object(
        'success', TRUE, 'delivery_id', v_dn_id, 'delivery_number', v_dn_number,
        'total_cogs', ROUND(v_total_cogs, 6), 'lines_processed', v_line_no, 'warnings', v_warnings
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_post_event_journal(p_event text, p_amount numeric, p_memo text, p_ref_type text, p_ref_id uuid DEFAULT NULL::uuid, p_tenant uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_jv_date date DEFAULT NULL::date)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID := wardah_org_id(p_tenant);
    v_map RECORD;
    v_debit_id UUID;
    v_credit_id UUID;
    v_result JSONB;
BEGIN
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;
    IF p_amount IS NULL OR p_amount <= 0 THEN
        RAISE EXCEPTION 'INVALID_AMOUNT: مبلغ الحدث يجب أن يكون موجباً (المستلم: %)', p_amount;
    END IF;

    -- الخريطة — خطأ واضح بدل حسابات افتراضية صامتة
    SELECT * INTO v_map
    FROM gl_event_mappings
    WHERE org_id = v_org AND event_code = upper(p_event)
      AND work_center_code IS NULL AND is_active = true
    LIMIT 1;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'MAPPING_MISSING: لا توجد خريطة حسابات للحدث "%" — أضفها عبر rpc_upsert_event_mapping', p_event;
    END IF;

    -- تحويل أكواد الحسابات إلى معرفات
    SELECT id INTO v_debit_id FROM gl_accounts WHERE org_id = v_org AND code = v_map.debit_account_code;
    SELECT id INTO v_credit_id FROM gl_accounts WHERE org_id = v_org AND code = v_map.credit_account_code;
    IF v_debit_id IS NULL OR v_credit_id IS NULL THEN
        RAISE EXCEPTION 'ACCOUNT_NOT_FOUND: أحد حسابي الخريطة (% / %) غير موجود',
            v_map.debit_account_code, v_map.credit_account_code;
    END IF;

    v_result := rpc_create_journal_entry(jsonb_build_object(
        'org_id', v_org,
        'entry_date', COALESCE(p_jv_date, CURRENT_DATE),
        'description', p_memo,
        'reference_type', p_ref_type,
        'reference_number', p_ref_id::text,
        'idempotency_key', p_idempotency_key,
        'auto_post', false,  -- يبقى Draft للمراجعة — يُفعَّل الترحيل الفوري لاحقاً بقرار
        'lines', jsonb_build_array(
            jsonb_build_object('line_number', 1, 'account_id', v_debit_id,
                               'debit', p_amount, 'credit', 0, 'description', p_memo),
            jsonb_build_object('line_number', 2, 'account_id', v_credit_id,
                               'debit', 0, 'credit', p_amount, 'description', p_memo)
        )
    ));

    RETURN (v_result ->> 'entry_id')::uuid;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_post_goods_receipt(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org        UUID;
    v_uid        UUID;
    v_gr_id      UUID;
    v_gr_number  TEXT;
    v_po_id      UUID;
    v_po_status  TEXT;
    v_po_vendor  UUID;
    v_vendor_id  UUID;
    v_wh_id      UUID;
    v_idem_key   TEXT;
    v_req_hash   TEXT;
    v_existing_id UUID;
    v_existing_no TEXT;
    v_existing_hash TEXT;
    v_line       JSONB;
    v_line_no    INTEGER := 0;
    v_prod       UUID;
    v_recv       NUMERIC;
    v_cost       NUMERIC;
    v_quality    TEXT;
    v_total      NUMERIC := 0;
    v_pol        RECORD;
    v_pol_id     UUID;
    v_recv_date  DATE;
BEGIN
    v_org := wardah_org_id(NULLIF(p_payload->>'tenant_id', '')::UUID);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED: تعذر تحديد هوية المؤسسة';
    END IF;
    v_uid := auth.uid();
    IF v_uid IS NULL OR NOT EXISTS (
        SELECT 1 FROM user_organizations WHERE user_id = v_uid AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'FORBIDDEN_ORG: المستخدم ليس عضواً في المؤسسة المطلوبة';
    END IF;

    v_vendor_id := (p_payload->>'vendor_id')::UUID;
    IF v_vendor_id IS NULL THEN
        RAISE EXCEPTION 'INVALID_PAYLOAD: vendor_id مطلوب';
    END IF;
    IF NOT EXISTS (SELECT 1 FROM vendors WHERE id = v_vendor_id AND org_id = v_org) THEN
        RAISE EXCEPTION 'VENDOR_NOT_FOUND: المورد ليس ضمن مؤسستك';
    END IF;
    IF jsonb_array_length(COALESCE(p_payload->'lines', '[]'::JSONB)) = 0 THEN
        RAISE EXCEPTION 'INVALID_PAYLOAD: لا سطور في سند الاستلام';
    END IF;

    v_wh_id := NULLIF(p_payload->>'warehouse_id', '')::UUID;
    IF v_wh_id IS NOT NULL AND NOT EXISTS (
        SELECT 1 FROM warehouses WHERE id = v_wh_id AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'WAREHOUSE_NOT_FOUND: المخزن ليس ضمن مؤسستك';
    END IF;

    v_po_id := NULLIF(p_payload->>'purchase_order_id', '')::UUID;
    IF v_po_id IS NOT NULL THEN
        SELECT status, vendor_id INTO v_po_status, v_po_vendor
        FROM purchase_orders WHERE id = v_po_id AND org_id = v_org
        FOR UPDATE;
        IF NOT FOUND THEN
            RAISE EXCEPTION 'PO_NOT_FOUND: أمر الشراء ليس ضمن مؤسستك';
        END IF;
        IF v_po_status NOT IN ('approved', 'submitted', 'partially_received') THEN
            RAISE EXCEPTION 'PO_NOT_RECEIVABLE: حالة أمر الشراء (%) لا تسمح بالاستلام', v_po_status;
        END IF;
        IF v_po_vendor IS NOT NULL AND v_po_vendor <> v_vendor_id THEN
            RAISE EXCEPTION 'VENDOR_MISMATCH: المورد لا يطابق مورد أمر الشراء';
        END IF;
    END IF;

    v_recv_date := COALESCE((p_payload->>'receipt_date')::DATE, CURRENT_DATE);

    BEGIN
        PERFORM assert_period_open(v_org, v_recv_date);
    EXCEPTION WHEN undefined_function THEN NULL;
    END;

    PERFORM pg_advisory_xact_lock(hashtext('goods_receipts:' || v_org::TEXT));

    -- بصمة الحمولة (بلا مفتاح idempotency) لكشف إعادة استخدام المفتاح بحمولة مختلفة
    v_req_hash := md5((p_payload - 'idempotency_key')::TEXT);

    v_idem_key := NULLIF(p_payload->>'idempotency_key', '');
    IF v_idem_key IS NOT NULL THEN
        SELECT id, receipt_number, request_hash
        INTO v_existing_id, v_existing_no, v_existing_hash
        FROM goods_receipts WHERE org_id = v_org AND idempotency_key = v_idem_key;
        IF v_existing_id IS NOT NULL THEN
            -- نُعيد السند القديم فقط إن تأكّد تطابق الحمولة (نفس request_hash).
            -- request_hash فارغ (سند أقدم من هذه المهاجرة أو نافذة نشر) ⇒ لا يمكن
            -- تأكيد التطابق ⇒ Fail-closed برفض بدل إعادة سند قد يكون لحمولة مختلفة.
            IF v_existing_hash IS NULL OR v_existing_hash <> v_req_hash THEN
                RAISE EXCEPTION 'IDEMPOTENCY_KEY_REUSED: تعذّر تأكيد تطابق الحمولة لهذا المفتاح (حمولة مختلفة أو سند قديم بلا بصمة) — استخدم مفتاحاً جديداً للعملية';
            END IF;
            RETURN jsonb_build_object(
                'success', TRUE, 'goods_receipt_id', v_existing_id,
                'receipt_number', v_existing_no, 'idempotent_replay', TRUE,
                'inventory_atomic', TRUE
            );
        END IF;
    END IF;

    SELECT 'GR-' || LPAD((
        COALESCE(MAX(NULLIF(regexp_replace(receipt_number, '\D', '', 'g'), ''))::BIGINT, 0) + 1
    )::TEXT, 6, '0')
    INTO v_gr_number
    FROM goods_receipts
    WHERE org_id = v_org AND receipt_number ~ '^GR-\d+$';
    v_gr_number := COALESCE(v_gr_number, 'GR-000001');

    INSERT INTO goods_receipts (
        org_id, receipt_number, purchase_order_id, vendor_id, receipt_date,
        warehouse_id, warehouse_location, receiver_name, status, notes,
        idempotency_key, request_hash, created_by
    ) VALUES (
        v_org, v_gr_number, v_po_id, v_vendor_id, v_recv_date,
        v_wh_id, NULLIF(p_payload->>'warehouse_location', ''),
        NULLIF(p_payload->>'receiver_name', ''), 'confirmed',
        NULLIF(p_payload->>'notes', ''), v_idem_key, v_req_hash, v_uid
    )
    RETURNING id INTO v_gr_id;

    FOR v_line IN SELECT * FROM jsonb_array_elements(p_payload->'lines')
    LOOP
        v_line_no := v_line_no + 1;
        v_prod := (v_line->>'product_id')::UUID;
        v_recv := COALESCE((v_line->>'received_quantity')::NUMERIC, 0);
        v_cost := COALESCE((v_line->>'unit_cost')::NUMERIC, 0);
        v_quality := COALESCE(NULLIF(v_line->>'quality_status', ''), 'accepted');

        IF v_recv < 0 OR v_cost < 0 THEN
            RAISE EXCEPTION 'INVALID_LINE: كمية/تكلفة سالبة (السطر %)', v_line_no;
        END IF;
        IF NOT EXISTS (SELECT 1 FROM products WHERE id = v_prod AND org_id = v_org) THEN
            RAISE EXCEPTION 'ITEM_NOT_FOUND: المنتج غير موجود ضمن مؤسستك (السطر %)', v_line_no;
        END IF;

        IF v_quality = 'accepted' AND v_recv > 0 AND v_wh_id IS NULL THEN
            RAISE EXCEPTION 'WAREHOUSE_REQUIRED: السطر % مقبول بكمية موجبة ويتطلب warehouse_id لتسجيل حركة المخزون', v_line_no;
        END IF;

        v_pol_id := NULLIF(v_line->>'purchase_order_line_id', '')::UUID;
        IF v_pol_id IS NOT NULL THEN
            IF v_po_id IS NULL THEN
                RAISE EXCEPTION 'PO_REQUIRED: السطر % يحمل purchase_order_line_id بلا purchase_order_id للسند', v_line_no;
            END IF;
            SELECT purchase_order_id, product_id, quantity, COALESCE(received_quantity, 0) AS received
            INTO v_pol
            FROM purchase_order_lines WHERE id = v_pol_id AND org_id = v_org
            FOR UPDATE;
            IF NOT FOUND THEN
                RAISE EXCEPTION 'INVALID_PO_LINE: سطر أمر الشراء غير موجود (السطر %)', v_line_no;
            END IF;
            IF v_pol.purchase_order_id <> v_po_id THEN
                RAISE EXCEPTION 'INVALID_PO_LINE: السطر لا يتبع أمر الشراء المحدد (السطر %)', v_line_no;
            END IF;
            IF v_pol.product_id <> v_prod THEN
                RAISE EXCEPTION 'PRODUCT_MISMATCH: منتج السطر لا يطابق سطر أمر الشراء (السطر %)', v_line_no;
            END IF;
            IF (v_pol.received + v_recv) > v_pol.quantity THEN
                RAISE EXCEPTION 'OVER_RECEIPT: الكمية % تتجاوز المتبقّي % في السطر %',
                    v_recv, (v_pol.quantity - v_pol.received), v_line_no;
            END IF;

            UPDATE purchase_order_lines
            SET received_quantity = v_pol.received + v_recv
            WHERE id = v_pol_id;
        END IF;

        INSERT INTO goods_receipt_lines (
            org_id, goods_receipt_id, purchase_order_line_id, product_id,
            ordered_quantity, received_quantity, unit_cost, quality_status, notes
        ) VALUES (
            v_org, v_gr_id, v_pol_id, v_prod,
            COALESCE((v_line->>'ordered_quantity')::NUMERIC, v_recv),
            v_recv, v_cost, v_quality, NULLIF(v_line->>'notes', '')
        );

        IF v_quality = 'accepted' AND v_recv > 0 THEN
            v_total := v_total + (v_recv * v_cost);
            PERFORM wardah_apply_stock_incoming(
                v_org, v_prod, v_wh_id, v_recv, v_cost,
                'Goods Receipt', v_gr_id, v_gr_number, v_recv_date
            );
        END IF;
    END LOOP;

    IF v_po_id IS NOT NULL THEN
        UPDATE purchase_orders po
        SET status = CASE
            WHEN NOT EXISTS (
                SELECT 1 FROM purchase_order_lines l
                WHERE l.purchase_order_id = po.id
                  AND COALESCE(l.received_quantity, 0) < l.quantity
            ) THEN 'fully_received'
            ELSE 'partially_received'
        END
        WHERE po.id = v_po_id;
    END IF;

    IF v_total > 0 THEN
        PERFORM rpc_post_event_journal(
            'GR_RECEIPT', v_total, 'استلام بضاعة ' || v_gr_number,
            'GOODS_RECEIPT', v_gr_id, v_org,
            'GR_RECEIPT:' || v_gr_id::TEXT, NULL
        );
    END IF;

    RETURN jsonb_build_object(
        'success', TRUE, 'goods_receipt_id', v_gr_id,
        'receipt_number', v_gr_number, 'total_value', ROUND(v_total, 6),
        'lines_processed', v_line_no,
        'inventory_atomic', TRUE
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_post_payroll_run(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org        UUID;
    v_year       INT;
    v_month      INT;
    v_idem       TEXT;
    v_hash       TEXT;
    v_period_id  UUID;
    v_run_id     UUID;
    v_existing   payroll_runs%ROWTYPE;
    v_totals     JSONB;
    v_lines      JSONB;
    v_entry_date DATE;
    v_gl_lines   JSONB := '[]'::JSONB;
    v_line_no    INT := 0;
    v_debits     NUMERIC := 0;
    v_credits    NUMERIC := 0;
    v_journal    JSONB;
    v_amount     NUMERIC;
    v_acct       UUID;
    v_bucket     TEXT;
    v_total_gross NUMERIC;
    v_total_ded   NUMERIC;
    v_total_net   NUMERIC;
    v_sum_earn    NUMERIC;
    v_sum_ded     NUMERIC;
    v_bad         BIGINT;
    v_expected    NUMERIC;
    c_tol CONSTANT NUMERIC := 0.011;
    c_debit_buckets  TEXT[] := ARRAY['basic_salary','housing_allowance',
        'transport_allowance','other_allowance','overtime','gosi_employer_expense'];
    c_credit_buckets TEXT[] := ARRAY['gosi_payable','deductions','loans',
        'absence_recovery','payable'];
    c_earning_line_buckets  TEXT[] := ARRAY['basic_salary','housing_allowance',
        'transport_allowance','other_allowance','overtime'];
    c_deduction_line_buckets TEXT[] := ARRAY['deductions','loans',
        'absence_recovery','gosi_employee'];
BEGIN
    v_org := wardah_org_id(NULLIF(p_payload->>'tenant_id','')::uuid);
    IF v_org IS NULL THEN RAISE EXCEPTION 'ORG_NOT_RESOLVED'; END IF;
    IF NOT EXISTS (SELECT 1 FROM user_organizations
                   WHERE user_id = auth.uid() AND org_id = v_org) THEN
        RAISE EXCEPTION 'NOT_ORG_MEMBER';
    END IF;
    IF NOT wardah_is_org_admin(v_org) THEN
        RAISE EXCEPTION 'NOT_AUTHORIZED_PAYROLL_POST: اعتماد المسير يتطلب صلاحية مدير المؤسسة';
    END IF;

    IF COALESCE((p_payload->>'payload_version')::int, 1) <> 2 THEN
        RAISE EXCEPTION 'PAYLOAD_VERSION_UNSUPPORTED: الخادم يتطلب payload_version=2 — حدّث الواجهة';
    END IF;

    v_year  := (p_payload->>'year')::int;
    v_month := (p_payload->>'month')::int;
    v_idem  := NULLIF(p_payload->>'idempotency_key','');
    IF v_year IS NULL OR v_month IS NULL OR v_idem IS NULL THEN
        RAISE EXCEPTION 'INVALID_PAYLOAD: year/month/idempotency_key إلزامية';
    END IF;
    v_totals := COALESCE(p_payload->'totals', '{}'::jsonb);
    v_lines  := COALESCE(p_payload->'lines', '[]'::jsonb);
    v_total_gross := COALESCE((p_payload->>'total_gross')::numeric, 0);
    v_total_ded   := COALESCE((p_payload->>'total_deductions')::numeric, 0);
    v_total_net   := COALESCE((p_payload->>'total_net')::numeric, 0);
    v_entry_date := COALESCE(NULLIF(p_payload->>'entry_date','')::date,
                             make_date(v_year, v_month, 1) + INTERVAL '1 month' - INTERVAL '1 day');

    BEGIN
        SELECT COUNT(*),
               COUNT(*) FILTER (WHERE
                   NULLIF(l->>'employee_id','')    IS NULL
                OR NULLIF(l->>'component_code','') IS NULL
                OR NOT (l ? 'is_deduction')
                OR (l->>'amount')::numeric IS NULL
                OR (l->>'amount')::numeric <= 0
                OR NOT (
                     CASE WHEN (l->>'is_deduction')::boolean
                          THEN (l->>'bucket') = ANY (c_deduction_line_buckets)
                          ELSE (l->>'bucket') = ANY (c_earning_line_buckets)
                     END))
        INTO v_line_no, v_bad
        FROM jsonb_array_elements(v_lines) l;
    EXCEPTION WHEN invalid_text_representation OR datatype_mismatch THEN
        RAISE EXCEPTION 'INVALID_LINE: قيمة غير قابلة للتحويل (uuid/numeric/boolean)';
    END;
    IF v_line_no = 0 THEN
        RAISE EXCEPTION 'EMPTY_PAYROLL: لا سطور للترحيل';
    END IF;
    IF v_bad > 0 THEN
        RAISE EXCEPTION 'INVALID_LINE: % سطر بمبلغ غير موجب أو حقول ناقصة أو bucket خارج القائمة', v_bad;
    END IF;
    v_line_no := 0;

    SELECT COUNT(*) INTO v_bad
    FROM (SELECT DISTINCT (l->>'employee_id')::uuid AS emp_id
          FROM jsonb_array_elements(v_lines) l) s
    LEFT JOIN employees e ON e.id = s.emp_id AND e.org_id = v_org
    WHERE e.id IS NULL;
    IF v_bad > 0 THEN
        RAISE EXCEPTION 'EMPLOYEE_ORG_MISMATCH: % موظف في السطور لا يتبع المؤسسة', v_bad;
    END IF;

    SELECT COALESCE(SUM((l->>'amount')::numeric) FILTER (WHERE NOT (l->>'is_deduction')::boolean), 0),
           COALESCE(SUM((l->>'amount')::numeric) FILTER (WHERE (l->>'is_deduction')::boolean), 0)
    INTO v_sum_earn, v_sum_ded
    FROM jsonb_array_elements(v_lines) l;
    IF abs(v_sum_earn - v_total_gross) > c_tol
       OR abs(v_sum_ded - v_total_ded) > c_tol
       OR abs(v_total_net - (v_total_gross - v_total_ded)) > c_tol THEN
        RAISE EXCEPTION 'TOTALS_MISMATCH: سطور(% / %) ≠ إجماليات(% / % / %)',
            v_sum_earn, v_sum_ded, v_total_gross, v_total_ded, v_total_net;
    END IF;

    FOREACH v_bucket IN ARRAY c_earning_line_buckets LOOP
        SELECT COALESCE(SUM((l->>'amount')::numeric), 0) INTO v_expected
        FROM jsonb_array_elements(v_lines) l
        WHERE l->>'bucket' = v_bucket AND NOT (l->>'is_deduction')::boolean;
        IF abs(v_expected - COALESCE((v_totals->>v_bucket)::numeric, 0)) > c_tol THEN
            RAISE EXCEPTION 'BUCKETS_MISMATCH: % — سطور % ≠ قيد %',
                v_bucket, v_expected, COALESCE((v_totals->>v_bucket)::numeric, 0);
        END IF;
    END LOOP;
    FOREACH v_bucket IN ARRAY ARRAY['deductions','loans','absence_recovery'] LOOP
        SELECT COALESCE(SUM((l->>'amount')::numeric), 0) INTO v_expected
        FROM jsonb_array_elements(v_lines) l
        WHERE l->>'bucket' = v_bucket AND (l->>'is_deduction')::boolean;
        IF abs(v_expected - COALESCE((v_totals->>v_bucket)::numeric, 0)) > c_tol THEN
            RAISE EXCEPTION 'BUCKETS_MISMATCH: % — سطور % ≠ قيد %',
                v_bucket, v_expected, COALESCE((v_totals->>v_bucket)::numeric, 0);
        END IF;
    END LOOP;
    SELECT COALESCE(SUM((l->>'amount')::numeric), 0) INTO v_expected
    FROM jsonb_array_elements(v_lines) l
    WHERE l->>'bucket' = 'gosi_employee' AND (l->>'is_deduction')::boolean;
    IF COALESCE((v_totals->>'gosi_employer_expense')::numeric, 0) < 0
       OR COALESCE((v_totals->>'gosi_payable')::numeric, 0)
          < COALESCE((v_totals->>'gosi_employer_expense')::numeric, 0)
       OR abs(v_expected + COALESCE((v_totals->>'gosi_employer_expense')::numeric, 0)
              - COALESCE((v_totals->>'gosi_payable')::numeric, 0)) > c_tol THEN
        RAISE EXCEPTION 'BUCKETS_MISMATCH: gosi_payable ≠ سطور حصة الموظف (%) + gosi_employer_expense', v_expected;
    END IF;
    IF abs(COALESCE((v_totals->>'payable')::numeric, 0) - v_total_net) > c_tol THEN
        RAISE EXCEPTION 'BUCKETS_MISMATCH: payable (%) ≠ total_net (%)',
            COALESCE((v_totals->>'payable')::numeric, 0), v_total_net;
    END IF;

    v_hash := md5((p_payload - 'idempotency_key')::text);
    PERFORM pg_advisory_xact_lock(hashtext(v_org::text || ':payroll:' || v_year || '-' || v_month));

    SELECT * INTO v_existing FROM payroll_runs
    WHERE org_id = v_org AND idempotency_key = v_idem;
    IF FOUND THEN
        IF v_existing.request_hash IS DISTINCT FROM v_hash THEN
            RAISE EXCEPTION 'IDEMPOTENCY_KEY_REUSED';
        END IF;
        RETURN jsonb_build_object(
            'success', true, 'replayed', true,
            'payroll_run_id', v_existing.id,
            'journal_entry_id', v_existing.journal_entry_id,
            'status', v_existing.status);
    END IF;

    IF EXISTS (SELECT 1 FROM hr_payroll_locks
               WHERE org_id = v_org AND year = v_year AND month = v_month
                 AND status = 'locked') THEN
        RAISE EXCEPTION 'PAYROLL_MONTH_LOCKED';
    END IF;

    SELECT id INTO v_period_id FROM payroll_periods
    WHERE org_id = v_org AND period_code = format('%s-%s', v_year, lpad(v_month::text,2,'0'));
    IF v_period_id IS NULL THEN
        INSERT INTO payroll_periods (org_id, period_code, period_name, period_type,
                                     start_date, end_date, status)
        VALUES (v_org, format('%s-%s', v_year, lpad(v_month::text,2,'0')),
                format('مسير %s-%s', v_year, lpad(v_month::text,2,'0')), 'monthly',
                make_date(v_year, v_month, 1), v_entry_date, 'open')
        RETURNING id INTO v_period_id;
    END IF;

    IF EXISTS (SELECT 1 FROM payroll_runs WHERE org_id = v_org AND period_id = v_period_id) THEN
        RAISE EXCEPTION 'PAYROLL_RUN_EXISTS: يوجد مسير لهذه الفترة';
    END IF;

    INSERT INTO payroll_runs (org_id, period_id, run_date, status,
                              total_gross, total_deductions, total_net,
                              idempotency_key, request_hash)
    VALUES (v_org, v_period_id, CURRENT_DATE, 'calculated',
            v_total_gross, v_total_ded, v_total_net, v_idem, v_hash)
    RETURNING id INTO v_run_id;

    INSERT INTO payroll_details (org_id, payroll_run_id, employee_id,
                                 component_id, component_code, component_label,
                                 is_deduction, bucket, amount, is_processed, processed_at)
    SELECT v_org, v_run_id,
           (l->>'employee_id')::uuid,
           NULLIF(l->>'component_id','')::uuid,
           l->>'component_code',
           l->>'component_label',
           (l->>'is_deduction')::boolean,
           l->>'bucket',
           (l->>'amount')::numeric,
           true, NOW()
    FROM jsonb_array_elements(v_lines) l;

    FOREACH v_bucket IN ARRAY c_debit_buckets LOOP
        v_amount := ROUND(COALESCE((v_totals->>v_bucket)::numeric, 0), 2);
        CONTINUE WHEN v_amount = 0;
        SELECT gl_account_id INTO v_acct FROM hr_payroll_account_mappings
        WHERE org_id = v_org AND account_type = v_bucket;
        IF v_acct IS NULL THEN
            RAISE EXCEPTION 'MAPPING_MISSING: % — اضبط الحساب من ضبط الرواتب', v_bucket;
        END IF;
        v_line_no := v_line_no + 1;
        v_debits := v_debits + v_amount;
        v_gl_lines := v_gl_lines || jsonb_build_array(jsonb_build_object(
            'line_number', v_line_no, 'account_id', v_acct,
            'debit', v_amount, 'credit', 0,
            'description', 'مسير رواتب ' || v_year || '-' || lpad(v_month::text,2,'0') || ' — ' || v_bucket));
    END LOOP;

    FOREACH v_bucket IN ARRAY c_credit_buckets LOOP
        v_amount := ROUND(COALESCE((v_totals->>v_bucket)::numeric, 0), 2);
        CONTINUE WHEN v_amount = 0;
        SELECT gl_account_id INTO v_acct FROM hr_payroll_account_mappings
        WHERE org_id = v_org AND account_type = v_bucket;
        IF v_acct IS NULL THEN
            RAISE EXCEPTION 'MAPPING_MISSING: % — اضبط الحساب من ضبط الرواتب', v_bucket;
        END IF;
        v_line_no := v_line_no + 1;
        v_credits := v_credits + v_amount;
        v_gl_lines := v_gl_lines || jsonb_build_array(jsonb_build_object(
            'line_number', v_line_no, 'account_id', v_acct,
            'debit', 0, 'credit', v_amount,
            'description', 'مسير رواتب ' || v_year || '-' || lpad(v_month::text,2,'0') || ' — ' || v_bucket));
    END LOOP;

    IF v_line_no < 2 THEN
        RAISE EXCEPTION 'EMPTY_PAYROLL: لا مبالغ للترحيل';
    END IF;
    IF ROUND(v_debits,2) <> ROUND(v_credits,2) THEN
        RAISE EXCEPTION 'UNBALANCED_PAYROLL: مدين % ≠ دائن %', v_debits, v_credits;
    END IF;

    v_journal := rpc_create_journal_entry(jsonb_build_object(
        'org_id', v_org::text,
        'entry_date', v_entry_date::text,
        'description', 'Payroll run ' || v_year || '-' || lpad(v_month::text,2,'0'),
        'description_ar', 'مسير رواتب ' || v_year || '-' || lpad(v_month::text,2,'0'),
        'reference_type', 'PAYROLL',
        'reference_number', v_year || '-' || lpad(v_month::text,2,'0'),
        'idempotency_key', v_idem || ':gl',
        'auto_post', true,
        'lines', v_gl_lines));

    UPDATE payroll_runs
    SET status = 'approved', journal_entry_id = (v_journal->>'entry_id')::uuid,
        updated_at = NOW()
    WHERE id = v_run_id;

    INSERT INTO hr_payroll_locks (org_id, year, month, status, locked_at, locked_by, journal_entry_id)
    VALUES (v_org, v_year, v_month, 'locked', NOW(), auth.uid(), (v_journal->>'entry_id')::uuid)
    ON CONFLICT (org_id, year, month) DO UPDATE SET
        status = 'locked', locked_at = NOW(), locked_by = auth.uid(),
        journal_entry_id = (v_journal->>'entry_id')::uuid;

    RETURN jsonb_build_object(
        'success', true, 'replayed', false,
        'payroll_run_id', v_run_id,
        'journal_entry_id', v_journal->>'entry_id',
        'entry_number', v_journal->>'entry_number',
        'total_debit', v_debits, 'total_credit', v_credits,
        'status', 'approved');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_post_settlement(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org        UUID;
    v_idem       TEXT;
    v_hash       TEXT;
    v_settlement hr_settlements%ROWTYPE;
    v_snapshot   JSONB;
    v_amount     NUMERIC;
    v_exp_acct   UUID;
    v_pay_acct   UUID;
    v_journal    JSONB;
    v_entry_date DATE;
    v_emp_status TEXT;
BEGIN
    v_org := wardah_org_id(NULLIF(p_payload->>'tenant_id','')::uuid);
    IF v_org IS NULL THEN RAISE EXCEPTION 'ORG_NOT_RESOLVED'; END IF;
    IF NOT EXISTS (SELECT 1 FROM user_organizations
                   WHERE user_id = auth.uid() AND org_id = v_org) THEN
        RAISE EXCEPTION 'NOT_ORG_MEMBER';
    END IF;
    IF NOT wardah_is_org_admin(v_org) THEN
        RAISE EXCEPTION 'NOT_AUTHORIZED_SETTLEMENT_POST: اعتماد التسوية يتطلب صلاحية مدير المؤسسة';
    END IF;

    v_idem := NULLIF(p_payload->>'idempotency_key','');
    IF v_idem IS NULL THEN RAISE EXCEPTION 'INVALID_PAYLOAD: idempotency_key إلزامي'; END IF;
    v_hash := md5((p_payload - 'idempotency_key')::text);

    SELECT * INTO v_settlement FROM hr_settlements
    WHERE id = (p_payload->>'settlement_id')::uuid AND org_id = v_org
    FOR UPDATE;
    IF NOT FOUND THEN RAISE EXCEPTION 'SETTLEMENT_NOT_FOUND'; END IF;

    IF v_settlement.idempotency_key = v_idem AND v_settlement.journal_entry_id IS NOT NULL THEN
        IF v_settlement.request_hash IS NOT NULL
           AND v_settlement.request_hash IS DISTINCT FROM v_hash THEN
            RAISE EXCEPTION 'IDEMPOTENCY_KEY_REUSED';
        END IF;
        RETURN jsonb_build_object('success', true, 'replayed', true,
            'settlement_id', v_settlement.id,
            'journal_entry_id', v_settlement.journal_entry_id,
            'status', v_settlement.status);
    END IF;

    IF v_settlement.status <> 'review' THEN
        RAISE EXCEPTION 'SETTLEMENT_NOT_REVIEWED: الحالة % — أرسل التسوية للمراجعة أولاً', v_settlement.status;
    END IF;

    v_snapshot := wardah_settlement_snapshot(v_settlement.id);
    IF v_settlement.review_hash IS DISTINCT FROM md5(v_snapshot::text) THEN
        RAISE EXCEPTION 'SETTLEMENT_CHANGED_AFTER_REVIEW: أعد إرسالها للمراجعة';
    END IF;

    v_amount := ROUND(COALESCE(v_settlement.payable_amount, v_settlement.calculated_amount, 0), 2);
    IF v_amount <= 0 THEN RAISE EXCEPTION 'SETTLEMENT_ZERO_AMOUNT'; END IF;
    v_entry_date := COALESCE(NULLIF(p_payload->>'entry_date','')::date, CURRENT_DATE);

    IF v_settlement.settlement_type = 'end_of_service' THEN
        SELECT status INTO v_emp_status FROM employees
        WHERE id = v_settlement.employee_id AND org_id = v_org;
        IF v_emp_status IS NULL THEN
            RAISE EXCEPTION 'EMPLOYEE_ORG_MISMATCH: موظف التسوية لا يتبع المؤسسة';
        END IF;
        IF v_emp_status <> 'active' THEN
            RAISE EXCEPTION 'EMPLOYEE_NOT_ACTIVE: حالة الموظف % — لا إنهاء مكرر', v_emp_status;
        END IF;
        IF v_settlement.service_end IS NOT NULL AND v_settlement.service_start IS NOT NULL
           AND v_settlement.service_end < v_settlement.service_start THEN
            RAISE EXCEPTION 'SETTLEMENT_INVALID_PERIOD: نهاية الخدمة قبل بدايتها';
        END IF;
        IF EXISTS (SELECT 1 FROM hr_settlements
                   WHERE org_id = v_org AND employee_id = v_settlement.employee_id
                     AND settlement_type = 'end_of_service'
                     AND status IN ('approved','paid') AND id <> v_settlement.id) THEN
            RAISE EXCEPTION 'EOS_ALREADY_SETTLED: للموظف تسوية نهاية خدمة معتمدة سابقاً';
        END IF;
        IF v_settlement.service_end IS NOT NULL AND EXISTS (
            SELECT 1 FROM hr_payroll_locks
            WHERE org_id = v_org AND status = 'locked'
              AND make_date(year, month, 1)
                  > date_trunc('month', v_settlement.service_end)::date) THEN
            RAISE EXCEPTION 'SETTLEMENT_AFTER_LOCKED_PAYROLL: يوجد مسير مقفل لشهر يلي نهاية الخدمة — راجع الفترات أولاً';
        END IF;
    END IF;

    SELECT gl_account_id INTO v_exp_acct FROM hr_payroll_account_mappings
    WHERE org_id = v_org AND account_type = 'eos_expense';
    SELECT gl_account_id INTO v_pay_acct FROM hr_payroll_account_mappings
    WHERE org_id = v_org AND account_type = 'eos_payable';
    IF v_exp_acct IS NULL OR v_pay_acct IS NULL THEN
        RAISE EXCEPTION 'MAPPING_MISSING: eos_expense/eos_payable — اضبطهما من ضبط الرواتب';
    END IF;

    v_journal := rpc_create_journal_entry(jsonb_build_object(
        'org_id', v_org::text,
        'entry_date', v_entry_date::text,
        'description', 'End of service settlement',
        'description_ar', 'تسوية نهاية خدمة',
        'reference_type', 'SETTLEMENT',
        'reference_number', v_settlement.id::text,
        'idempotency_key', v_idem || ':gl',
        'auto_post', true,
        'lines', jsonb_build_array(
            jsonb_build_object('line_number', 1, 'account_id', v_exp_acct,
                               'debit', v_amount, 'credit', 0,
                               'description', 'مكافأة نهاية خدمة'),
            jsonb_build_object('line_number', 2, 'account_id', v_pay_acct,
                               'debit', 0, 'credit', v_amount,
                               'description', 'مستحق نهاية خدمة'))));

    UPDATE hr_settlements
    SET status = 'approved', approved_by = auth.uid(), approved_at = NOW(),
        journal_entry_id = (v_journal->>'entry_id')::uuid,
        idempotency_key = v_idem, request_hash = v_hash,
        posted_snapshot = v_snapshot, updated_at = NOW()
    WHERE id = v_settlement.id;

    IF v_settlement.settlement_type = 'end_of_service' THEN
        UPDATE employees
        SET status = 'terminated',
            termination_date = COALESCE(v_settlement.service_end, CURRENT_DATE),
            updated_at = NOW()
        WHERE id = v_settlement.employee_id AND org_id = v_org;
    END IF;

    RETURN jsonb_build_object('success', true, 'replayed', false,
        'settlement_id', v_settlement.id,
        'journal_entry_id', v_journal->>'entry_id',
        'entry_number', v_journal->>'entry_number',
        'amount', v_amount, 'status', 'approved');
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_post_work_center_oh(p_work_center text, p_amount numeric, p_memo text, p_ref_type text, p_ref_id uuid DEFAULT NULL::uuid, p_tenant uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_jv_date date DEFAULT NULL::date)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID := wardah_org_id(p_tenant);
    v_map RECORD;
    v_debit_id UUID;
    v_credit_id UUID;
    v_result JSONB;
BEGIN
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;
    IF p_amount IS NULL OR p_amount <= 0 THEN
        RAISE EXCEPTION 'INVALID_AMOUNT: مبلغ الأوفرهيد يجب أن يكون موجباً';
    END IF;

    -- خريطة مخصصة لمركز العمل أولاً، ثم الخريطة العامة OH_APPLIED
    SELECT * INTO v_map
    FROM gl_event_mappings
    WHERE org_id = v_org AND event_code = 'OH_APPLIED'
      AND work_center_code = p_work_center AND is_active = true
    LIMIT 1;

    IF NOT FOUND THEN
        SELECT * INTO v_map
        FROM gl_event_mappings
        WHERE org_id = v_org AND event_code = 'OH_APPLIED'
          AND work_center_code IS NULL AND is_active = true
        LIMIT 1;
    END IF;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'MAPPING_MISSING: لا توجد خريطة OH_APPLIED لمركز العمل "%" ولا خريطة عامة', p_work_center;
    END IF;

    SELECT id INTO v_debit_id FROM gl_accounts WHERE org_id = v_org AND code = v_map.debit_account_code;
    SELECT id INTO v_credit_id FROM gl_accounts WHERE org_id = v_org AND code = v_map.credit_account_code;
    IF v_debit_id IS NULL OR v_credit_id IS NULL THEN
        RAISE EXCEPTION 'ACCOUNT_NOT_FOUND: أحد حسابي خريطة OH_APPLIED غير موجود';
    END IF;

    v_result := rpc_create_journal_entry(jsonb_build_object(
        'org_id', v_org,
        'entry_date', COALESCE(p_jv_date, CURRENT_DATE),
        'description', p_memo,
        'reference_type', p_ref_type,
        'reference_number', p_ref_id::text,
        'idempotency_key', p_idempotency_key,
        'auto_post', false,
        'lines', jsonb_build_array(
            jsonb_build_object('line_number', 1, 'account_id', v_debit_id,
                               'debit', p_amount, 'credit', 0,
                               'description', p_memo || ' [WC: ' || p_work_center || ']'),
            jsonb_build_object('line_number', 2, 'account_id', v_credit_id,
                               'debit', 0, 'credit', p_amount,
                               'description', p_memo || ' [WC: ' || p_work_center || ']')
        )
    ));

    RETURN (v_result ->> 'entry_id')::uuid;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_set_org_admin(p_target_user_id uuid, p_org_id uuid, p_value boolean)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_caller_id UUID := auth.uid();
    v_admins_count INT;
BEGIN
    IF NOT (wardah_is_org_admin(p_org_id) OR is_super_admin()) THEN
        RETURN jsonb_build_object('ok', false, 'error', 'NOT_ORG_ADMIN');
    END IF;
    IF p_target_user_id = v_caller_id AND p_value = true THEN
        RETURN jsonb_build_object('ok', false, 'error', 'CANNOT_PROMOTE_SELF');
    END IF;
    IF p_value = false THEN
        SELECT COUNT(*) INTO v_admins_count
        FROM user_organizations
        WHERE org_id = p_org_id AND is_org_admin = true AND is_active = true AND user_id != p_target_user_id;
        IF v_admins_count = 0 THEN
            RETURN jsonb_build_object('ok', false, 'error', 'LAST_ORG_ADMIN');
        END IF;
    END IF;
    UPDATE user_organizations SET is_org_admin = p_value WHERE user_id = p_target_user_id AND org_id = p_org_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('ok', false, 'error', 'USER_NOT_MEMBER');
    END IF;
    RETURN jsonb_build_object('ok', true);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_set_period_status(p_period_code text, p_status text, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org     UUID := wardah_org_id(p_tenant);
    v_col     TEXT := wardah_periods_org_col();
    v_current TEXT;
    v_id      UUID;
BEGIN
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;
    IF v_col IS NULL THEN
        RAISE EXCEPTION 'PERIODS_TABLE_MISSING: جدول accounting_periods غير موجود أو بنيته غير معروفة';
    END IF;
    IF p_status NOT IN ('open', 'closed', 'permanently_closed') THEN
        RAISE EXCEPTION 'INVALID_STATUS: الحالة "%" غير صالحة — المسموح: open / closed / permanently_closed', p_status;
    END IF;

    EXECUTE format(
        'SELECT id, status FROM accounting_periods WHERE %I = $1 AND period_code = $2 LIMIT 1',
        v_col
    )
    INTO v_id, v_current
    USING v_org, p_period_code;

    IF v_id IS NULL THEN
        RAISE EXCEPTION 'PERIOD_NOT_FOUND: الفترة "%" غير موجودة', p_period_code;
    END IF;

    IF v_current = 'permanently_closed' THEN
        RAISE EXCEPTION 'PERIOD_LOCKED: الفترة "%" مقفلة نهائياً ولا يمكن تغيير حالتها', p_period_code;
    END IF;

    IF v_current = p_status THEN
        RETURN jsonb_build_object(
            'success', true, 'period_code', p_period_code,
            'status', p_status, 'changed', false
        );
    END IF;

    EXECUTE format(
        'UPDATE accounting_periods SET status = $1, updated_at = now()
         WHERE %I = $2 AND period_code = $3',
        v_col
    )
    USING p_status, v_org, p_period_code;

    RETURN jsonb_build_object(
        'success', true,
        'period_code', p_period_code,
        'previous_status', v_current,
        'status', p_status,
        'changed', true
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_subledger_gl_reconciliation(p_as_of_date date DEFAULT CURRENT_DATE, p_tenant uuid DEFAULT NULL::uuid, p_inventory_prefixes text[] DEFAULT ARRAY['131'::text, '132'::text, '133'::text, '135'::text], p_wip_prefixes text[] DEFAULT ARRAY['134'::text])
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID;

    -- كشف أعمدة gl_entry_lines (الأرشيف: debit_amount/account_code — الحي: debit/account_id)
    v_debit_col   TEXT;
    v_credit_col  TEXT;
    v_has_acct_id BOOLEAN;
    v_sql         TEXT;

    -- أرصدة GL لكل قسم + تفصيل الحسابات
    v_gl_inventory      NUMERIC := 0;
    v_gl_wip            NUMERIC := 0;
    v_inv_accounts      JSONB   := '[]'::JSONB;
    v_wip_accounts      JSONB   := '[]'::JSONB;
    v_gl_available      BOOLEAN := FALSE;

    -- الدفاتر الفرعية
    v_sub_inventory        NUMERIC := NULL;  -- NULL = غير متاح
    v_sub_inventory_source TEXT    := NULL;
    v_sub_wip              NUMERIC := NULL;
    v_sub_wip_source       TEXT    := NULL;
    v_open_mo_count        INTEGER := 0;

    -- تسوية
    v_inv_diff      NUMERIC;
    v_wip_diff      NUMERIC;
    v_inv_balanced  BOOLEAN;
    v_wip_balanced  BOOLEAN;

    -- أعمدة stage_costs الديناميكية
    v_sc_tenant_col TEXT;
    v_sc_mo_col     TEXT;
BEGIN
    -- ===== هوية المؤسسة =====
    v_org := wardah_org_id(p_tenant);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED: تعذر تحديد هوية المؤسسة';
    END IF;

    -- ================================================================
    -- جانب GL: أرصدة الحسابات من القيود المرحَّلة حتى التاريخ المطلوب
    -- ================================================================
    IF to_regclass('public.gl_entries') IS NOT NULL
       AND to_regclass('public.gl_entry_lines') IS NOT NULL THEN

        SELECT column_name INTO v_debit_col
        FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'gl_entry_lines'
          AND column_name IN ('debit', 'debit_amount')
        ORDER BY CASE column_name WHEN 'debit' THEN 1 ELSE 2 END
        LIMIT 1;

        SELECT column_name INTO v_credit_col
        FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'gl_entry_lines'
          AND column_name IN ('credit', 'credit_amount')
        ORDER BY CASE column_name WHEN 'credit' THEN 1 ELSE 2 END
        LIMIT 1;

        v_has_acct_id := EXISTS (
            SELECT 1 FROM information_schema.columns
            WHERE table_schema = 'public' AND table_name = 'gl_entry_lines'
              AND column_name = 'account_id'
        ) AND to_regclass('public.gl_accounts') IS NOT NULL;

        IF v_debit_col IS NOT NULL AND v_credit_col IS NOT NULL THEN
            v_gl_available := TRUE;

            -- الرصيد المدين الصافي لكل حساب (طبيعة حسابات الأصول)
            IF v_has_acct_id THEN
                v_sql := format(
                    'SELECT COALESCE(a.code, '''') AS code,
                            COALESCE(a.name, a.name_ar, '''') AS name,
                            SUM(COALESCE(l.%I,0) - COALESCE(l.%I,0)) AS balance
                     FROM gl_entry_lines l
                     JOIN gl_entries e ON e.id = l.entry_id
                     JOIN gl_accounts a ON a.id = l.account_id
                     WHERE e.org_id = $1
                       AND e.status = ''posted''
                       AND e.entry_date <= $2
                       AND a.code LIKE ANY (SELECT unnest($3) || ''%%'')
                     GROUP BY a.code, COALESCE(a.name, a.name_ar, '''')
                     ORDER BY a.code',
                    v_debit_col, v_credit_col
                );
            ELSE
                v_sql := format(
                    'SELECT l.account_code AS code,
                            COALESCE(MAX(l.account_name), '''') AS name,
                            SUM(COALESCE(l.%I,0) - COALESCE(l.%I,0)) AS balance
                     FROM gl_entry_lines l
                     JOIN gl_entries e ON e.id = l.entry_id
                     WHERE e.org_id = $1
                       AND e.status = ''posted''
                       AND e.entry_date <= $2
                       AND l.account_code LIKE ANY (SELECT unnest($3) || ''%%'')
                     GROUP BY l.account_code
                     ORDER BY l.account_code',
                    v_debit_col, v_credit_col
                );
            END IF;

            -- قسم المخزون
            EXECUTE format(
                'SELECT COALESCE(SUM(balance),0),
                        COALESCE(jsonb_agg(jsonb_build_object(
                            ''code'', code, ''name'', name,
                            ''balance'', ROUND(balance,6))), ''[]''::jsonb)
                 FROM (%s) t', v_sql)
            INTO v_gl_inventory, v_inv_accounts
            USING v_org, p_as_of_date, p_inventory_prefixes;

            -- قسم WIP
            EXECUTE format(
                'SELECT COALESCE(SUM(balance),0),
                        COALESCE(jsonb_agg(jsonb_build_object(
                            ''code'', code, ''name'', name,
                            ''balance'', ROUND(balance,6))), ''[]''::jsonb)
                 FROM (%s) t', v_sql)
            INTO v_gl_wip, v_wip_accounts
            USING v_org, p_as_of_date, p_wip_prefixes;
        END IF;
    END IF;

    -- ================================================================
    -- الدفتر الفرعي للمخزون: آخر رصيد جارٍ لكل صنف حتى التاريخ
    -- ================================================================
    IF to_regclass('public.inventory_ledger') IS NOT NULL THEN
        BEGIN
            SELECT COALESCE(SUM(running_value), 0), 'inventory_ledger'
            INTO v_sub_inventory, v_sub_inventory_source
            FROM (
                SELECT DISTINCT ON (item_id) running_value
                FROM inventory_ledger
                WHERE tenant_id = v_org
                  AND moved_at::date <= p_as_of_date
                ORDER BY item_id, moved_at DESC, created_at DESC
            ) latest;
        EXCEPTION WHEN OTHERS THEN
            v_sub_inventory := NULL;  -- بنية أعمدة مختلفة — نجرّب المصدر الآخر
        END;
    END IF;

    IF v_sub_inventory IS NULL
       AND to_regclass('public.stock_ledger_entries') IS NOT NULL THEN
        BEGIN
            SELECT COALESCE(SUM(stock_value), 0), 'stock_ledger_entries'
            INTO v_sub_inventory, v_sub_inventory_source
            FROM (
                SELECT DISTINCT ON (product_id, warehouse_id) stock_value
                FROM stock_ledger_entries
                WHERE org_id = v_org
                  AND posting_date <= p_as_of_date
                  AND COALESCE(is_cancelled, FALSE) = FALSE
                ORDER BY product_id, warehouse_id, posting_datetime DESC
            ) latest;
        EXCEPTION WHEN OTHERS THEN
            v_sub_inventory := NULL;
        END;
    END IF;

    -- ================================================================
    -- الدفتر الفرعي لـ WIP: تكاليف مراحل الأوامر المفتوحة
    -- (أمر مكتمل/ملغى يجب أن يكون WIP الخاص به صفراً — تحوَّل لـ FG)
    -- ================================================================
    IF to_regclass('public.stage_costs') IS NOT NULL
       AND to_regclass('public.manufacturing_orders') IS NOT NULL THEN

        SELECT column_name INTO v_sc_tenant_col
        FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'stage_costs'
          AND column_name IN ('tenant_id', 'org_id')
        ORDER BY CASE column_name WHEN 'tenant_id' THEN 1 ELSE 2 END
        LIMIT 1;

        SELECT column_name INTO v_sc_mo_col
        FROM information_schema.columns
        WHERE table_schema = 'public' AND table_name = 'stage_costs'
          AND column_name IN ('mo_id', 'manufacturing_order_id')
        ORDER BY CASE column_name WHEN 'mo_id' THEN 1 ELSE 2 END
        LIMIT 1;

        IF v_sc_tenant_col IS NOT NULL AND v_sc_mo_col IS NOT NULL THEN
            BEGIN
                EXECUTE format(
                    'SELECT COALESCE(SUM(sc.total_cost),0), COUNT(DISTINCT mo.id)
                     FROM stage_costs sc
                     JOIN manufacturing_orders mo ON mo.id = sc.%I
                     WHERE sc.%I = $1
                       AND mo.org_id = $1
                       AND lower(replace(mo.status, ''-'', ''_''))
                           NOT IN (''done'', ''completed'', ''cancelled'', ''closed'')',
                    v_sc_mo_col, v_sc_tenant_col
                )
                INTO v_sub_wip, v_open_mo_count
                USING v_org;
                v_sub_wip_source := 'stage_costs (أوامر مفتوحة)';
            EXCEPTION WHEN OTHERS THEN
                v_sub_wip := NULL;
            END;
        END IF;
    END IF;

    -- ================================================================
    -- التسوية
    -- ================================================================
    v_inv_diff     := CASE WHEN v_gl_available AND v_sub_inventory IS NOT NULL
                           THEN v_gl_inventory - v_sub_inventory ELSE NULL END;
    v_wip_diff     := CASE WHEN v_gl_available AND v_sub_wip IS NOT NULL
                           THEN v_gl_wip - v_sub_wip ELSE NULL END;
    v_inv_balanced := v_inv_diff IS NOT NULL AND ABS(v_inv_diff) < 0.01;
    v_wip_balanced := v_wip_diff IS NOT NULL AND ABS(v_wip_diff) < 0.01;

    RETURN jsonb_build_object(
        'success', TRUE,
        'report_type', 'subledger_gl_reconciliation',
        'as_of_date', p_as_of_date,
        'generated_at', now(),
        'gl_available', v_gl_available,
        'sections', jsonb_build_array(
            jsonb_build_object(
                'section', 'inventory',
                'title_ar', 'المخزون (مواد خام + إنتاج تام)',
                'gl_prefixes', to_jsonb(p_inventory_prefixes),
                'gl_balance', CASE WHEN v_gl_available THEN ROUND(v_gl_inventory, 6) END,
                'gl_accounts', v_inv_accounts,
                'subledger_balance', CASE WHEN v_sub_inventory IS NOT NULL
                                          THEN ROUND(v_sub_inventory, 6) END,
                'subledger_source', v_sub_inventory_source,
                'difference', CASE WHEN v_inv_diff IS NOT NULL
                                   THEN ROUND(v_inv_diff, 6) END,
                'is_balanced', v_inv_balanced,
                'status', CASE
                    WHEN NOT v_gl_available          THEN 'gl_unavailable'
                    WHEN v_sub_inventory IS NULL     THEN 'subledger_unavailable'
                    WHEN v_inv_balanced              THEN 'balanced'
                    ELSE 'unbalanced' END
            ),
            jsonb_build_object(
                'section', 'wip',
                'title_ar', 'الإنتاج تحت التشغيل',
                'gl_prefixes', to_jsonb(p_wip_prefixes),
                'gl_balance', CASE WHEN v_gl_available THEN ROUND(v_gl_wip, 6) END,
                'gl_accounts', v_wip_accounts,
                'subledger_balance', CASE WHEN v_sub_wip IS NOT NULL
                                          THEN ROUND(v_sub_wip, 6) END,
                'subledger_source', v_sub_wip_source,
                'open_mo_count', v_open_mo_count,
                'difference', CASE WHEN v_wip_diff IS NOT NULL
                                   THEN ROUND(v_wip_diff, 6) END,
                'is_balanced', v_wip_balanced,
                'status', CASE
                    WHEN NOT v_gl_available      THEN 'gl_unavailable'
                    WHEN v_sub_wip IS NULL       THEN 'subledger_unavailable'
                    WHEN v_wip_balanced          THEN 'balanced'
                    ELSE 'unbalanced' END
            )
        ),
        'all_balanced', v_inv_balanced AND v_wip_balanced
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_submit_settlement_review(p_payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org        UUID;
    v_settlement hr_settlements%ROWTYPE;
    v_snapshot   JSONB;
BEGIN
    v_org := wardah_org_id(NULLIF(p_payload->>'tenant_id','')::uuid);
    IF v_org IS NULL THEN RAISE EXCEPTION 'ORG_NOT_RESOLVED'; END IF;
    IF NOT EXISTS (SELECT 1 FROM user_organizations
                   WHERE user_id = auth.uid() AND org_id = v_org) THEN
        RAISE EXCEPTION 'NOT_ORG_MEMBER';
    END IF;
    IF NOT wardah_is_org_admin(v_org) THEN
        RAISE EXCEPTION 'NOT_AUTHORIZED_SETTLEMENT_POST: إرسال التسوية للمراجعة يتطلب صلاحية مدير المؤسسة';
    END IF;

    SELECT * INTO v_settlement FROM hr_settlements
    WHERE id = (p_payload->>'settlement_id')::uuid AND org_id = v_org
    FOR UPDATE;
    IF NOT FOUND THEN RAISE EXCEPTION 'SETTLEMENT_NOT_FOUND'; END IF;
    IF v_settlement.status <> 'draft' THEN
        RAISE EXCEPTION 'SETTLEMENT_NOT_DRAFT: الحالة % — المراجعة تبدأ من مسودة', v_settlement.status;
    END IF;
    IF ROUND(COALESCE(v_settlement.payable_amount, v_settlement.calculated_amount, 0), 2) <= 0 THEN
        RAISE EXCEPTION 'SETTLEMENT_ZERO_AMOUNT';
    END IF;

    v_snapshot := wardah_settlement_snapshot(v_settlement.id);

    UPDATE hr_settlements
    SET status = 'review',
        reviewed_by = auth.uid(),
        reviewed_at = NOW(),
        review_hash = md5(v_snapshot::text),
        updated_at = NOW()
    WHERE id = v_settlement.id;

    RETURN jsonb_build_object('success', true,
        'settlement_id', v_settlement.id, 'status', 'review',
        'review_hash', md5(v_snapshot::text));
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_transition_mo_status(p_mo_id uuid, p_status text, p_notes text DEFAULT NULL::text, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org  UUID;
    v_uid  UUID;
    v_prev TEXT;
    v_norm TEXT;
    v_mo   RECORD;
BEGIN
    v_org  := wardah_org_id(p_tenant);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED: تعذر تحديد هوية المؤسسة';
    END IF;

    v_uid := auth.uid();
    IF v_uid IS NOT NULL AND NOT EXISTS (
        SELECT 1 FROM user_organizations WHERE user_id = v_uid AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'FORBIDDEN_ORG: المستخدم ليس عضواً في المؤسسة المطلوبة';
    END IF;

    v_norm := normalize_mo_status(p_status);

    SELECT id, status, order_number INTO v_mo
    FROM manufacturing_orders
    WHERE id = p_mo_id AND org_id = v_org;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'MO_NOT_FOUND: أمر التصنيع "%" غير موجود ضمن مؤسستك', p_mo_id;
    END IF;
    v_prev := normalize_mo_status(v_mo.status);

    PERFORM validate_mo_transition(v_mo.status, v_norm);

    UPDATE manufacturing_orders
    SET status = v_norm, notes = COALESCE(p_notes, notes)
    WHERE id = p_mo_id AND org_id = v_org;

    SELECT id, order_number, status, start_date, completed_date, updated_at
    INTO v_mo
    FROM manufacturing_orders WHERE id = p_mo_id;

    RETURN jsonb_build_object(
        'success', TRUE,
        'mo_id', p_mo_id,
        'order_number', v_mo.order_number,
        'previous_status', v_prev,
        'new_status', v_norm,
        'start_date', v_mo.start_date,
        'completed_date', v_mo.completed_date,
        'updated_at', v_mo.updated_at
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.rpc_upsert_event_mapping(p_event_code text, p_debit_account_code text, p_credit_account_code text, p_work_center_code text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_tenant uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID := wardah_org_id(p_tenant);
    v_id UUID;
BEGIN
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'TENANT_MISSING: تعذر تحديد هوية المؤسسة';
    END IF;

    IF to_regclass('public.gl_accounts') IS NOT NULL THEN
        IF NOT EXISTS (SELECT 1 FROM gl_accounts WHERE org_id = v_org AND code = p_debit_account_code) THEN
            RAISE EXCEPTION 'ACCOUNT_NOT_FOUND: الحساب المدين % غير موجود في شجرة الحسابات', p_debit_account_code;
        END IF;
        IF NOT EXISTS (SELECT 1 FROM gl_accounts WHERE org_id = v_org AND code = p_credit_account_code) THEN
            RAISE EXCEPTION 'ACCOUNT_NOT_FOUND: الحساب الدائن % غير موجود في شجرة الحسابات', p_credit_account_code;
        END IF;
    END IF;

    INSERT INTO gl_event_mappings (org_id, event_code, work_center_code,
                                   debit_account_code, credit_account_code, description)
    VALUES (v_org, upper(p_event_code), p_work_center_code,
            p_debit_account_code, p_credit_account_code, p_description)
    ON CONFLICT (org_id, event_code, COALESCE(work_center_code, ''))
    DO UPDATE SET debit_account_code = EXCLUDED.debit_account_code,
                  credit_account_code = EXCLUDED.credit_account_code,
                  description = COALESCE(EXCLUDED.description, gl_event_mappings.description),
                  is_active = true,
                  updated_at = NOW()
    RETURNING id INTO v_id;

    RETURN v_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.schedule_work_order(p_work_order_id uuid, p_scheduled_start timestamp with time zone, p_schedule_id uuid DEFAULT NULL::uuid)
 RETURNS schedule_details
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_work_order work_orders;
    v_scheduled_end TIMESTAMP WITH TIME ZONE;
    v_result schedule_details;
    v_sequence INTEGER;
BEGIN
    -- الحصول على أمر العمل
    SELECT * INTO v_work_order FROM work_orders WHERE id = p_work_order_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Work order not found: %', p_work_order_id;
    END IF;

    -- [120] حارس عضوية على مؤسسة أمر العمل
    PERFORM public.wardah_assert_org_member(v_work_order.org_id);

    -- حساب وقت الانتهاء المتوقع
    v_scheduled_end := p_scheduled_start +
        ((v_work_order.planned_setup_time + v_work_order.planned_run_time) * INTERVAL '1 minute');

    -- تحديث أمر العمل
    UPDATE work_orders SET
        planned_start_date = p_scheduled_start,
        planned_end_date = v_scheduled_end,
        updated_at = NOW()
    WHERE id = p_work_order_id;

    -- إذا تم تحديد جدول
    IF p_schedule_id IS NOT NULL THEN
        -- الحصول على التسلسل التالي
        SELECT COALESCE(MAX(schedule_sequence), 0) + 1 INTO v_sequence
        FROM schedule_details WHERE schedule_id = p_schedule_id;

        -- إدراج تفاصيل الجدولة
        INSERT INTO schedule_details (
            org_id, schedule_id, work_order_id, schedule_sequence,
            scheduled_start, scheduled_end, priority, schedule_status
        ) VALUES (
            v_work_order.org_id, p_schedule_id, p_work_order_id, v_sequence,
            p_scheduled_start, v_scheduled_end, v_work_order.priority, 'SCHEDULED'
        )
        ON CONFLICT (schedule_id, work_order_id)
        DO UPDATE SET
            scheduled_start = EXCLUDED.scheduled_start,
            scheduled_end = EXCLUDED.scheduled_end,
            updated_at = NOW()
        RETURNING * INTO v_result;

        RETURN v_result;
    END IF;

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.search_accounts(p_org_id uuid, p_search_term character varying)
 RETURNS TABLE(account_id uuid, code character varying, name character varying, category character varying, subtype character varying)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        id,
        gl_accounts.code,
        gl_accounts.name,
        gl_accounts.category,
        gl_accounts.subtype
    FROM gl_accounts
    WHERE gl_accounts.org_id = p_org_id
    AND is_active = true
    AND (
        LOWER(gl_accounts.code) LIKE LOWER('%' || p_search_term || '%')
        OR LOWER(gl_accounts.name) LIKE LOWER('%' || p_search_term || '%')
    )
    ORDER BY gl_accounts.code
    LIMIT 50;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.select_optimal_bom(p_item_id uuid, p_quantity numeric, p_order_date date DEFAULT CURRENT_DATE, p_org_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_selected_bom_id UUID;
    v_primary_bom_id UUID;
    v_alternative_bom_id UUID;
    v_rule bom_selection_rules%ROWTYPE;
    v_condition_met BOOLEAN;
    v_min_cost NUMERIC;
    v_bom_cost NUMERIC;
    v_primary_cost NUMERIC;
BEGIN
    -- البحث عن BOM الأساسي
    SELECT id INTO v_primary_bom_id
    FROM bom_headers
    WHERE item_id = p_item_id
    AND is_active = true
    AND status = 'APPROVED'
    AND (p_org_id IS NULL OR org_id = p_org_id)
    ORDER BY bom_version DESC, effective_date DESC
    LIMIT 1;

    IF v_primary_bom_id IS NULL THEN
        RAISE EXCEPTION 'No active BOM found for item';
    END IF;

    -- حساب تكلفة BOM الأساسي
    SELECT COALESCE(calculate_bom_cost(v_primary_bom_id, p_quantity), 0) INTO v_primary_cost;
    v_min_cost := v_primary_cost;
    v_selected_bom_id := v_primary_bom_id;

    -- البحث عن BOMs بديلة
    FOR v_alternative_bom_id IN
        SELECT alternative_bom_id
        FROM bom_alternatives
        WHERE primary_bom_id = v_primary_bom_id
        AND is_active = true
        AND (p_org_id IS NULL OR org_id = p_org_id)
        AND (min_quantity IS NULL OR p_quantity >= min_quantity)
        AND (max_quantity IS NULL OR p_quantity <= max_quantity)
        AND (effective_from IS NULL OR p_order_date >= effective_from)
        AND (effective_to IS NULL OR p_order_date <= effective_to)
        ORDER BY priority, is_default DESC
    LOOP
        -- التحقق من القواعد
        v_condition_met := true; -- افتراضياً، الشرط محقق
        
        -- تقييم القواعد (مبسط - يمكن تطويره)
        FOR v_rule IN
            SELECT * FROM bom_selection_rules
            WHERE org_id = p_org_id
            AND is_active = true
            ORDER BY priority
        LOOP
            -- تقييم الشرط بناءً على rule_type
            IF v_rule.rule_type = 'COST' THEN
                -- اختيار BOM الأقل تكلفة
                SELECT COALESCE(calculate_bom_cost(v_alternative_bom_id, p_quantity), 0) INTO v_bom_cost;
                
                IF v_bom_cost < v_min_cost THEN
                    v_min_cost := v_bom_cost;
                    v_selected_bom_id := v_alternative_bom_id;
                END IF;
            ELSIF v_rule.rule_type = 'QUANTITY' THEN
                -- التحقق من شروط الكمية
                v_condition_met := true; -- TODO: تقييم condition_json
            ELSE
                v_condition_met := true;
            END IF;
        END LOOP;
        
        -- إذا لم تكن هناك قواعد، استخدم BOM الأقل تكلفة
        IF NOT EXISTS (SELECT 1 FROM bom_selection_rules WHERE org_id = p_org_id AND is_active = true) THEN
            SELECT COALESCE(calculate_bom_cost(v_alternative_bom_id, p_quantity), 0) INTO v_bom_cost;
            
            IF v_bom_cost < v_min_cost THEN
                v_min_cost := v_bom_cost;
                v_selected_bom_id := v_alternative_bom_id;
            END IF;
        END IF;
    END LOOP;

    RETURN v_selected_bom_id;
END;
$function$
;

