CREATE OR REPLACE FUNCTION public.simulate_cogs(p_product_id uuid, p_quantity numeric)
 RETURNS TABLE(method character varying, cogs numeric, avg_rate numeric, remaining_qty numeric, remaining_value numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_product RECORD;
  v_remaining DECIMAL(18, 6);
  v_total_cost DECIMAL(18, 6);
  v_batch JSONB;
BEGIN
  -- Get product details
  SELECT * INTO v_product
  FROM products
  WHERE id = p_product_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Product not found';
  END IF;
  
  IF v_product.stock_quantity < p_quantity THEN
    RAISE EXCEPTION 'Insufficient stock';
  END IF;
  
  -- Initialize
  v_remaining := p_quantity;
  v_total_cost := 0;
  
  -- FIFO Simulation (from start of queue)
  IF v_product.valuation_method = 'FIFO' THEN
    FOR v_batch IN 
      SELECT value 
      FROM jsonb_array_elements(v_product.stock_queue)
      ORDER BY ordinality
    LOOP
      IF v_remaining <= 0 THEN EXIT; END IF;
      
      DECLARE
        batch_qty DECIMAL := (v_batch->>'qty')::DECIMAL;
        batch_rate DECIMAL := (v_batch->>'rate')::DECIMAL;
        take_qty DECIMAL;
      BEGIN
        take_qty := LEAST(batch_qty, v_remaining);
        v_total_cost := v_total_cost + (take_qty * batch_rate);
        v_remaining := v_remaining - take_qty;
      END;
    END LOOP;
  
  -- LIFO Simulation (from end of queue)
  ELSIF v_product.valuation_method = 'LIFO' THEN
    FOR v_batch IN 
      SELECT value 
      FROM jsonb_array_elements(v_product.stock_queue)
      ORDER BY ordinality DESC
    LOOP
      IF v_remaining <= 0 THEN EXIT; END IF;
      
      DECLARE
        batch_qty DECIMAL := (v_batch->>'qty')::DECIMAL;
        batch_rate DECIMAL := (v_batch->>'rate')::DECIMAL;
        take_qty DECIMAL;
      BEGIN
        take_qty := LEAST(batch_qty, v_remaining);
        v_total_cost := v_total_cost + (take_qty * batch_rate);
        v_remaining := v_remaining - take_qty;
      END;
    END LOOP;
  
  -- Weighted Average (simple calculation)
  ELSE
    v_total_cost := p_quantity * v_product.cost_price;
  END IF;
  
  -- Return results
  RETURN QUERY SELECT 
    v_product.valuation_method,
    v_total_cost as cogs,
    (v_total_cost / p_quantity) as avg_rate,
    (v_product.stock_quantity - p_quantity) as remaining_qty,
    (v_product.stock_value - v_total_cost) as remaining_value;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.start_operation(p_work_order_id uuid, p_operator_id uuid DEFAULT NULL::uuid, p_is_setup boolean DEFAULT true)
 RETURNS work_orders
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_work_order work_orders;
    v_event_type VARCHAR;
BEGIN
    -- التحقق من حالة أمر العمل
    SELECT * INTO v_work_order FROM work_orders WHERE id = p_work_order_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Work order not found: %', p_work_order_id;
    END IF;

    -- [120] حارس عضوية على مؤسسة أمر العمل
    PERFORM public.wardah_assert_org_member(v_work_order.org_id);

    IF v_work_order.status NOT IN ('PENDING', 'READY', 'ON_HOLD') THEN
        RAISE EXCEPTION 'Work order cannot be started. Current status: %', v_work_order.status;
    END IF;

    -- تحديد نوع الحدث
    IF p_is_setup THEN
        v_event_type := 'SETUP_START';
    ELSE
        v_event_type := 'PRODUCTION_START';
    END IF;

    -- تحديث أمر العمل
    UPDATE work_orders SET
        status = CASE WHEN p_is_setup THEN 'IN_SETUP' ELSE 'IN_PROGRESS' END,
        actual_start_date = COALESCE(actual_start_date, NOW()),
        current_operator_id = COALESCE(p_operator_id, auth.uid()),
        updated_at = NOW()
    WHERE id = p_work_order_id
    RETURNING * INTO v_work_order;

    -- تسجيل الحدث
    INSERT INTO operation_execution_logs (
        org_id, work_order_id, event_type, operator_id, event_timestamp
    ) VALUES (
        v_work_order.org_id, p_work_order_id, v_event_type,
        COALESCE(p_operator_id, auth.uid()), NOW()
    );

    -- بدء تسجيل الوقت
    INSERT INTO labor_time_tracking (
        org_id, work_order_id, employee_id, labor_type, clock_in, status
    ) VALUES (
        v_work_order.org_id, p_work_order_id, COALESCE(p_operator_id, auth.uid()),
        CASE WHEN p_is_setup THEN 'SETUP' ELSE 'DIRECT' END, NOW(), 'ACTIVE'
    );

    RETURN v_work_order;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.translate_amount(p_amount numeric, p_from_currency text, p_to_currency text, p_rate_date date DEFAULT CURRENT_DATE)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_rate NUMERIC(18,6);
BEGIN
    v_rate := get_exchange_rate(p_from_currency, p_to_currency, p_rate_date);
    RETURN p_amount * v_rate;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trg_gl_entries_period_guard()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    IF TG_OP = 'INSERT' THEN
        -- قيد جديد في فترة مقفلة؟
        PERFORM assert_period_open(NEW.org_id, NEW.entry_date);

    ELSIF TG_OP = 'UPDATE' THEN
        -- ترحيل قيد (draft → posted) في فترة مقفلة؟
        IF NEW.status IS DISTINCT FROM OLD.status AND NEW.status = 'posted' THEN
            PERFORM assert_period_open(NEW.org_id, NEW.entry_date);
        END IF;
        -- نقل قيد إلى تاريخ في فترة مقفلة؟
        IF NEW.entry_date IS DISTINCT FROM OLD.entry_date THEN
            PERFORM assert_period_open(NEW.org_id, NEW.entry_date);
        END IF;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trg_mo_status_machine()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
    v_norm_status TEXT;
BEGIN
    v_norm_status := normalize_mo_status(NEW.status);
    PERFORM validate_mo_transition(OLD.status, v_norm_status);
    NEW.status := v_norm_status;

    IF v_norm_status = 'in_progress' AND OLD.start_date IS NULL THEN
        NEW.start_date := NOW();
    END IF;

    IF v_norm_status IN ('done', 'cancelled') AND OLD.completed_date IS NULL THEN
        NEW.completed_date := NOW();
    END IF;

    NEW.updated_at := NOW();
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.trigger_update_load_on_work_order_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
