    PERFORM update_work_center_load(
        COALESCE(NEW.work_center_id, OLD.work_center_id),
        DATE_TRUNC('week', CURRENT_DATE)::DATE,
        (DATE_TRUNC('week', CURRENT_DATE) + INTERVAL '6 days')::DATE
    );
