END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_adjustment_totals()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
  UPDATE stock_adjustments
  SET 
    total_items = (
      SELECT COUNT(*) 
      FROM stock_adjustment_items 
      WHERE adjustment_id = COALESCE(NEW.adjustment_id, OLD.adjustment_id)
    ),
    total_qty_difference = (
      SELECT COALESCE(SUM(difference_qty), 0)
      FROM stock_adjustment_items
      WHERE adjustment_id = COALESCE(NEW.adjustment_id, OLD.adjustment_id)
    ),
    total_value_difference = (
      SELECT COALESCE(SUM(value_difference), 0)
      FROM stock_adjustment_items
      WHERE adjustment_id = COALESCE(NEW.adjustment_id, OLD.adjustment_id)
    ),
    updated_at = NOW()
  WHERE id = COALESCE(NEW.adjustment_id, OLD.adjustment_id);
  
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_bom_where_used()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    -- عند إضافة أو تحديث bom_lines، حدّث جدول where_used
    IF (TG_OP = 'INSERT' OR TG_OP = 'UPDATE') THEN
        INSERT INTO bom_where_used (component_id, parent_bom_id, parent_item_id, quantity_per, org_id)
        SELECT 
            NEW.item_id,
            NEW.bom_id,
            bh.item_id,
            NEW.quantity,
            NEW.org_id
        FROM bom_headers bh
        WHERE bh.id = NEW.bom_id
        ON CONFLICT (component_id, parent_bom_id) 
        DO UPDATE SET 
            quantity_per = EXCLUDED.quantity_per,
            updated_at = NOW();
            
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM bom_where_used 
        WHERE component_id = OLD.item_id 
        AND parent_bom_id = OLD.bom_id;
    END IF;
    
    RETURN COALESCE(NEW, OLD);
END;
$function$
;

