CREATE OR REPLACE FUNCTION public.update_mo_status_from_work_orders()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_total_work_orders INTEGER;
    v_completed_work_orders INTEGER;
    v_in_progress_work_orders INTEGER;
    v_total_completed DECIMAL;
    v_mo_quantity DECIMAL;
BEGIN
    -- الحصول على إحصائيات أوامر العمل
    SELECT 
        COUNT(*),
        COUNT(*) FILTER (WHERE status = 'COMPLETED'),
        COUNT(*) FILTER (WHERE status IN ('IN_SETUP', 'IN_PROGRESS'))
    INTO v_total_work_orders, v_completed_work_orders, v_in_progress_work_orders
    FROM work_orders
    WHERE mo_id = NEW.mo_id;
    
    -- الحصول على الكمية المكتملة والكمية المطلوبة
    SELECT 
        COALESCE(SUM(completed_quantity), 0),
        mo.quantity
    INTO v_total_completed, v_mo_quantity
    FROM work_orders wo
    JOIN manufacturing_orders mo ON wo.mo_id = mo.id
    WHERE wo.mo_id = NEW.mo_id
    GROUP BY mo.quantity;
    
    -- تحديث حالة أمر التصنيع
    IF v_completed_work_orders = v_total_work_orders AND v_total_work_orders > 0 THEN
        -- جميع أوامر العمل مكتملة
        UPDATE manufacturing_orders SET
            status = 'COMPLETED',
            actual_end_date = NOW(),
            updated_at = NOW()
        WHERE id = NEW.mo_id
        AND status != 'COMPLETED';
    ELSIF v_in_progress_work_orders > 0 THEN
        -- يوجد أوامر عمل قيد التنفيذ
        UPDATE manufacturing_orders SET
            status = 'IN_PROGRESS',
            updated_at = NOW()
        WHERE id = NEW.mo_id
        AND status NOT IN ('IN_PROGRESS', 'COMPLETED');
    END IF;
    
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_org_users_count()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE organizations 
        SET current_users_count = current_users_count + 1
        WHERE id = NEW.org_id;
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        UPDATE organizations 
        SET current_users_count = current_users_count - 1
        WHERE id = OLD.org_id;
        RETURN OLD;
    END IF;
    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_organization_profile(p_org_id uuid, p_name character varying DEFAULT NULL::character varying, p_name_ar character varying DEFAULT NULL::character varying, p_name_en character varying DEFAULT NULL::character varying, p_tax_number character varying DEFAULT NULL::character varying, p_commercial_registration character varying DEFAULT NULL::character varying, p_license_number character varying DEFAULT NULL::character varying, p_phone character varying DEFAULT NULL::character varying, p_mobile character varying DEFAULT NULL::character varying, p_email character varying DEFAULT NULL::character varying, p_website character varying DEFAULT NULL::character varying, p_fax character varying DEFAULT NULL::character varying, p_address text DEFAULT NULL::text, p_city character varying DEFAULT NULL::character varying, p_state character varying DEFAULT NULL::character varying, p_country character varying DEFAULT NULL::character varying, p_postal_code character varying DEFAULT NULL::character varying, p_logo_url text DEFAULT NULL::text, p_primary_color character varying DEFAULT NULL::character varying, p_secondary_color character varying DEFAULT NULL::character varying, p_currency character varying DEFAULT NULL::character varying, p_timezone character varying DEFAULT NULL::character varying)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_user_id UUID;
    v_user_role VARCHAR(50);
    v_result JSONB;
    v_is_authorized BOOLEAN;
BEGIN
    -- الحصول على المستخدم الحالي
    v_user_id := auth.uid();
    
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'غير مصرح');
    END IF;
    
    -- ⚠️ INPUT VALIDATION: Validate formats for security
    -- Email format validation
    IF p_email IS NOT NULL AND p_email <> '' AND p_email !~* '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$' THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'صيغة البريد الإلكتروني غير صحيحة');
    END IF;

    -- Website URL format validation
    IF p_website IS NOT NULL AND p_website <> '' AND p_website !~* '^https?://[A-Za-z0-9.-]+(\:[0-9]+)?(/.*)?$' THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'صيغة الموقع الإلكتروني غير صحيحة');
    END IF;

    -- Logo URL format validation
    IF p_logo_url IS NOT NULL AND p_logo_url <> '' AND p_logo_url !~* '^https?://[A-Za-z0-9.-]+(\:[0-9]+)?(/.*)?$' THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'صيغة رابط الشعار غير صحيحة');
    END IF;

    -- Primary color hex code validation
    IF p_primary_color IS NOT NULL AND p_primary_color <> '' AND p_primary_color !~* '^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$' THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'صيغة كود اللون الأساسي غير صحيحة');
    END IF;

    -- Secondary color hex code validation
    IF p_secondary_color IS NOT NULL AND p_secondary_color <> '' AND p_secondary_color !~* '^#([A-Fa-f0-9]{6}|[A-Fa-f0-9]{3})$' THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'صيغة كود اللون الثانوي غير صحيحة');
    END IF;

    -- التحقق من صلاحية المستخدم
    SELECT role INTO v_user_role
    FROM user_organizations
    WHERE user_id = v_user_id 
      AND org_id = p_org_id 
      AND is_active;
    
    v_is_authorized := v_user_role IS NOT NULL AND v_user_role IN ('admin', 'manager');
    
    IF NOT v_is_authorized THEN
        RETURN jsonb_build_object('success', FALSE, 'error', 'ليس لديك صلاحية لتعديل بيانات المؤسسة');
    END IF;
    
    -- تحديث البيانات
    UPDATE organizations SET
        name = COALESCE(p_name, name),
        name_ar = COALESCE(p_name_ar, name_ar),
        name_en = COALESCE(p_name_en, name_en),
        tax_number = COALESCE(p_tax_number, tax_number),
        commercial_registration = COALESCE(p_commercial_registration, commercial_registration),
        license_number = COALESCE(p_license_number, license_number),
        phone = COALESCE(p_phone, phone),
        mobile = COALESCE(p_mobile, mobile),
        email = COALESCE(p_email, email),
        website = COALESCE(p_website, website),
        fax = COALESCE(p_fax, fax),
        address = COALESCE(p_address, address),
        city = COALESCE(p_city, city),
        state = COALESCE(p_state, state),
        country = COALESCE(p_country, country),
        postal_code = COALESCE(p_postal_code, postal_code),
        logo_url = COALESCE(p_logo_url, logo_url),
        primary_color = COALESCE(p_primary_color, primary_color),
        secondary_color = COALESCE(p_secondary_color, secondary_color),
        currency = COALESCE(p_currency, currency),
        timezone = COALESCE(p_timezone, timezone),
        updated_at = NOW()
    WHERE id = p_org_id;
    
    -- إرجاع البيانات المحدثة
    SELECT jsonb_build_object(
        'success', TRUE,
        'data', row_to_json(o.*)
    ) INTO v_result
    FROM organizations o
    WHERE o.id = p_org_id;
    
    RETURN v_result;
END;
$function$
;

