CREATE OR REPLACE FUNCTION public.update_warehouse_gl_mapping(p_warehouse_id uuid, p_org_id uuid, p_stock_account uuid DEFAULT NULL::uuid, p_stock_adjustment_account uuid DEFAULT NULL::uuid, p_expense_account uuid DEFAULT NULL::uuid, p_cogs_account uuid DEFAULT NULL::uuid, p_cost_center uuid DEFAULT NULL::uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    -- Update warehouse main accounts
    UPDATE warehouses
    SET 
        inventory_account_id = COALESCE(p_stock_account, inventory_account_id),
        expense_account_id = COALESCE(p_expense_account, expense_account_id),
        cost_center_id = COALESCE(p_cost_center, cost_center_id),
        updated_at = CURRENT_TIMESTAMP
    WHERE id = p_warehouse_id;
    
    -- Insert or update GL mapping
    INSERT INTO warehouse_gl_mapping (
        warehouse_id,
        org_id,
        stock_account,
        stock_adjustment_account,
        expenses_included_in_valuation,
        default_cogs_account,
        cost_center
    ) VALUES (
        p_warehouse_id,
        p_org_id,
        p_stock_account,
        p_stock_adjustment_account,
        p_expense_account,
        p_cogs_account,
        p_cost_center
    )
    ON CONFLICT (warehouse_id) DO UPDATE SET
        stock_account = COALESCE(EXCLUDED.stock_account, warehouse_gl_mapping.stock_account),
        stock_adjustment_account = COALESCE(EXCLUDED.stock_adjustment_account, warehouse_gl_mapping.stock_adjustment_account),
        expenses_included_in_valuation = COALESCE(EXCLUDED.expenses_included_in_valuation, warehouse_gl_mapping.expenses_included_in_valuation),
        default_cogs_account = COALESCE(EXCLUDED.default_cogs_account, warehouse_gl_mapping.default_cogs_account),
        cost_center = COALESCE(EXCLUDED.cost_center, warehouse_gl_mapping.cost_center),
        updated_at = CURRENT_TIMESTAMP;
    
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'Error updating warehouse GL mapping: %', SQLERRM;
    RETURN FALSE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_work_center_load(p_work_center_id uuid, p_start_date date, p_end_date date)
 RETURNS work_center_load
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org_id UUID;
    v_capacity RECORD;
    v_load RECORD;
    v_result work_center_load;
BEGIN
    -- الحصول على org_id
    SELECT org_id INTO v_org_id FROM work_centers WHERE id = p_work_center_id;

    -- [120] حارس عضوية على مؤسسة مركز العمل
    IF v_org_id IS NULL THEN
        RAISE EXCEPTION 'Work center not found: %', p_work_center_id;
    END IF;
    PERFORM public.wardah_assert_org_member(v_org_id);

    -- حساب الطاقة المتاحة
    SELECT * INTO v_capacity FROM calculate_available_capacity(p_work_center_id, p_start_date, p_end_date);

    -- حساب الحمل المخطط
    SELECT * INTO v_load FROM calculate_planned_load(p_work_center_id, p_start_date, p_end_date);

    -- إدراج أو تحديث السجل
    INSERT INTO work_center_load (
        org_id, work_center_id, period_start, period_end,
        available_capacity_hours, planned_load_hours,
        utilization_pct, planned_work_orders, status, calculated_at
    ) VALUES (
        v_org_id, p_work_center_id, p_start_date, p_end_date,
        v_capacity.total_available_hours, v_load.total_planned_hours,
        CASE
            WHEN v_capacity.total_available_hours > 0
            THEN ROUND((v_load.total_planned_hours / v_capacity.total_available_hours * 100)::NUMERIC, 2)
            ELSE 0
        END,
        v_load.total_work_orders, 'PLANNED', NOW()
    )
    ON CONFLICT (work_center_id, period_start, period_end)
    DO UPDATE SET
        available_capacity_hours = EXCLUDED.available_capacity_hours,
        planned_load_hours = EXCLUDED.planned_load_hours,
        utilization_pct = EXCLUDED.utilization_pct,
        planned_work_orders = EXCLUDED.planned_work_orders,
        calculated_at = NOW(),
        updated_at = NOW()
    RETURNING * INTO v_result;

    RETURN v_result;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.upsert_attendance_day(p_org_id uuid, p_employee_id uuid, p_year smallint, p_month smallint, p_day text, p_payload jsonb)
 RETURNS hr_attendance_monthly
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org UUID;
    v_row hr_attendance_monthly;
BEGIN
    -- اشتقاق آمن: القيمة الصريحة تُقبل فقط إن كان المستخدم عضواً فيها
    v_org := wardah_org_id(p_org_id);
    IF v_org IS NULL THEN
        RAISE EXCEPTION 'ORG_NOT_RESOLVED';
    END IF;
    IF NOT EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = auth.uid() AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'NOT_ORG_MEMBER';
    END IF;

    -- الموظف يجب أن يتبع نفس المؤسسة
    IF NOT EXISTS (
        SELECT 1 FROM employees WHERE id = p_employee_id AND org_id = v_org
    ) THEN
        RAISE EXCEPTION 'EMPLOYEE_NOT_FOUND';
    END IF;

    -- شهر مقفل ⇒ لا تعديل حضور
    IF EXISTS (
        SELECT 1 FROM hr_payroll_locks
        WHERE org_id = v_org AND year = p_year AND month = p_month
          AND status = 'locked'
    ) THEN
        RAISE EXCEPTION 'PAYROLL_MONTH_LOCKED';
    END IF;

    INSERT INTO hr_attendance_monthly (org_id, employee_id, year, month, days, updated_by)
    VALUES (v_org, p_employee_id, p_year, p_month,
            jsonb_build_object(p_day, p_payload), auth.uid())
    ON CONFLICT (org_id, employee_id, year, month) DO UPDATE SET
        days       = hr_attendance_monthly.days || jsonb_build_object(p_day, p_payload),
        updated_by = auth.uid(),
        updated_at = NOW()
    RETURNING * INTO v_row;

    RETURN v_row;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.upsert_stage_cost(p_tenant uuid, p_mo uuid, p_stage integer, p_wc uuid, p_good_qty numeric, p_dm numeric DEFAULT 0, p_mode text DEFAULT 'precosted'::text, p_scrap_qty numeric DEFAULT 0, p_rework_qty numeric DEFAULT 0, p_input_qty numeric DEFAULT NULL::numeric, p_notes text DEFAULT NULL::text, p_wip_end_qty numeric DEFAULT 0, p_wip_end_dm_completion_pct numeric DEFAULT 0, p_wip_end_cc_completion_pct numeric DEFAULT 0, p_regrind_cost numeric DEFAULT 0, p_waste_credit numeric DEFAULT 0, p_wip_beginning_qty numeric DEFAULT 0, p_wip_beginning_dm_completion_pct numeric DEFAULT 0, p_wip_beginning_cc_completion_pct numeric DEFAULT 0, p_wip_beginning_cost numeric DEFAULT 0)
 RETURNS TABLE(stage_id uuid, total_cost numeric, unit_cost numeric, transferred_in numeric, labor_cost numeric, overhead_cost numeric, eup numeric, normal_scrap_cost numeric, abnormal_scrap_cost numeric, costing_method text, wip_beginning_cost numeric, current_period_cost numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    -- [120] حارس عضوية على p_tenant قبل تفويض النواة (النواة تحتفظ بفحص
    -- get_current_tenant_id القديم — الغلاف يغلق ثغرة السقوط للمؤسسة الافتراضية)
    PERFORM public.wardah_assert_org_member(p_tenant);
    RETURN QUERY SELECT * FROM public.upsert_stage_cost_core(
        p_tenant, p_mo, p_stage, p_wc, p_good_qty, p_dm, p_mode,
        p_scrap_qty, p_rework_qty, p_input_qty, p_notes,
        p_wip_end_qty, p_wip_end_dm_completion_pct, p_wip_end_cc_completion_pct,
        p_regrind_cost, p_waste_credit,
        p_wip_beginning_qty, p_wip_beginning_dm_completion_pct,
        p_wip_beginning_cc_completion_pct, p_wip_beginning_cost
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.upsert_stage_cost_core(p_tenant uuid, p_mo uuid, p_stage integer, p_wc uuid, p_good_qty numeric, p_dm numeric DEFAULT 0, p_mode text DEFAULT 'precosted'::text, p_scrap_qty numeric DEFAULT 0, p_rework_qty numeric DEFAULT 0, p_input_qty numeric DEFAULT NULL::numeric, p_notes text DEFAULT NULL::text, p_wip_end_qty numeric DEFAULT 0, p_wip_end_dm_completion_pct numeric DEFAULT 0, p_wip_end_cc_completion_pct numeric DEFAULT 0, p_regrind_cost numeric DEFAULT 0, p_waste_credit numeric DEFAULT 0, p_wip_beginning_qty numeric DEFAULT 0, p_wip_beginning_dm_completion_pct numeric DEFAULT 0, p_wip_beginning_cc_completion_pct numeric DEFAULT 0, p_wip_beginning_cost numeric DEFAULT 0)
 RETURNS TABLE(stage_id uuid, total_cost numeric, unit_cost numeric, transferred_in numeric, labor_cost numeric, overhead_cost numeric, eup numeric, normal_scrap_cost numeric, abnormal_scrap_cost numeric, costing_method text, wip_beginning_cost numeric, current_period_cost numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  -- Constants
  C_SCHEMA_PUBLIC CONSTANT TEXT := 'public';
  C_COL_TENANT_ID CONSTANT TEXT := 'tenant_id';
  C_COL_ORG_ID CONSTANT TEXT := 'org_id';
  C_COL_MO_ID CONSTANT TEXT := 'mo_id';
  C_COL_MANUFACTURING_ORDER_ID CONSTANT TEXT := 'manufacturing_order_id';
  C_TABLE_WORK_CENTERS CONSTANT TEXT := 'work_centers';
  C_TABLE_STAGE_COSTS CONSTANT TEXT := 'stage_costs';
  C_TABLE_MANUFACTURING_ORDERS CONSTANT TEXT := 'manufacturing_orders';
  C_METHOD_WEIGHTED_AVG CONSTANT TEXT := 'weighted_average';
  C_METHOD_FIFO CONSTANT TEXT := 'fifo';
  
  v_ti NUMERIC := 0;
  v_dl NUMERIC := 0;
  v_oh NUMERIC := 0;
  v_rg NUMERIC := 0;
  v_wc NUMERIC := 0;
  v_total NUMERIC;
  v_unit NUMERIC;
  v_stage_id UUID;
  v_current_tenant UUID;
  
  -- EUP calculation variables
  v_eup_dm NUMERIC := 0;
  v_eup_cc NUMERIC := 0;
  v_eup NUMERIC := 0;
  
  -- Scrap accounting variables
  v_normal_scrap_rate NUMERIC := 0;
  v_normal_scrap_qty NUMERIC := 0;
  v_abnormal_scrap_qty NUMERIC := 0;
  v_normal_scrap_cost NUMERIC := 0;
  v_abnormal_scrap_cost NUMERIC := 0;
  v_unit_cost_before_scrap NUMERIC := 0;
  
  -- FIFO variables
  v_costing_method TEXT := C_METHOD_WEIGHTED_AVG;
  v_wip_beginning_cost NUMERIC := 0;
  v_current_period_cost NUMERIC := 0;
  v_wip_beginning_eup_dm NUMERIC := 0;
  v_wip_beginning_eup_cc NUMERIC := 0;
  
  -- Column name detection
  v_tenant_col TEXT;
  v_mo_col TEXT;
BEGIN
  -- Validate tenant access
  v_current_tenant := get_current_tenant_id();
  IF v_current_tenant IS NULL OR v_current_tenant != p_tenant THEN
    RAISE EXCEPTION 'Access denied: Invalid tenant context';
  END IF;

  -- Validate parameters
  IF p_stage <= 0 THEN
    RAISE EXCEPTION 'Stage number must be positive';
  END IF;
  
  IF p_good_qty < 0 THEN
    RAISE EXCEPTION 'Good quantity cannot be negative';
  END IF;
  
  IF p_wip_end_qty < 0 THEN
    RAISE EXCEPTION 'WIP ending quantity cannot be negative';
  END IF;
  
  IF p_wip_beginning_qty < 0 THEN
    RAISE EXCEPTION 'WIP beginning quantity cannot be negative';
  END IF;
  
  IF p_wip_end_dm_completion_pct < 0 OR p_wip_end_dm_completion_pct > 100 THEN
    RAISE EXCEPTION 'WIP DM completion percentage must be between 0 and 100';
  END IF;
  
  IF p_wip_end_cc_completion_pct < 0 OR p_wip_end_cc_completion_pct > 100 THEN
    RAISE EXCEPTION 'WIP CC completion percentage must be between 0 and 100';
  END IF;
  
  IF p_wip_beginning_dm_completion_pct < 0 OR p_wip_beginning_dm_completion_pct > 100 THEN
    RAISE EXCEPTION 'WIP beginning DM completion percentage must be between 0 and 100';
  END IF;
  
  IF p_wip_beginning_cc_completion_pct < 0 OR p_wip_beginning_cc_completion_pct > 100 THEN
    RAISE EXCEPTION 'WIP beginning CC completion percentage must be between 0 and 100';
  END IF;
  
  IF p_scrap_qty < 0 THEN
    RAISE EXCEPTION 'Scrap quantity cannot be negative';
  END IF;
  
  IF p_regrind_cost < 0 THEN
    RAISE EXCEPTION 'Regrind cost cannot be negative';
  END IF;
  
  IF p_waste_credit < 0 THEN
    RAISE EXCEPTION 'Waste credit cannot be negative';
  END IF;
  
  IF p_wip_beginning_cost < 0 THEN
    RAISE EXCEPTION 'WIP beginning cost cannot be negative';
  END IF;

  -- Detect column names dynamically
  SELECT column_name INTO v_tenant_col
  FROM information_schema.columns
  WHERE table_schema = C_SCHEMA_PUBLIC
  AND table_name = C_TABLE_WORK_CENTERS
  AND column_name IN (C_COL_TENANT_ID, C_COL_ORG_ID)
  ORDER BY CASE column_name WHEN C_COL_TENANT_ID THEN 1 WHEN C_COL_ORG_ID THEN 2 END
  LIMIT 1;
  
  -- Get normal scrap rate from work center
  IF v_tenant_col = C_COL_TENANT_ID THEN
    SELECT COALESCE(normal_scrap_rate, 0) INTO v_normal_scrap_rate
    FROM public.work_centers
    WHERE id = p_wc AND tenant_id = p_tenant AND is_active = true;
  ELSE
    SELECT COALESCE(normal_scrap_rate, 0) INTO v_normal_scrap_rate
    FROM public.work_centers
    WHERE id = p_wc AND org_id = p_tenant AND is_active = true;
  END IF;
  
  -- Validate work center exists
  IF v_normal_scrap_rate IS NULL THEN
    RAISE EXCEPTION 'Work center not found or not active for tenant';
  END IF;

  -- Get costing method from manufacturing order
  IF EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = C_SCHEMA_PUBLIC
    AND table_name = C_TABLE_MANUFACTURING_ORDERS 
    AND column_name = 'costing_method'
  ) THEN
    IF EXISTS (
      SELECT 1 FROM information_schema.columns 
      WHERE table_schema = C_SCHEMA_PUBLIC
      AND table_name = C_TABLE_MANUFACTURING_ORDERS 
      AND column_name = C_COL_TENANT_ID
    ) THEN
      SELECT COALESCE(costing_method, C_METHOD_WEIGHTED_AVG) INTO v_costing_method
      FROM public.manufacturing_orders
      WHERE id = p_mo AND tenant_id = p_tenant;
    ELSE
      SELECT COALESCE(costing_method, C_METHOD_WEIGHTED_AVG) INTO v_costing_method
      FROM public.manufacturing_orders
      WHERE id = p_mo AND org_id = p_tenant;
    END IF;
  END IF;
  
  -- Validate costing method
  IF v_costing_method NOT IN (C_METHOD_WEIGHTED_AVG, C_METHOD_FIFO) THEN
    v_costing_method := C_METHOD_WEIGHTED_AVG;
  END IF;

  -- Calculate input quantity if not provided
  IF p_input_qty IS NULL THEN
    p_input_qty := p_good_qty + COALESCE(p_scrap_qty, 0) + COALESCE(p_rework_qty, 0);
  END IF;

  -- Detect column names for stage_costs table
  SELECT column_name INTO v_tenant_col
  FROM information_schema.columns
  WHERE table_schema = C_SCHEMA_PUBLIC
  AND table_name = C_TABLE_STAGE_COSTS
  AND column_name IN (C_COL_TENANT_ID, C_COL_ORG_ID)
  ORDER BY CASE column_name WHEN C_COL_TENANT_ID THEN 1 WHEN C_COL_ORG_ID THEN 2 END
  LIMIT 1;
  
  SELECT column_name INTO v_mo_col
  FROM information_schema.columns
  WHERE table_schema = C_SCHEMA_PUBLIC
  AND table_name = C_TABLE_STAGE_COSTS
  AND column_name IN (C_COL_MO_ID, C_COL_MANUFACTURING_ORDER_ID)
  ORDER BY CASE column_name WHEN C_COL_MO_ID THEN 1 WHEN C_COL_MANUFACTURING_ORDER_ID THEN 2 END
  LIMIT 1;

  -- For stages > 1, get transferred-in cost from previous stage
  IF p_stage > 1 THEN
    IF v_tenant_col = C_COL_TENANT_ID AND v_mo_col = C_COL_MO_ID THEN
      SELECT COALESCE(total_cost, 0) INTO v_ti
      FROM public.stage_costs
      WHERE tenant_id = p_tenant 
        AND mo_id = p_mo 
        AND stage_no = p_stage - 1
      FOR UPDATE;
    ELSIF v_tenant_col = C_COL_ORG_ID AND v_mo_col = C_COL_MANUFACTURING_ORDER_ID THEN
      SELECT COALESCE(total_cost, 0) INTO v_ti
      FROM public.stage_costs
      WHERE org_id = p_tenant 
        AND manufacturing_order_id = p_mo 
        AND stage_number = p_stage - 1
      FOR UPDATE;
    ELSE
      BEGIN
        SELECT COALESCE(total_cost, 0) INTO v_ti
        FROM public.stage_costs
        WHERE (tenant_id = p_tenant OR org_id = p_tenant)
          AND (mo_id = p_mo OR manufacturing_order_id = p_mo)
          AND (stage_no = p_stage - 1 OR stage_number = p_stage - 1)
        LIMIT 1
        FOR UPDATE;
      EXCEPTION WHEN OTHERS THEN
        RAISE EXCEPTION 'Previous stage (%) not found or not completed', p_stage - 1;
      END;
    END IF;
    
    IF v_ti IS NULL THEN
      RAISE EXCEPTION 'Previous stage (%) not found or not completed', p_stage - 1;
    END IF;
  END IF;

  -- Calculate labor cost from labor time logs
  IF EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = C_SCHEMA_PUBLIC 
    AND table_name = 'labor_time_logs' 
    AND column_name = C_COL_TENANT_ID
  ) THEN
    SELECT COALESCE(SUM(hours * hourly_rate), 0) INTO v_dl
    FROM public.labor_time_logs
    WHERE tenant_id = p_tenant 
      AND mo_id = p_mo 
      AND stage_no = p_stage
      AND status = 'active';
  ELSE
    SELECT COALESCE(SUM(hours * hourly_rate), 0) INTO v_dl
    FROM public.labor_time_logs
    WHERE org_id = p_tenant 
      AND manufacturing_order_id = p_mo 
      AND stage_number = p_stage
      AND status = 'active';
  END IF;

  -- Calculate overhead cost from applied overhead
  IF EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = C_SCHEMA_PUBLIC 
    AND table_name = 'moh_applied' 
    AND column_name = C_COL_TENANT_ID
  ) THEN
    SELECT COALESCE(SUM(amount), 0) INTO v_oh
    FROM public.moh_applied
    WHERE tenant_id = p_tenant 
      AND mo_id = p_mo 
      AND stage_no = p_stage
      AND status = 'applied';
  ELSE
    SELECT COALESCE(SUM(amount), 0) INTO v_oh
    FROM public.moh_applied
    WHERE org_id = p_tenant 
      AND manufacturing_order_id = p_mo 
      AND stage_number = p_stage
      AND status = 'applied';
  END IF;

  -- Calculate regrind/reprocessing cost (from parameter)
  v_rg := COALESCE(p_regrind_cost, 0);

  -- Calculate waste credit (from parameter)
  v_wc := COALESCE(p_waste_credit, 0);

  -- ===================================================================
  -- SCRAP ACCOUNTING LOGIC
  -- ===================================================================
  
  -- Calculate normal vs abnormal scrap
  IF p_good_qty > 0 AND v_normal_scrap_rate > 0 THEN
    v_normal_scrap_qty := LEAST(
      p_good_qty * v_normal_scrap_rate / 100,
      COALESCE(p_scrap_qty, 0)
    );
    v_abnormal_scrap_qty := GREATEST(
      0,
      COALESCE(p_scrap_qty, 0) - v_normal_scrap_qty
    );
  ELSE
    v_normal_scrap_qty := 0;
    v_abnormal_scrap_qty := COALESCE(p_scrap_qty, 0);
  END IF;

  -- Calculate base costs (before scrap allocation)
  -- Total Cost = Transferred In + Direct Materials + Direct Labor + MOH + Regrind - Waste Credit
  v_total := v_ti + p_dm + v_dl + v_oh + v_rg - v_wc;

  -- ===================================================================
  -- EUP CALCULATION (Weighted-Average vs FIFO)
  -- ===================================================================
  
  IF v_costing_method = C_METHOD_FIFO THEN
    -- FIFO Method: Separate beginning WIP from current period
    
    -- Beginning WIP EUP (to be subtracted)
    IF p_stage = 1 THEN
      v_wip_beginning_eup_dm := COALESCE(p_wip_beginning_qty, 0) * COALESCE(p_wip_beginning_dm_completion_pct, 0) / 100;
    ELSE
      v_wip_beginning_eup_dm := 0; -- Stages > 1: DM already in transferred-in
    END IF;
    v_wip_beginning_eup_cc := COALESCE(p_wip_beginning_qty, 0) * COALESCE(p_wip_beginning_cc_completion_pct, 0) / 100;
    
    -- FIFO EUP = Units Completed + Ending WIP - Beginning WIP
    IF p_stage = 1 THEN
      v_eup_dm := p_good_qty + (COALESCE(p_wip_end_qty, 0) * COALESCE(p_wip_end_dm_completion_pct, 0) / 100) - v_wip_beginning_eup_dm;
    ELSE
      v_eup_dm := p_good_qty; -- Stages > 1: DM already in transferred-in
    END IF;
    v_eup_cc := p_good_qty + (COALESCE(p_wip_end_qty, 0) * COALESCE(p_wip_end_cc_completion_pct, 0) / 100) - v_wip_beginning_eup_cc;
    
    -- Use Conversion Costs EUP as primary
    v_eup := v_eup_cc;
    
    -- Separate beginning WIP cost from current period cost
    v_wip_beginning_cost := COALESCE(p_wip_beginning_cost, 0);
    v_current_period_cost := v_total; -- Current period costs only
    
    -- Calculate unit cost using current period costs only
    IF v_eup > 0 THEN
      v_unit_cost_before_scrap := v_current_period_cost / v_eup;
    ELSIF p_good_qty > 0 THEN
      v_unit_cost_before_scrap := v_current_period_cost / p_good_qty;
    ELSE
      v_unit_cost_before_scrap := 0;
    END IF;
    
  ELSE
    -- Weighted-Average Method: Combine beginning WIP + current costs
    
    -- Beginning WIP cost is included in total_cost (via transferred-in or parameter)
    IF p_stage = 1 AND COALESCE(p_wip_beginning_cost, 0) > 0 THEN
      -- Add beginning WIP cost to total for weighted-average
      v_total := v_total + COALESCE(p_wip_beginning_cost, 0);
    END IF;
    
    -- Weighted-Average EUP = Units Completed + Ending WIP
    IF p_stage = 1 THEN
      v_eup_dm := p_good_qty + (COALESCE(p_wip_end_qty, 0) * COALESCE(p_wip_end_dm_completion_pct, 0) / 100);
    ELSE
      v_eup_dm := p_good_qty;
    END IF;
    v_eup_cc := p_good_qty + (COALESCE(p_wip_end_qty, 0) * COALESCE(p_wip_end_cc_completion_pct, 0) / 100);
    v_eup := v_eup_cc;
    
    -- Beginning WIP cost is part of total_cost in weighted-average
    v_wip_beginning_cost := COALESCE(p_wip_beginning_cost, 0);
    v_current_period_cost := v_total - v_wip_beginning_cost;
    
    -- Calculate unit cost using total cost (includes beginning WIP)
    IF v_eup > 0 THEN
      v_unit_cost_before_scrap := v_total / v_eup;
    ELSIF p_good_qty > 0 THEN
      v_unit_cost_before_scrap := v_total / p_good_qty;
    ELSE
      v_unit_cost_before_scrap := 0;
    END IF;
  END IF;

  -- ===================================================================
  -- SCRAP COST ALLOCATION
  -- ===================================================================
  
  -- Normal scrap cost: allocated to good units (increases unit cost)
  IF v_normal_scrap_qty > 0 AND v_unit_cost_before_scrap > 0 THEN
    v_normal_scrap_cost := v_normal_scrap_qty * v_unit_cost_before_scrap;
    v_total := v_total + v_normal_scrap_cost;
  END IF;
  
  -- Abnormal scrap cost: charged to expense (period cost, not included in unit cost)
  IF v_abnormal_scrap_qty > 0 AND v_unit_cost_before_scrap > 0 THEN
    v_abnormal_scrap_cost := v_abnormal_scrap_qty * v_unit_cost_before_scrap;
  END IF;

  -- Calculate final unit cost (includes normal scrap cost)
  IF v_eup > 0 THEN
    v_unit := v_total / v_eup;
  ELSIF p_good_qty > 0 THEN
    v_unit := v_total / p_good_qty;
  ELSE
    v_unit := 0;
  END IF;

  -- Upsert stage cost record with FIFO support
  IF v_tenant_col = C_COL_TENANT_ID AND v_mo_col = C_COL_MO_ID THEN
    INSERT INTO public.stage_costs (
      tenant_id, mo_id, stage_no, wc_id,
      input_qty, good_qty, scrap_qty, rework_qty,
      transferred_in, dm_cost, dl_cost, moh_cost, regrind_proc_cost, waste_credit,
      total_cost, unit_cost, mode, notes,
      wip_end_qty, wip_end_dm_completion_pct, wip_end_cc_completion_pct,
      wip_beginning_qty, wip_beginning_dm_completion_pct, wip_beginning_cc_completion_pct,
      normal_scrap_qty, abnormal_scrap_qty, normal_scrap_cost, abnormal_scrap_cost,
      regrind_cost, waste_credit_amount,
      wip_beginning_cost, current_period_cost,
      created_by, updated_by
    ) VALUES (
      p_tenant, p_mo, p_stage, p_wc,
      p_input_qty, p_good_qty, COALESCE(p_scrap_qty, 0), COALESCE(p_rework_qty, 0),
      v_ti, p_dm, v_dl, v_oh, v_rg, v_wc,
      v_total, v_unit, p_mode, p_notes,
      COALESCE(p_wip_end_qty, 0), COALESCE(p_wip_end_dm_completion_pct, 0), COALESCE(p_wip_end_cc_completion_pct, 0),
      COALESCE(p_wip_beginning_qty, 0), COALESCE(p_wip_beginning_dm_completion_pct, 0), COALESCE(p_wip_beginning_cc_completion_pct, 0),
      v_normal_scrap_qty, v_abnormal_scrap_qty, v_normal_scrap_cost, v_abnormal_scrap_cost,
      v_rg, v_wc,
      v_wip_beginning_cost, v_current_period_cost,
      get_current_user_id(), get_current_user_id()
    )
    ON CONFLICT (tenant_id, mo_id, stage_no) DO UPDATE SET
      wc_id = EXCLUDED.wc_id,
      input_qty = EXCLUDED.input_qty,
      good_qty = EXCLUDED.good_qty,
      scrap_qty = EXCLUDED.scrap_qty,
      rework_qty = EXCLUDED.rework_qty,
      transferred_in = EXCLUDED.transferred_in,
      dm_cost = EXCLUDED.dm_cost,
      dl_cost = EXCLUDED.dl_cost,
      moh_cost = EXCLUDED.moh_cost,
      regrind_proc_cost = EXCLUDED.regrind_proc_cost,
      waste_credit = EXCLUDED.waste_credit,
      total_cost = EXCLUDED.total_cost,
      unit_cost = EXCLUDED.unit_cost,
      mode = EXCLUDED.mode,
      notes = EXCLUDED.notes,
      wip_end_qty = EXCLUDED.wip_end_qty,
      wip_end_dm_completion_pct = EXCLUDED.wip_end_dm_completion_pct,
      wip_end_cc_completion_pct = EXCLUDED.wip_end_cc_completion_pct,
      wip_beginning_qty = EXCLUDED.wip_beginning_qty,
      wip_beginning_dm_completion_pct = EXCLUDED.wip_beginning_dm_completion_pct,
      wip_beginning_cc_completion_pct = EXCLUDED.wip_beginning_cc_completion_pct,
      normal_scrap_qty = EXCLUDED.normal_scrap_qty,
      abnormal_scrap_qty = EXCLUDED.abnormal_scrap_qty,
      normal_scrap_cost = EXCLUDED.normal_scrap_cost,
      abnormal_scrap_cost = EXCLUDED.abnormal_scrap_cost,
      regrind_cost = EXCLUDED.regrind_cost,
      waste_credit_amount = EXCLUDED.waste_credit_amount,
      wip_beginning_cost = EXCLUDED.wip_beginning_cost,
      current_period_cost = EXCLUDED.current_period_cost,
      updated_at = now(),
      updated_by = get_current_user_id()
    RETURNING id INTO v_stage_id;
  ELSE
    -- Use org_id and manufacturing_order_id (similar structure)
    INSERT INTO public.stage_costs (
      org_id, manufacturing_order_id, stage_number, work_center_id,
      input_qty, good_qty, scrap_qty, rework_qty,
      transferred_in, dm_cost, dl_cost, moh_cost, regrind_proc_cost, waste_credit,
      total_cost, unit_cost, mode, notes,
      wip_end_qty, wip_end_dm_completion_pct, wip_end_cc_completion_pct,
      wip_beginning_qty, wip_beginning_dm_completion_pct, wip_beginning_cc_completion_pct,
      normal_scrap_qty, abnormal_scrap_qty, normal_scrap_cost, abnormal_scrap_cost,
      regrind_cost, waste_credit_amount,
      wip_beginning_cost, current_period_cost,
      created_by, updated_by
    ) VALUES (
      p_tenant, p_mo, p_stage, p_wc,
      p_input_qty, p_good_qty, COALESCE(p_scrap_qty, 0), COALESCE(p_rework_qty, 0),
      v_ti, p_dm, v_dl, v_oh, v_rg, v_wc,
      v_total, v_unit, p_mode, p_notes,
      COALESCE(p_wip_end_qty, 0), COALESCE(p_wip_end_dm_completion_pct, 0), COALESCE(p_wip_end_cc_completion_pct, 0),
      COALESCE(p_wip_beginning_qty, 0), COALESCE(p_wip_beginning_dm_completion_pct, 0), COALESCE(p_wip_beginning_cc_completion_pct, 0),
      v_normal_scrap_qty, v_abnormal_scrap_qty, v_normal_scrap_cost, v_abnormal_scrap_cost,
      v_rg, v_wc,
      v_wip_beginning_cost, v_current_period_cost,
      get_current_user_id(), get_current_user_id()
    )
    ON CONFLICT (org_id, manufacturing_order_id, stage_number) DO UPDATE SET
      work_center_id = EXCLUDED.work_center_id,
      input_qty = EXCLUDED.input_qty,
      good_qty = EXCLUDED.good_qty,
      scrap_qty = EXCLUDED.scrap_qty,
      rework_qty = EXCLUDED.rework_qty,
      transferred_in = EXCLUDED.transferred_in,
      dm_cost = EXCLUDED.dm_cost,
      dl_cost = EXCLUDED.dl_cost,
      moh_cost = EXCLUDED.moh_cost,
      regrind_proc_cost = EXCLUDED.regrind_proc_cost,
      waste_credit = EXCLUDED.waste_credit,
      total_cost = EXCLUDED.total_cost,
      unit_cost = EXCLUDED.unit_cost,
      mode = EXCLUDED.mode,
      notes = EXCLUDED.notes,
      wip_end_qty = EXCLUDED.wip_end_qty,
      wip_end_dm_completion_pct = EXCLUDED.wip_end_dm_completion_pct,
      wip_end_cc_completion_pct = EXCLUDED.wip_end_cc_completion_pct,
      wip_beginning_qty = EXCLUDED.wip_beginning_qty,
      wip_beginning_dm_completion_pct = EXCLUDED.wip_beginning_dm_completion_pct,
      wip_beginning_cc_completion_pct = EXCLUDED.wip_beginning_cc_completion_pct,
      normal_scrap_qty = EXCLUDED.normal_scrap_qty,
      abnormal_scrap_qty = EXCLUDED.abnormal_scrap_qty,
      normal_scrap_cost = EXCLUDED.normal_scrap_cost,
      abnormal_scrap_cost = EXCLUDED.abnormal_scrap_cost,
      regrind_cost = EXCLUDED.regrind_cost,
      waste_credit_amount = EXCLUDED.waste_credit_amount,
      wip_beginning_cost = EXCLUDED.wip_beginning_cost,
      current_period_cost = EXCLUDED.current_period_cost,
      updated_at = now(),
      updated_by = get_current_user_id()
    RETURNING id INTO v_stage_id;
  END IF;

  -- Update manufacturing order current stage
  IF EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = C_SCHEMA_PUBLIC
    AND table_name = C_TABLE_MANUFACTURING_ORDERS 
    AND column_name = C_COL_TENANT_ID
  ) THEN
    UPDATE public.manufacturing_orders 
    SET current_stage = GREATEST(COALESCE(current_stage, 1), p_stage),
        updated_at = now()
    WHERE id = p_mo 
      AND tenant_id = p_tenant;
  ELSE
    UPDATE public.manufacturing_orders 
    SET current_stage = GREATEST(COALESCE(current_stage, 1), p_stage),
        updated_at = now()
    WHERE id = p_mo 
      AND org_id = p_tenant;
  END IF;

  -- Return results including FIFO fields
  RETURN QUERY
  SELECT v_stage_id, v_total, v_unit, v_ti, v_dl, v_oh, v_eup, v_normal_scrap_cost, v_abnormal_scrap_cost, 
         v_costing_method, v_wip_beginning_cost, v_current_period_cost;
END $function$
;

CREATE OR REPLACE FUNCTION public.validate_entry_balance()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_total_debit DECIMAL(12,2);
    v_total_credit DECIMAL(12,2);
BEGIN
    -- حساب مجموع المدين والدائن
    SELECT 
        COALESCE(SUM(debit_amount), 0),
        COALESCE(SUM(credit_amount), 0)
    INTO v_total_debit, v_total_credit
    FROM gl_entry_lines
    WHERE entry_id = NEW.id;
    
    -- تحديث القيد بالمجاميع
    UPDATE gl_entries
    SET 
        total_debit = v_total_debit,
        total_credit = v_total_credit
    WHERE id = NEW.id;
    
    -- التحقق من التوازن
    IF ABS(v_total_debit - v_total_credit) > 0.01 THEN
        RAISE EXCEPTION 'القيد غير متوازن: مدين % ≠ دائن %', v_total_debit, v_total_credit;
    END IF;
    
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_foreign_key(p_table_name text, p_column_name text, p_reference_table text, p_org_id uuid)
 RETURNS TABLE(orphaned_count bigint, orphaned_ids uuid[])
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_query TEXT;
    v_orphaned_count BIGINT;
    v_orphaned_ids UUID[];
BEGIN
    -- Build dynamic query to find orphaned records
    v_query := format('
        SELECT COUNT(*), array_agg(id)
        FROM %I t
        WHERE t.org_id = $1
        AND t.%I IS NOT NULL
        AND NOT EXISTS (
            SELECT 1 FROM %I r
            WHERE r.id = t.%I
            AND r.org_id = $1
        )
    ', p_table_name, p_column_name, p_reference_table, p_column_name);
    
    EXECUTE v_query INTO v_orphaned_count, v_orphaned_ids USING p_org_id;
    
    RETURN QUERY SELECT v_orphaned_count, COALESCE(v_orphaned_ids, ARRAY[]::UUID[]);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_mo_transition(p_from text, p_to text)
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
-- جدول التنقّلات المسموحة:
--
--  draft        → confirmed, cancelled
--  pending      → confirmed, cancelled
--  confirmed    → in_progress, on_hold, cancelled
--  in_progress  → done, on_hold, quality_check, cancelled
--  on_hold      → in_progress, cancelled
--  quality_check→ in_progress, done, cancelled
--  done         → (terminal)
--  cancelled    → (terminal)
DECLARE
    v_from TEXT := normalize_mo_status(p_from);
    v_to   TEXT := normalize_mo_status(p_to);
BEGIN
    -- لا تغيير = لا تحقق
    IF v_from = v_to THEN RETURN; END IF;

    -- حالات نهائية لا تقبل التنقل
    IF v_from IN ('done', 'cancelled') THEN
        RAISE EXCEPTION 'MO_TERMINAL_STATE: لا يمكن تغيير حالة أمر التصنيع من "%" — الحالة نهائية', v_from;
    END IF;

    -- جدول التنقّلات
    IF NOT (
        (v_from = 'draft'         AND v_to IN ('confirmed', 'cancelled'))                          OR
        (v_from = 'pending'       AND v_to IN ('confirmed', 'cancelled'))                          OR
        (v_from = 'confirmed'     AND v_to IN ('in_progress', 'on_hold', 'cancelled'))             OR
        (v_from = 'in_progress'   AND v_to IN ('done', 'on_hold', 'quality_check', 'cancelled'))   OR
        (v_from = 'on_hold'       AND v_to IN ('in_progress', 'cancelled'))                        OR
        (v_from = 'quality_check' AND v_to IN ('in_progress', 'done', 'cancelled'))
    ) THEN
        RAISE EXCEPTION 'MO_INVALID_TRANSITION: التنقل من "%" إلى "%" غير مسموح', v_from, v_to;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_posting_account(p_org_id uuid, p_account_code character varying)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_allow_posting BOOLEAN;
    v_is_active BOOLEAN;
BEGIN
    SELECT allow_posting, is_active
    INTO v_allow_posting, v_is_active
    FROM gl_accounts
    WHERE org_id = p_org_id
    AND code = p_account_code;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Account % not found', p_account_code;
    END IF;
    
    IF NOT v_is_active THEN
        RAISE EXCEPTION 'Account % is not active', p_account_code;
    END IF;
    
    IF NOT v_allow_posting THEN
        RAISE EXCEPTION 'Account % does not allow posting', p_account_code;
    END IF;
    
    RETURN true;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_reservations(p_org_id uuid)
 RETURNS TABLE(item_id uuid, mo_id uuid, reserved numeric, available numeric, on_hand numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    WITH reservations_summary AS (
        SELECT
            mr.item_id,
            mr.mo_id,
            SUM(mr.quantity_reserved - COALESCE(mr.quantity_consumed, 0) - COALESCE(mr.quantity_released, 0)) as reserved
        FROM material_reservations mr
        WHERE mr.org_id = p_org_id
        AND mr.status = 'reserved'
        GROUP BY mr.item_id, mr.mo_id
    ),
    stock_available AS (
        SELECT
            sq.item_id,
            sq.quantity as on_hand
        FROM stock_quants sq
        WHERE sq.org_id = p_org_id
    )
    SELECT
        rs.item_id,
        rs.mo_id,
        rs.reserved,
        COALESCE(sa.on_hand, 0) - COALESCE(rs.reserved, 0) as available,
        COALESCE(sa.on_hand, 0) as on_hand
    FROM reservations_summary rs
    LEFT JOIN stock_available sa ON rs.item_id = sa.item_id
    WHERE COALESCE(sa.on_hand, 0) < rs.reserved;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_stock_balance(p_org_id uuid)
 RETURNS TABLE(item_id uuid, location_id uuid, calculated_quantity numeric, actual_quantity numeric, difference numeric)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    RETURN QUERY
    WITH stock_calculated AS (
        SELECT
            sm.item_id,
            sm.location_id,
            SUM(sm.quantity) as calculated_qty
        FROM stock_moves sm
        WHERE sm.org_id = p_org_id
        GROUP BY sm.item_id, sm.location_id
    ),
    stock_actual AS (
        SELECT
            sq.item_id,
            sq.location_id,
            sq.quantity as actual_qty
        FROM stock_quants sq
        WHERE sq.org_id = p_org_id
    )
    SELECT
        COALESCE(sc.item_id, sa.item_id) as item_id,
        COALESCE(sc.location_id, sa.location_id) as location_id,
        COALESCE(sc.calculated_qty, 0) as calculated_quantity,
        COALESCE(sa.actual_qty, 0) as actual_quantity,
        COALESCE(sc.calculated_qty, 0) - COALESCE(sa.actual_qty, 0) as difference
    FROM stock_calculated sc
    FULL OUTER JOIN stock_actual sa
        ON sc.item_id = sa.item_id
        AND sc.location_id = sa.location_id
    WHERE ABS(COALESCE(sc.calculated_qty, 0) - COALESCE(sa.actual_qty, 0)) > 0.01;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_stock_queue()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  queue_qty DECIMAL(18, 6);
  queue_value DECIMAL(18, 6);
  batch JSONB;
BEGIN
  -- Calculate totals from queue
  queue_qty := 0;
  queue_value := 0;
  
  FOR batch IN SELECT jsonb_array_elements(NEW.stock_queue)
  LOOP
    queue_qty := queue_qty + (batch->>'qty')::DECIMAL;
    queue_value := queue_value + ((batch->>'qty')::DECIMAL * (batch->>'rate')::DECIMAL);
  END LOOP;
  
  -- Update stock_quantity and stock_value from queue
  NEW.stock_quantity := queue_qty;
  NEW.stock_value := queue_value;
  
  -- For weighted average, ensure cost_price matches
  IF NEW.valuation_method IN ('Weighted Average', 'Moving Average') AND queue_qty > 0 THEN
    NEW.cost_price := queue_value / queue_qty;
  END IF;
  
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_tenant_isolation(p_table_name text, p_org_id uuid)
 RETURNS TABLE(record_count bigint, valid_count bigint, invalid_count bigint)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_query TEXT;
    v_total BIGINT;
    v_valid BIGINT;
    v_invalid BIGINT;
BEGIN
    -- Count total records
    v_query := format('SELECT COUNT(*) FROM %I WHERE org_id = $1', p_table_name);
    EXECUTE v_query INTO v_total USING p_org_id;
    
    -- Count valid records (with org_id matching)
    v_valid := v_total; -- If RLS is working, all visible records should be valid
    
    -- Invalid would be records we can't see due to RLS (which is good)
    v_invalid := 0;
    
    RETURN QUERY SELECT v_total, v_valid, v_invalid;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.validate_warehouse_accounts(p_stock_account uuid, p_expense_account uuid)
 RETURNS TABLE(is_valid boolean, error_message text)
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_stock_category TEXT;
    v_expense_category TEXT;
BEGIN
    -- Check stock account category
    SELECT category INTO v_stock_category
    FROM gl_accounts
    WHERE id = p_stock_account;
    
    IF v_stock_category != 'ASSET' THEN
        RETURN QUERY SELECT FALSE, 'حساب المخزون يجب أن يكون من فئة الأصول (ASSET)'::TEXT;
        RETURN;
    END IF;
    
    -- Check expense account category
    SELECT category INTO v_expense_category
    FROM gl_accounts
    WHERE id = p_expense_account;
    
    IF v_expense_category != 'EXPENSE' THEN
        RETURN QUERY SELECT FALSE, 'حساب المصروفات يجب أن يكون من فئة المصروفات (EXPENSE)'::TEXT;
        RETURN;
    END IF;
    
    RETURN QUERY SELECT TRUE, 'الحسابات صحيحة'::TEXT;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_apply_stock_incoming(p_org uuid, p_product uuid, p_warehouse uuid, p_qty numeric, p_rate numeric, p_voucher_type text, p_voucher_id uuid, p_voucher_number text, p_posting_date date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_method     TEXT;
    v_prev_qty   NUMERIC := 0;
    v_prev_value NUMERIC := 0;
    v_prev_queue JSONB   := '[]'::JSONB;
    v_new_qty    NUMERIC;
    v_new_value  NUMERIC;
    v_new_rate   NUMERIC;
    v_new_queue  JSONB;
    v_len        INTEGER;
    v_prod_qty   NUMERIC;
    v_prod_rate  NUMERIC;
BEGIN
    -- لا مخزن ⇒ لا دفتر مخزون (المخزن اختياري في سند الاستلام)
    IF p_warehouse IS NULL OR p_qty IS NULL OR p_qty <= 0 THEN
        RETURN jsonb_build_object('applied', FALSE, 'reason', 'NO_WAREHOUSE_OR_QTY');
    END IF;

    -- طريقة التقييم (افتراضي: متوسط مرجّح)
    SELECT COALESCE(valuation_method, 'Weighted Average')
    INTO v_method
    FROM products WHERE id = p_product AND org_id = p_org;
    v_method := COALESCE(v_method, 'Weighted Average');

    -- قفل صف الـ bin (أو غيابه) — يمنع سباق القراءة/الكتابة.
    SELECT actual_qty, stock_value, stock_queue
    INTO v_prev_qty, v_prev_value, v_prev_queue
    FROM bins
    WHERE product_id = p_product AND warehouse_id = p_warehouse
    FOR UPDATE;

    v_prev_qty   := COALESCE(v_prev_qty, 0);
    v_prev_value := COALESCE(v_prev_value, 0);
    v_prev_queue := COALESCE(v_prev_queue, '[]'::JSONB);

    v_new_qty   := v_prev_qty + p_qty;
    v_new_value := v_prev_value + (p_qty * p_rate);
    v_new_queue := v_prev_queue
                   || jsonb_build_array(jsonb_build_object('qty', p_qty, 'rate', p_rate));

    IF v_method = 'FIFO' THEN
        v_new_rate := COALESCE((v_new_queue->0->>'rate')::NUMERIC, p_rate);
    ELSIF v_method = 'LIFO' THEN
        v_len := jsonb_array_length(v_new_queue);
        v_new_rate := COALESCE((v_new_queue->(v_len - 1)->>'rate')::NUMERIC, p_rate);
    ELSE
        v_new_rate  := CASE WHEN v_new_qty > 0 THEN v_new_value / v_new_qty ELSE 0 END;
        v_new_queue := jsonb_build_array(jsonb_build_object('qty', v_new_qty, 'rate', v_new_rate));
    END IF;

    INSERT INTO stock_ledger_entries (
        voucher_type, voucher_id, voucher_number, product_id, warehouse_id,
        posting_date, actual_qty, qty_after_transaction, incoming_rate,
        valuation_rate, stock_value, stock_value_difference, stock_queue,
        docstatus, org_id, created_by
    ) VALUES (
        p_voucher_type, p_voucher_id, p_voucher_number, p_product, p_warehouse,
        COALESCE(p_posting_date, CURRENT_DATE), p_qty, v_new_qty, p_rate,
        v_new_rate, v_new_value, (p_qty * p_rate), v_new_queue,
        1, p_org, auth.uid()
    );

    -- Bin: upsert (فهرس فريد على product_id, warehouse_id)
    INSERT INTO bins (
        org_id, product_id, warehouse_id, actual_qty,
        valuation_rate, stock_value, stock_queue, updated_at
    ) VALUES (
        p_org, p_product, p_warehouse, v_new_qty,
        v_new_rate, v_new_value, v_new_queue, NOW()
    )
    ON CONFLICT (product_id, warehouse_id) DO UPDATE SET
        actual_qty     = EXCLUDED.actual_qty,
        valuation_rate = EXCLUDED.valuation_rate,
        stock_value    = EXCLUDED.stock_value,
        stock_queue    = EXCLUDED.stock_queue,
        updated_at     = NOW();

    -- ✅ توحيد المخزون (Migration 97): مزامنة products من مجموع bins لهذا المنتج
    --    عبر كل المخازن — اشتقاق idempotent (لا يضاعف عند إعادة التطبيق). يجعل
    --    products المجمّع المرجعي الذي تقرؤه التقارير/اللوحة/تقييم المخزون.
    SELECT COALESCE(SUM(actual_qty), 0),
           CASE WHEN COALESCE(SUM(actual_qty), 0) > 0
                THEN SUM(stock_value) / SUM(actual_qty) ELSE NULL END
    INTO v_prod_qty, v_prod_rate
    FROM bins WHERE product_id = p_product AND org_id = p_org;

    UPDATE products
    SET stock_quantity = v_prod_qty,
        cost_price     = COALESCE(v_prod_rate, cost_price),
        updated_at     = NOW()
    WHERE id = p_product AND org_id = p_org;

    RETURN jsonb_build_object(
        'applied', TRUE, 'new_qty', v_new_qty,
        'new_rate', ROUND(v_new_rate, 6), 'new_value', ROUND(v_new_value, 6),
        'method', v_method,
        'product_synced', jsonb_build_object(
            'stock_quantity', v_prod_qty,
            'cost_price', ROUND(COALESCE(v_prod_rate, 0), 6))
    );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_assert_org_admin(p_org uuid)
 RETURNS void
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    PERFORM public.wardah_assert_org_member(p_org);
    IF NOT (COALESCE(public.is_super_admin(), FALSE)
            OR public.wardah_is_org_admin(p_org)) THEN
        RAISE EXCEPTION 'NOT_ORG_ADMIN';
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_assert_org_member(p_org uuid)
 RETURNS void
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'NOT_AUTHENTICATED';
    END IF;
    IF p_org IS NULL THEN
        RAISE EXCEPTION 'ORG_UNRESOLVED';
    END IF;
    IF NOT EXISTS (
        SELECT 1 FROM public.user_organizations
        WHERE user_id = auth.uid()
          AND org_id = p_org
          AND COALESCE(is_active, TRUE)
    ) THEN
        RAISE EXCEPTION 'NOT_ORG_MEMBER';
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_is_org_admin(p_org uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
    SELECT EXISTS (
        SELECT 1 FROM user_organizations
        WHERE user_id = auth.uid()
          AND org_id = p_org
          AND (COALESCE(is_org_admin, FALSE) OR role IN ('admin', 'owner'))
    );
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_is_org_member(p_org uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
    SELECT auth.uid() IS NOT NULL
       AND p_org IS NOT NULL
       AND EXISTS (
            SELECT 1 FROM public.user_organizations
            WHERE user_id = auth.uid() AND org_id = p_org AND COALESCE(is_active, TRUE)
       );
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_org_id(p_explicit uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_org uuid;
BEGIN
    IF p_explicit IS NOT NULL THEN
        IF public.wardah_is_org_member(p_explicit) THEN RETURN p_explicit; END IF;
        RETURN NULL;
    END IF;
    BEGIN v_org := public.get_current_tenant_id();
    EXCEPTION WHEN OTHERS THEN v_org := NULL; END;
    RETURN v_org;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_periods_org_col()
 RETURNS text
 LANGUAGE sql
 STABLE
 SET search_path TO 'public'
AS $function$
    SELECT CASE
        WHEN EXISTS (
            SELECT 1 FROM information_schema.columns
            WHERE table_schema = 'public' AND table_name = 'accounting_periods'
              AND column_name = 'org_id'
        ) THEN 'org_id'
        WHEN EXISTS (
            SELECT 1 FROM information_schema.columns
            WHERE table_schema = 'public' AND table_name = 'accounting_periods'
              AND column_name = 'tenant_id'
        ) THEN 'tenant_id'
        ELSE NULL
    END;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_settlement_snapshot(p_settlement_id uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
    SELECT jsonb_build_object(
        'employee_id',       s.employee_id,
        'settlement_type',   s.settlement_type,
        'termination_type',  s.termination_type,
        'payable_amount',    ROUND(COALESCE(s.payable_amount, 0), 2),
        'calculated_amount', ROUND(COALESCE(s.calculated_amount, 0), 2),
        'service_start',     s.service_start,
        'service_end',       s.service_end,
        'notes',             s.notes,
        'lines', COALESCE((
            SELECT jsonb_agg(jsonb_build_object(
                       'component_code', l.component_code,
                       'amount', ROUND(l.amount, 2),
                       'is_deduction', l.is_deduction)
                   ORDER BY l.component_code, l.amount)
            FROM hr_settlement_lines l
            WHERE l.settlement_id = s.id), '[]'::jsonb))
    FROM hr_settlements s
    WHERE s.id = p_settlement_id;
$function$
;

CREATE OR REPLACE FUNCTION public.wardah_touch_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$function$
;

-- ============================================================
-- Views (17)
-- ============================================================

CREATE OR REPLACE VIEW public.v_all_public_functions AS
 SELECT n.nspname AS schema_name,
    p.proname AS function_name,
    pg_get_function_identity_arguments(p.oid) AS arguments,
        CASE
            WHEN p.provolatile = 'i'::"char" THEN 'IMMUTABLE'::text
            WHEN p.provolatile = 's'::"char" THEN 'STABLE'::text
            WHEN p.provolatile = 'v'::"char" THEN 'VOLATILE'::text
            ELSE 'UNKNOWN'::text
        END AS volatility
   FROM pg_proc p
     JOIN pg_namespace n ON p.pronamespace = n.oid
  WHERE n.nspname = 'public'::name AND p.prokind = 'f'::"char"
  ORDER BY p.proname;

CREATE OR REPLACE VIEW public.v_capacity_summary AS
 SELECT wc.org_id,
    wc.id AS work_center_id,
    wc.name AS work_center_name,
    wc.capacity_hours_per_day,
    wc.number_of_machines,
    wcl.period_start,
    wcl.period_end,
    wcl.available_capacity_hours,
    wcl.planned_load_hours,
    wcl.actual_load_hours,
    wcl.utilization_pct,
    wcl.planned_work_orders,
    wcl.completed_work_orders,
        CASE
            WHEN wcl.utilization_pct > 100::numeric THEN 'OVERLOADED'::text
            WHEN wcl.utilization_pct > 85::numeric THEN 'HIGH'::text
            WHEN wcl.utilization_pct > 50::numeric THEN 'NORMAL'::text
            ELSE 'LOW'::text
        END AS load_status
   FROM work_centers wc
     LEFT JOIN work_center_load wcl ON wc.id = wcl.work_center_id;

CREATE OR REPLACE VIEW public.v_cost_variance_report AS
 SELECT wo.org_id,
    mo.order_number,
    wo.work_order_number,
    wo.operation_name,
    wc.name AS work_center_name,
    round((wo.planned_setup_time + wo.planned_run_time) / 60::numeric * COALESCE(ro.labor_rate_per_hour, wc.default_labor_rate, 0::numeric), 2) AS planned_labor_cost,
    round((wo.actual_setup_time + wo.actual_run_time) / 60::numeric * COALESCE(ro.labor_rate_per_hour, wc.default_labor_rate, 0::numeric), 2) AS actual_labor_cost,
    round((wo.actual_setup_time + wo.actual_run_time - (wo.planned_setup_time + wo.planned_run_time)) / 60::numeric * COALESCE(ro.labor_rate_per_hour, wc.default_labor_rate, 0::numeric), 2) AS labor_variance,
    round((wo.planned_setup_time + wo.planned_run_time) / 60::numeric * COALESCE(ro.overhead_rate_per_hour, wc.default_overhead_rate, 0::numeric), 2) AS planned_overhead_cost,
    round((wo.actual_setup_time + wo.actual_run_time) / 60::numeric * COALESCE(ro.overhead_rate_per_hour, wc.default_overhead_rate, 0::numeric), 2) AS actual_overhead_cost,
    round((wo.actual_setup_time + wo.actual_run_time - (wo.planned_setup_time + wo.planned_run_time)) / 60::numeric * COALESCE(ro.overhead_rate_per_hour, wc.default_overhead_rate, 0::numeric), 2) AS overhead_variance,
    wo.status,
    wo.actual_end_date
   FROM work_orders wo
     JOIN manufacturing_orders mo ON wo.mo_id = mo.id
     JOIN work_centers wc ON wo.work_center_id = wc.id
     LEFT JOIN routing_operations ro ON wo.operation_id = ro.id
  WHERE wo.status::text = 'COMPLETED'::text;

CREATE OR REPLACE VIEW public.v_gl_entries_full AS
 SELECT ge.id,
    ge.org_id,
    ge.entry_number,
    ge.entry_date,
    ge.entry_type,
    ge.description,
    ge.description_ar,
    ge.status,
    ge.journal_id,
    ge.reference_type,
    ge.reference_number,
    ge.reference_id,
    ge.created_by,
    ge.created_at,
    ge.updated_at,
    j.name AS journal_name,
    j.name_ar AS journal_name_ar,
    j.code AS journal_code,
    ( SELECT sum(gl_entry_lines.debit_amount) AS sum
           FROM gl_entry_lines
          WHERE gl_entry_lines.entry_id = ge.id) AS total_debit,
    ( SELECT sum(gl_entry_lines.credit_amount) AS sum
           FROM gl_entry_lines
          WHERE gl_entry_lines.entry_id = ge.id) AS total_credit,
    ( SELECT count(*) AS count
           FROM gl_entry_lines
          WHERE gl_entry_lines.entry_id = ge.id) AS line_count
   FROM gl_entries ge
     LEFT JOIN journals j ON ge.journal_id = j.id;

CREATE OR REPLACE VIEW public.v_labor_efficiency AS
 SELECT wo.org_id,
    wo.work_center_id,
    wc.name AS work_center_name,
    mo.order_number,
    wo.work_order_number,
    wo.operation_name,
    wo.planned_setup_time,
    wo.actual_setup_time,
    wo.planned_run_time,
    wo.actual_run_time,
    wo.planned_quantity,
    wo.completed_quantity,
    wo.scrapped_quantity,
        CASE
            WHEN wo.actual_setup_time > 0::numeric THEN round(wo.planned_setup_time / wo.actual_setup_time * 100::numeric, 2)
            ELSE 100::numeric
        END AS setup_efficiency_pct,
        CASE
            WHEN wo.actual_run_time > 0::numeric THEN round(wo.planned_run_time / wo.actual_run_time * 100::numeric, 2)
            ELSE 100::numeric
        END AS run_efficiency_pct,
        CASE
            WHEN (wo.actual_setup_time + wo.actual_run_time) > 0::numeric THEN round((wo.planned_setup_time + wo.planned_run_time) / (wo.actual_setup_time + wo.actual_run_time) * 100::numeric, 2)
            ELSE 100::numeric
        END AS overall_efficiency_pct,
        CASE
            WHEN (wo.completed_quantity + wo.scrapped_quantity) > 0::numeric THEN round(wo.scrapped_quantity / (wo.completed_quantity + wo.scrapped_quantity) * 100::numeric, 2)
            ELSE 0::numeric
        END AS scrap_rate_pct,
    wo.actual_start_date,
    wo.actual_end_date,
    wo.status
   FROM work_orders wo
     JOIN manufacturing_orders mo ON wo.mo_id = mo.id
     JOIN work_centers wc ON wo.work_center_id = wc.id
  WHERE wo.status::text = 'COMPLETED'::text;

CREATE OR REPLACE VIEW public.v_manufacturing_orders_full AS
 SELECT mo.id,
    mo.org_id,
    mo.order_number,
    mo.item_id,
    mo.product_id,
    mo.quantity,
    mo.status,
    mo.start_date,
    mo.due_date,
    mo.completed_date,
    mo.completed_quantity,
    mo.scrap_quantity,
    mo.total_cost,
    mo.unit_cost,
    mo.notes,
    mo.created_by,
    mo.created_at,
    mo.updated_at,
    COALESCE(p.name, i.name::character varying) AS product_name,
    COALESCE(p.code, i.code) AS product_code,
    COALESCE(p.id, i.id) AS effective_product_id
   FROM manufacturing_orders mo
     LEFT JOIN products p ON mo.product_id = p.id
     LEFT JOIN items i ON mo.item_id = i.id;

CREATE OR REPLACE VIEW public.v_manufacturing_orders_summary AS
 SELECT org_id,
    status,
    count(*) AS order_count,
    sum(quantity) AS total_quantity,
    sum(completed_quantity) AS total_completed,
    sum(scrap_quantity) AS total_scrap,
    sum(total_cost) AS total_cost,
    avg(unit_cost) AS avg_unit_cost,
    min(start_date) AS earliest_start,
    max(due_date) AS latest_due
   FROM manufacturing_orders
  GROUP BY org_id, status;

CREATE OR REPLACE VIEW public.v_material_consumption_report AS
 SELECT mc.org_id,
    mo.order_number,
    wo.work_order_number,
    i.code AS item_code,
    i.name AS item_name,
    mc.planned_quantity,
    mc.consumed_quantity,
    mc.consumed_quantity - mc.planned_quantity AS variance_qty,
        CASE
            WHEN mc.planned_quantity > 0::numeric THEN round((mc.consumed_quantity - mc.planned_quantity) / mc.planned_quantity * 100::numeric, 2)
            ELSE 0::numeric
        END AS variance_pct,
    mc.unit_cost,
    mc.total_cost,
    mc.consumption_type,
    mc.consumption_date,
    mc.status
   FROM material_consumption mc
     JOIN manufacturing_orders mo ON mc.mo_id = mo.id
     JOIN work_orders wo ON mc.work_order_id = wo.id
     JOIN items i ON mc.item_id = i.id;

CREATE OR REPLACE VIEW public.v_oee_report AS
 WITH daily_data AS (
         SELECT wo.org_id,
            wo.work_center_id,
            date_trunc('day'::text, wo.actual_end_date) AS production_date,
            wc_1.capacity_hours_per_day * 60::numeric AS available_time,
            sum(wo.actual_setup_time + wo.actual_run_time) AS operating_time,
            COALESCE(sum(md.duration_minutes), 0::numeric) AS downtime,
            sum(wo.completed_quantity) AS total_produced,
            sum(wo.completed_quantity - wo.scrapped_quantity) AS good_quantity,
            sum(wo.planned_quantity) AS planned_quantity,
            avg(ro.standard_run_time_per_unit) AS ideal_cycle_time
           FROM work_orders wo
             JOIN work_centers wc_1 ON wo.work_center_id = wc_1.id
             LEFT JOIN machine_downtime md ON wo.work_center_id = md.work_center_id AND date_trunc('day'::text, md.start_time) = date_trunc('day'::text, wo.actual_end_date)
             LEFT JOIN routing_operations ro ON wo.operation_id = ro.id
          WHERE wo.status::text = 'COMPLETED'::text AND wo.actual_end_date IS NOT NULL
          GROUP BY wo.org_id, wo.work_center_id, wc_1.capacity_hours_per_day, (date_trunc('day'::text, wo.actual_end_date))
        )
 SELECT dd.org_id,
    dd.work_center_id,
    wc.name AS work_center_name,
    dd.production_date,
    dd.available_time,
    dd.operating_time,
    dd.downtime,
    dd.total_produced,
    dd.good_quantity,
    round(dd.operating_time / NULLIF(dd.available_time, 0::numeric) * 100::numeric, 2) AS availability_pct,
    round(
        CASE
            WHEN dd.operating_time > 0::numeric AND dd.ideal_cycle_time > 0::numeric THEN dd.total_produced * dd.ideal_cycle_time / dd.operating_time * 100::numeric
            ELSE 100::numeric
        END, 2) AS performance_pct,
    round(
        CASE
            WHEN dd.total_produced > 0::numeric THEN dd.good_quantity / dd.total_produced * 100::numeric
            ELSE 100::numeric
        END, 2) AS quality_pct,
    round(dd.operating_time / NULLIF(dd.available_time, 0::numeric) *
        CASE
            WHEN dd.operating_time > 0::numeric AND dd.ideal_cycle_time > 0::numeric THEN dd.total_produced * dd.ideal_cycle_time / dd.operating_time
            ELSE 1::numeric
        END *
        CASE
            WHEN dd.total_produced > 0::numeric THEN dd.good_quantity / dd.total_produced
            ELSE 1::numeric
        END * 100::numeric, 2) AS oee_pct
   FROM daily_data dd
     JOIN work_centers wc ON dd.work_center_id = wc.id;

CREATE OR REPLACE VIEW public.v_production_schedule_details AS
 SELECT ps.id AS schedule_id,
    ps.schedule_number,
    ps.status AS schedule_status,
    ps.period_start,
    ps.period_end,
    sd.schedule_sequence,
    sd.scheduled_start,
    sd.scheduled_end,
    sd.schedule_status AS item_status,
    wo.work_order_number,
    wo.operation_name,
    wo.planned_quantity,
    wo.completed_quantity,
    mo.order_number AS mo_number,
    wc.name AS work_center_name,
    EXTRACT(epoch FROM sd.scheduled_end - sd.scheduled_start) / 3600::numeric AS duration_hours
   FROM production_schedules ps
     JOIN schedule_details sd ON ps.id = sd.schedule_id
     JOIN work_orders wo ON sd.work_order_id = wo.id
     JOIN manufacturing_orders mo ON wo.mo_id = mo.id
     JOIN work_centers wc ON wo.work_center_id = wc.id;

CREATE OR REPLACE VIEW public.v_trial_balance AS
 SELECT gl.account_code,
    ga.name AS account_name,
    COALESCE(ga.name_ar, ga.name::text) AS account_name_ar,
    ga.category AS account_type,
    ga.parent_code,
    sum(
        CASE
            WHEN gl.debit_amount > 0::numeric THEN gl.debit_amount
            ELSE 0::numeric
        END) AS total_debit,
    sum(
        CASE
            WHEN gl.credit_amount > 0::numeric THEN gl.credit_amount
            ELSE 0::numeric
        END) AS total_credit,
    sum(gl.debit_amount - gl.credit_amount) AS balance,
    ge.org_id,
    min(ge.entry_date) AS first_transaction_date,
    max(ge.entry_date) AS last_transaction_date,
    count(DISTINCT ge.id) AS transaction_count
   FROM gl_entry_lines gl
     JOIN gl_entries ge ON gl.entry_id = ge.id
     LEFT JOIN gl_accounts ga ON gl.account_code::text = ga.code::text AND ge.org_id = ga.org_id
  WHERE ge.status::text = 'posted'::text
  GROUP BY gl.account_code, ga.name, (COALESCE(ga.name_ar, ga.name::text)), ga.category, ga.parent_code, ge.org_id;

CREATE OR REPLACE VIEW public.v_work_center_efficiency_summary AS
 SELECT wo.org_id,
    wo.work_center_id,
    wc.name AS work_center_name,
    wc.name_ar AS work_center_name_ar,
    date_trunc('day'::text, wo.actual_end_date) AS production_date,
    count(*) AS completed_operations,
    sum(wo.completed_quantity) AS total_produced,
    sum(wo.scrapped_quantity) AS total_scrapped,
    sum(wo.planned_setup_time) AS total_planned_setup,
    sum(wo.actual_setup_time) AS total_actual_setup,
    sum(wo.planned_run_time) AS total_planned_run,
    sum(wo.actual_run_time) AS total_actual_run,
    round(avg(
        CASE
            WHEN wo.actual_setup_time > 0::numeric THEN wo.planned_setup_time / wo.actual_setup_time * 100::numeric
            ELSE 100::numeric
        END), 2) AS avg_setup_efficiency,
    round(avg(
        CASE
            WHEN wo.actual_run_time > 0::numeric THEN wo.planned_run_time / wo.actual_run_time * 100::numeric
            ELSE 100::numeric
        END), 2) AS avg_run_efficiency,
    round(avg(
        CASE
            WHEN (wo.actual_setup_time + wo.actual_run_time) > 0::numeric THEN (wo.planned_setup_time + wo.planned_run_time) / (wo.actual_setup_time + wo.actual_run_time) * 100::numeric
            ELSE 100::numeric
        END), 2) AS avg_overall_efficiency
   FROM work_orders wo
     JOIN work_centers wc ON wo.work_center_id = wc.id
  WHERE wo.status::text = 'COMPLETED'::text AND wo.actual_end_date IS NOT NULL
  GROUP BY wo.org_id, wo.work_center_id, wc.name, wc.name_ar, (date_trunc('day'::text, wo.actual_end_date));

CREATE OR REPLACE VIEW public.v_work_center_productivity AS
 SELECT wc.id AS work_center_id,
    wc.org_id,
    wc.name AS work_center_name,
    wc.capacity_hours_per_day,
    count(DISTINCT wo.id) AS total_work_orders,
    count(DISTINCT wo.id) FILTER (WHERE wo.status::text = 'IN_PROGRESS'::text) AS active_work_orders,
    sum(wo.completed_quantity) AS total_produced,
    sum(wo.scrapped_quantity) AS total_scrapped,
    sum(wo.actual_run_time) AS total_run_time_minutes,
    round(avg(
        CASE
            WHEN wo.planned_run_time > 0::numeric THEN wo.actual_run_time / wo.planned_run_time * 100::numeric
            ELSE NULL::numeric
        END), 2) AS avg_efficiency_pct
   FROM work_centers wc
     LEFT JOIN work_orders wo ON wc.id = wo.work_center_id
  GROUP BY wc.id, wc.org_id, wc.name, wc.capacity_hours_per_day;

CREATE OR REPLACE VIEW public.v_work_centers_utilization AS
 SELECT wc.id,
    wc.org_id,
    wc.code,
    wc.name,
    wc.name_ar,
    wc.description,
    wc.hourly_rate,
    wc.capacity_per_hour,
    wc.efficiency_percent,
    wc.is_active,
    wc.created_at,
    wc.updated_at,
    count(DISTINCT sc.manufacturing_order_id) AS active_orders,
    sum(sc.dl_cost) AS total_labor_cost,
    sum(sc.moh_cost) AS total_overhead_cost,
    wc.efficiency_percent AS avg_efficiency
   FROM work_centers wc
     LEFT JOIN stage_costs sc ON wc.id = sc.work_center_id
  GROUP BY wc.id, wc.org_id, wc.code, wc.name, wc.name_ar, wc.description, wc.hourly_rate, wc.capacity_per_hour, wc.efficiency_percent, wc.is_active, wc.created_at, wc.updated_at;

CREATE OR REPLACE VIEW public.v_work_order_status AS
 SELECT wo.id,
    wo.org_id,
    wo.work_order_number,
    wo.operation_name,
    wo.status,
    mo.order_number AS mo_number,
    wc.name AS work_center_name,
    wo.planned_quantity,
    wo.completed_quantity,
    wo.scrapped_quantity,
    wo.planned_setup_time,
    wo.actual_setup_time,
    wo.planned_run_time,
    wo.actual_run_time,
        CASE
            WHEN wo.planned_setup_time > 0::numeric THEN round((wo.actual_setup_time - wo.planned_setup_time) / wo.planned_setup_time * 100::numeric, 2)
            ELSE 0::numeric
        END AS setup_variance_pct,
        CASE
            WHEN wo.planned_run_time > 0::numeric THEN round((wo.actual_run_time - wo.planned_run_time) / wo.planned_run_time * 100::numeric, 2)
            ELSE 0::numeric
        END AS run_variance_pct,
    wo.current_operator_id
   FROM work_orders wo
     JOIN manufacturing_orders mo ON mo.id = wo.mo_id
     JOIN work_centers wc ON wc.id = wo.work_center_id;

CREATE OR REPLACE VIEW public.vw_stock_valuation_by_method AS
 SELECT org_id,
    valuation_method,
    count(*) AS product_count,
    sum(stock_quantity) AS total_quantity,
    sum(stock_value) AS total_value,
    avg(cost_price) AS avg_unit_cost,
    min(cost_price) AS min_unit_cost,
    max(cost_price) AS max_unit_cost
   FROM products
  WHERE stock_quantity > 0::numeric
  GROUP BY org_id, valuation_method;

CREATE OR REPLACE VIEW public.wip_by_stage AS
 SELECT mo.id,
    mo.org_id,
    mo.order_number,
    mo.product_id,
    p.name AS product_name,
    mo.status,
    mo.quantity AS qty_planned,
    COALESCE(mo.completed_quantity, 0::numeric) AS qty_produced,
        CASE
            WHEN count(wo.id) = 0 THEN 0::numeric
            ELSE round(100.0 * count(wo.id) FILTER (WHERE wo.status::text = 'done'::text)::numeric / NULLIF(count(wo.id), 0)::numeric, 1)
        END AS operations_completion_pct,
    COALESCE(mo.total_cost, 0::numeric) AS total_wip_cost,
    COALESCE(mo.unit_cost, 0::numeric) AS current_unit_cost,
    mo.start_date,
    mo.due_date
   FROM manufacturing_orders mo
     JOIN products p ON p.id = mo.product_id
     LEFT JOIN work_orders wo ON wo.mo_id = mo.id
  WHERE mo.status::text = ANY (ARRAY['in_progress'::character varying, 'quality_check'::character varying, 'on_hold'::character varying]::text[])
  GROUP BY mo.id, mo.org_id, mo.order_number, mo.product_id, p.name, mo.status, mo.quantity, mo.completed_quantity, mo.total_cost, mo.unit_cost, mo.start_date, mo.due_date;

