CREATE POLICY user_organizations_ins_m ON public.user_organizations FOR INSERT TO authenticated WITH CHECK ((is_org_admin(org_id) OR is_super_admin()));

CREATE POLICY user_organizations_sel_m ON public.user_organizations FOR SELECT TO authenticated USING ((is_org_admin(org_id) OR (user_id = auth.uid()) OR is_super_admin()));

CREATE POLICY user_organizations_upd_m ON public.user_organizations FOR UPDATE TO authenticated USING ((is_org_admin(org_id) OR is_super_admin())) WITH CHECK ((is_org_admin(org_id) OR is_super_admin()));

CREATE POLICY user_profiles_del_m ON public.user_profiles FOR DELETE TO authenticated USING (((user_id = auth.uid()) OR is_super_admin()));

CREATE POLICY user_profiles_ins_m ON public.user_profiles FOR INSERT TO authenticated WITH CHECK (((user_id = auth.uid()) OR is_super_admin()));

CREATE POLICY user_profiles_sel_m ON public.user_profiles FOR SELECT TO authenticated USING (((user_id IN ( SELECT uo.user_id
   FROM user_organizations uo
  WHERE (uo.org_id = ANY (get_user_org_ids())))) OR (user_id = auth.uid()) OR is_super_admin()));

CREATE POLICY user_profiles_upd_m ON public.user_profiles FOR UPDATE TO authenticated USING (((user_id = auth.uid()) OR is_super_admin())) WITH CHECK (((user_id = auth.uid()) OR is_super_admin()));

CREATE POLICY user_roles_delete ON public.user_roles FOR DELETE TO authenticated USING ((is_org_admin(org_id) OR ( SELECT is_super_admin() AS is_super_admin)));

CREATE POLICY user_roles_insert ON public.user_roles FOR INSERT TO authenticated WITH CHECK ((is_org_admin(org_id) OR ( SELECT is_super_admin() AS is_super_admin)));

CREATE POLICY user_roles_select ON public.user_roles FOR SELECT TO authenticated USING (((user_id = ( SELECT auth.uid() AS uid)) OR is_org_admin(org_id) OR ( SELECT is_super_admin() AS is_super_admin)));

CREATE POLICY user_roles_update ON public.user_roles FOR UPDATE TO authenticated USING ((is_org_admin(org_id) OR ( SELECT is_super_admin() AS is_super_admin))) WITH CHECK ((is_org_admin(org_id) OR ( SELECT is_super_admin() AS is_super_admin)));

